CtBt3C,EAAIq0C,eAAiBA,EACrBr0C,EAAIg1C,oBAAsBA,IArd9B","file":"bundle.ts.js","sourcesContent":[null,"const mobilemenu = document.querySelector('#mobile-menu');  //seleccion por id\r\nconst sidebar = document.querySelector('.sidebar') as HTMLElement|null;  //seleccion por calses\r\nconst btnmenux = document.querySelector('#mobile-menux');\r\nconst barra = document.querySelector('.barra-mobile') as HTMLElement|null;\r\nconst nametop:HTMLElement|null = document.querySelector('.nametop');\r\ndeclare let Chart:any; //declare le indica a typescript que la variable chart viene de manera externa\r\ndeclare const Swal: any;\r\ndeclare var moment: any;\r\ndeclare let List: any; \r\ndeclare const mediosPagoDB: MedioPago[];  //mediosPagoDB inyectada por medio de json desde la vista ventas/index.php interfaz en ventas.type.ts\r\ndeclare const creditosDB: any;  //mediosPagoDB inyectada por medio de json desde la vista creditos/index.php interfaz en ventas.type.ts\r\n\r\n(window as any).POS = (window as any).POS || {};\r\n\r\n // Submódulos\r\n  if (!(window as any).POS.gestionarDescuentos) {\r\n    (window as any).POS.gestionarDescuentos = {};\r\n  }\r\n\r\nif(mobilemenu){\r\n    mobilemenu.addEventListener('click', function(){\r\n      if (sidebar && barra) {\r\n        sidebar.classList.toggle('mostrar');\r\n        barra.classList.toggle('ocultarmenu');\r\n      }\r\n    });\r\n}\r\nif(btnmenux){\r\n    btnmenux.addEventListener('click', function(){\r\n      if (sidebar && barra) {\r\n        sidebar.classList.toggle('mostrar');\r\n        barra.classList.toggle('ocultarmenu');\r\n      }\r\n    });\r\n}\r\n/////////////////////// animacion del sidebar toggle ///////////////////////////\r\ndocument.querySelector('.sidebartoggle')!.addEventListener('click', (e)=>{\r\n  if(sidebar)sidebar?.classList.toggle('minsidebar');\r\n  if(nametop)nametop.classList.toggle('noneElement');\r\n  $('.btnav').toggleClass('noneElement');\r\n});\r\n\r\n//------------------------------------------------------------------------------------------------------------------//\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES /////////////////////\r\nconst configdatatables = {\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA 25 REGISTROS /////////////////////\r\nconst configdatatables25reg = {\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA GENERAL /////////////////////\r\nconst configdatatablesgenerico = {\r\n  layout: {\r\n        topStart: {\r\n            buttons: [\r\n              {extend: 'copyHtml5', text: 'Copia'}, \r\n              {extend: 'excelHtml5', title: 'informe'}, \r\n              {extend: 'csvHtml5', title: 'informe'}, \r\n              {extend: 'pdfHtml5', title: 'informe'}, \r\n              {extend: 'print', title: 'informe', text: 'Imprimir'},\r\n              'colvis'\r\n            ],\r\n            pageLength: 'pageLength'\r\n        }\r\n  },\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA STOCK RAPIDO /////////////////////\r\nconst configdatatablesstockrapido = {\r\n  layout: {\r\n        topStart: {\r\n            buttons: [\r\n              {extend: 'copyHtml5', text: 'Copia'}, \r\n              {extend: 'excelHtml5', exportOptions: {columns: [1, 2, 3, 4, 5]}, title: 'Stock-inventario'}, \r\n              {extend: 'csvHtml5', exportOptions: {columns: [1, 2, 3, 4, 5]}, title: 'Stock-inventario'}, \r\n              {extend: 'pdfHtml5', exportOptions: {columns: [1, 2, 3, 4, 5]}, title: 'Stock-inventario'}, \r\n              {extend: 'print', exportOptions: {columns: [1, 3, 4]}, title: 'Stock-inventario', text: 'Imprimir'},\r\n              'colvis'\r\n            ],\r\n            pageLength: 'pageLength'\r\n        }\r\n  },\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA AJUSTAR COSTOS /////////////////////\r\nconst configdatatablesajustarcostos = {\r\n  layout: {\r\n        topStart: {\r\n            buttons: [\r\n              {extend: 'copyHtml5', text: 'Copia'}, \r\n              {extend: 'excelHtml5', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto'}, \r\n              {extend: 'csvHtml5', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto'}, \r\n              {extend: 'pdfHtml5', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto'}, \r\n              {extend: 'print', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto', text: 'Imprimir'},\r\n              'colvis'\r\n            ],\r\n            pageLength: 'pageLength'\r\n        }\r\n  },\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// CONFIGURACION DEL PLUGIN DATATABLES PARA CAJA/////////////////////\r\nconst configdatatablescaja = {\r\n  \"paging\": false,\r\n  \"order\": [[ 3, 'desc' ]],\r\n  \"searching\": false,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando 1 de _MAX_ registros',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// FUNCION QUE IMPRIME MENSAJE TIPO ALERTA /////////////////////\r\nfunction msjAlert(tipo:string, msj:string, divmsjalerta:HTMLElement):void{\r\n  divmsjalerta.insertAdjacentHTML('beforeend', `<div class=\"alerta alerta__${tipo}\">\r\n      <p><i class=\"fa-solid fa-circle-exclamation\"></i> ${msj}</p></div>`\r\n  );\r\n  borrarMsjAlert(divmsjalerta);\r\n}\r\n//////////////////// BORRAR MENSAJES TIPO ALERTA /////////////////////\r\n/*(borrarMsjAlert =()=>{  //se aplica de manera global\r\n  const msj = document.querySelector('#divmsjalerta');\r\n  if(document.querySelector('.alerta'))setTimeout(()=>{ while(msj.firstChild)msj.removeChild(msj.firstChild);}, 5000);\r\n})();*/\r\nfunction borrarMsjAlert(divmsj:HTMLElement):void{  //se aplica de manera global\r\n  //const msj = document.querySelector('#divmsjalerta')!;\r\n  if(document.querySelector('.alerta'))setTimeout(()=>{ while(divmsj.firstChild)divmsj.removeChild(divmsj.firstChild);}, 5000);\r\n}\r\n//////////////////// FUNCION QUE IMPRIME UN MENSAJE FORMATO TOAST ////////////////////\r\n//msjalertToast('error', '¡Error!', 'debe seleccionar una imagen')\r\nfunction msjalertToast(icono:string, tipo:string, msj:string){\r\n    Swal.fire({\r\n    icon: icono,  // Puedes cambiar el ícono (success, error, warning, info, etc.)\r\n    title: tipo,\r\n    text: msj,\r\n    toast: true,\r\n    position: 'top-end',  \r\n    showConfirmButton: false,  \r\n    timer: 2700  \r\n    });\r\n}\r\n\r\n/////////////////// FUNCION CONTADOR DE CARACTERES ////////////////////\r\n(function countchars():void{\r\n  const numinput = document.querySelectorAll('.count-charts') as NodeListOf<HTMLElement>;  \r\n  numinput.forEach(element =>{ //element es cada label\r\n      element.textContent = (parseInt(element.dataset.num!)-(element.previousElementSibling as HTMLInputElement).value.length).toString();\r\n      element.previousElementSibling?.addEventListener('input', (e)=>{ //seleccionamos el input o el textarea en donde se escribe y se le da el evento de teclas\r\n          element.textContent = parseInt(element.dataset.num!)-(e.target as HTMLInputElement).value.length+\"\";\r\n            \r\n          if(parseInt(element.dataset.num!)-(e.target as HTMLInputElement).value.length <= 0){\r\n              let cadena = (e.target as HTMLInputElement).value.slice(0, parseInt(element.dataset.num!));\r\n              (e.target as HTMLInputElement).value = cadena;\r\n              element.textContent =`${0}`;\r\n          }\r\n      });\r\n  });\r\n})();\r\n\r\n/////////////////// paginacion de negocio empleado, malla, config //////////////////\r\nif(document.querySelector('#tabulacion')){ // view/admin/adminconfig/index.php\r\n  const renderid = document.querySelector('#tabulacion input[type=\"radio\"]:checked')!.nextElementSibling as HTMLElement; //se selecciona el input cheked y luego su span q contiene el id de la pagina a mostrar\r\n  document.querySelector<HTMLElement>(`.${renderid.id}`)!.style.display = \"block\"; //mostramos la primera seccion\r\n  const btns_navtabs = document.querySelectorAll('.tabs span');\r\n  const paginas = document.querySelectorAll<HTMLElement>('.paginas'); //seleccionamos las secciones o paginas a mostrar\r\n  btns_navtabs.forEach(Element => {\r\n      Element.addEventListener('click', (e)=>{ //cada btn o enlace\r\n          const target = e.target as HTMLElement;\r\n          paginas.forEach(pagina =>pagina.style.display = \"none\"); ////quitamos la class mostrarseccion a todas las secciones\r\n          document.querySelector<HTMLElement>(`.${target.id}`)!.style.display = \"block\"; //añadimos la class mostrarseccion a la la seccion o pagina correspondiente\r\n      });\r\n  });\r\n}\r\n\r\nfunction mesyañoactual():[string, number]\r\n{\r\n  const fecha = new Date();\r\n  const mesTexto:string = fecha.toLocaleString('es-CO', { month: 'long' });\r\n  const año:number = fecha.getFullYear();\r\n  return [mesTexto, año];\r\n}\r\n\r\nfunction getDgv(nit: number): number {\r\n    const multiplicadores = [3, 7, 13, 17, 19, 23, 29, 37, 41, 43, 47, 53, 59, 67, 71];\r\n    const digitos = nit.toString().trim().split('').map(Number);\r\n    let suma = 0;\r\n    digitos.forEach((digito, indice) => {\r\n        const posicionMultiplicador = digitos.length - indice;\r\n        suma += digito * multiplicadores[posicionMultiplicador - 1];\r\n    }); \r\n    const modulo = suma%11;\r\n    return modulo > 1 ?(11 - modulo):modulo;\r\n}\r\n\r\n","(function():void{\r\n  if(document.querySelector('.inicio')){\r\n    \r\n    async function ventasgraficas($url:string, $dato:string){\r\n      try{\r\n        const respuesta = await fetch($url); \r\n        const resultado = await respuesta.json();\r\n        if($dato == 'ventasVsGastos')graficaVentasVsGastos(resultado);\r\n        if($dato == 'ultimos7dias')ventas7dias(resultado);\r\n      }catch(error){\r\n            console.log(error);\r\n      }\r\n    }\r\n    ventasgraficas('/admin/api/ventasVsGastos', 'ventasVsGastos');\r\n    ventasgraficas('/admin/api/ultimos7dias', 'ultimos7dias');\r\n\r\n    // Ventas por horas (hoy) - ejemplo 24 horas o por horas de apertura (aquí 10 valores)\r\n    const ventasPorHoras = {\r\n      labels: [\"08:00\",\"09:00\",\"10:00\",\"11:00\",\"12:00\",\"13:00\",\"14:00\",\"15:00\",\"16:00\",\"17:00\"],\r\n      data:    [5, 12, 20, 35, 60, 48, 30, 22, 15, 10]\r\n    };\r\n\r\n\r\n    // Gastos por transacción (gráfico doughnut)\r\n    const gastosTransaccion = {\r\n      labels: [\"Comisiones\", \"Materia Primas\", \"Servicios\", \"Otros\"],\r\n      data:   [15, 50, 25, 10] // porcentajes o montos relativos\r\n    };\r\n\r\n\r\n    // ---------- Charts ----------\r\n\r\n    // Ventas por horas (line)\r\n    /*const ctxHoras = (document.getElementById('chartVentasHoras') as HTMLCanvasElement).getContext('2d');\r\n    new Chart(ctxHoras, {\r\n      type: 'line',\r\n      data: {\r\n        labels: ventasPorHoras.labels,\r\n        datasets: [{\r\n          label: 'Ventas (unidades)',\r\n          data: ventasPorHoras.data,\r\n          borderColor: '#6366F1',\r\n          backgroundColor: 'rgba(99,102,241,0.12)',\r\n          fill: true,\r\n          tension: 0.35,\r\n          pointRadius: 3\r\n        }]\r\n      },\r\n      options: {\r\n        responsive: true,\r\n        scales: {\r\n          y: { beginAtZero: true }\r\n        },\r\n        plugins: {\r\n          tooltip: {\r\n            callbacks: {\r\n              label: (ctx:any) => ` ${ctx.parsed.y} unidades`\r\n            }\r\n          },\r\n          legend: { display: false }\r\n        }\r\n      }\r\n    });*/\r\n\r\n    // Ingresos por día (bar)\r\n    function ventas7dias(resultado:{dia:string, ventas_totales:string}[]){\r\n      const ctxIngresosDias = (document.getElementById('chartIngresosDias') as HTMLCanvasElement).getContext('2d');\r\n      new Chart(ctxIngresosDias, {\r\n        type: 'bar',\r\n        data: {\r\n          labels: resultado.map(x=>x.dia),\r\n          datasets: [{\r\n            label: 'Ingresos',\r\n            data: resultado.map(x=>x.ventas_totales),\r\n            backgroundColor: '#10B981'\r\n          }]\r\n        },\r\n        options: {\r\n          responsive: true,\r\n          plugins: { legend: { display: false } },\r\n          scales: {\r\n            y: {\r\n              beginAtZero: true,\r\n            }\r\n          }\r\n        }\r\n      });\r\n    }\r\n\r\n    // Gastos por transacción (doughnut)\r\n    /*const ctxGastos = (document.getElementById('chartGastosTransaccion') as HTMLCanvasElement).getContext('2d');\r\n    new Chart(ctxGastos, {\r\n      type: 'doughnut',\r\n      data: {\r\n        labels: gastosTransaccion.labels,\r\n        datasets: [{\r\n          data: gastosTransaccion.data,\r\n          backgroundColor: ['#EF4444','#F59E0B','#3B82F6','#6B7280']\r\n        }]\r\n      },\r\n      options: {\r\n        responsive: true,\r\n        plugins: {\r\n          legend: { position: 'bottom' }\r\n        }\r\n      }\r\n    });*/\r\n\r\n    function graficaVentasVsGastos(resultado:{periodo:string[], ventastotales:string[], gastostotales:string[]}){\r\n      // Ventas vs Gastos (combinado: barras gastos + línea ventas)\r\n      const ctxVG = (document.getElementById('chartVentasGastos') as HTMLCanvasElement).getContext('2d');\r\n      new Chart(ctxVG, {\r\n        data: {\r\n          labels: resultado.periodo,\r\n          datasets: [\r\n            {\r\n              type: 'bar',\r\n              label: 'Ventas',\r\n              data: resultado.ventastotales,\r\n              backgroundColor: 'rgba(239,68,68,0.8)'\r\n            },\r\n            {\r\n              type: 'line',\r\n              label: 'Gastos',\r\n              data: resultado.gastostotales,\r\n              borderColor: '#4F46E5',\r\n              backgroundColor: 'rgba(79,70,229,0.15)',\r\n              tension: 0.3,\r\n              fill: true,\r\n              yAxisID: 'y1'\r\n            }\r\n          ]\r\n        },\r\n        options: {\r\n          responsive: true,\r\n          plugins: { legend: { position: 'bottom' } },\r\n          scales: {\r\n            y: {\r\n              beginAtZero: true,\r\n              position: 'left',\r\n              title: { display: true, text: 'Ventas (COP)' }\r\n            },\r\n            y1: {\r\n              beginAtZero: true,\r\n              position: 'right',\r\n              grid: { drawOnChartArea: false },\r\n              title: { display: true, text: 'Gastos (COP)' }\r\n            }\r\n          },\r\n        }\r\n      });\r\n    }\r\n    \r\n\r\n  }\r\n})();","\r\n\r\n// const mobilemenu1 = document.querySelector('#mobile-menu1')as HTMLButtonElement;\r\n// const miDialogomenumovil = document.querySelector('#miDialogomenumovil') as any;\r\n\r\n// mobilemenu1.addEventListener('click', ()=>{\r\n//     miDialogomenumovil.showModal();\r\n//     document.addEventListener('click', cerrarDialogoExterno);\r\n// });\r\n\r\n\r\n// function cerrarDialogoExterno(event:Event){\r\n//  const f = event.target;\r\n//  if(f === miDialogomenumovil){\r\n//     miDialogomenumovil.close();\r\n//  }\r\n// }\r\nconst mobilemenu1 = document.querySelector('#mobile-menu1') as HTMLButtonElement;\r\nconst miDialogomenumovil = document.querySelector('#miDialogomenumovil') as HTMLDialogElement;\r\n\r\n// aseguramos que al cargar la página el modal esté cerrado y oculto\r\nmiDialogomenumovil.close();\r\nmiDialogomenumovil.setAttribute('hidden', 'true');\r\n\r\nmobilemenu1.addEventListener('click', () => {\r\n  miDialogomenumovil.showModal();\r\n  miDialogomenumovil.removeAttribute('hidden');\r\n  document.addEventListener('click', cerrarDialogoExterno);\r\n});\r\n\r\nfunction cerrarDialogoExterno(event: Event) {\r\n  const f = event.target;\r\n  if (f === miDialogomenumovil) {\r\n    miDialogomenumovil.close();\r\n    miDialogomenumovil.setAttribute('hidden', 'true');\r\n    document.removeEventListener('click', cerrarDialogoExterno);\r\n  }\r\n}\r\n\r\n\r\n","(()=>{\r\n    if(document.querySelector('.perfil')){\r\n      const btnCambiarEmail = document.querySelector('#btnCambiarEmail');\r\n      const miDialogoUpEmail = document.querySelector('#miDialogoUpEmail') as any;\r\n      //const btnCerrarUpDireccion = document.querySelector('#btnCerrarUpDireccion') as HTMLButtonElement;\r\n      \r\n  \r\n      btnCambiarEmail?.addEventListener('click', (e):void=>{\r\n        miDialogoUpEmail.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }); \r\n\r\n      //btnCerrarUpDireccion.addEventListener('click', ()=>miDialogoUpDireccion.close());\r\n\r\n  \r\n      function cerrarDialogoExterno(event:Event) {\r\n        if (event.target === miDialogoUpEmail || (event.target as HTMLInputElement).value === 'salir') {\r\n          miDialogoUpEmail.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n    }\r\n  \r\n  })();","(()=>{\r\n    if(document.querySelector('.ajustarcostos')){\r\n        let tablaAjustarCostos:HTMLElement;\r\n\r\n        type conversionunidadesapi = {\r\n            id:string,\r\n            idproducto: string,\r\n            idsubproducto: string,\r\n            idunidadmedidabase: string,\r\n            idunidadmedidadestino: string,\r\n            nombreunidadbase: string,\r\n            nombreunidaddestino: string,\r\n            factorconversion: string,\r\n            //idservicios:{idempleado:string, idservicio:string}[]\r\n          };\r\n\r\n        let allConversionUnidades:conversionunidadesapi[] = [];\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json();\r\n                console.log(allConversionUnidades);\r\n                pirntUnidades();\r\n                tablaAjustarCostos = ($('#tablaAjustarCostos') as any).DataTable(configdatatablesajustarcostos);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        //tablaAjustarCostos = ($('#tablaAjustarCostos') as any).DataTable(configdatatables);\r\n        //indiceFila = (tablaAjustarCostos as any).row(1).data();\r\n\r\n        function pirntUnidades():void{\r\n            allConversionUnidades.forEach(subUnd =>{\r\n                let select = document.querySelector(`tr[data-idsubproducto=\"${subUnd.idsubproducto}\"]`)?.children[5].children[0];\r\n                if(select == undefined)select = document.querySelector(`tr[data-idproducto=\"${subUnd.idproducto}\"]`)?.children[5].children[0];\r\n                const option = document.createElement('option');\r\n                option.textContent = subUnd.nombreunidaddestino;\r\n                option.dataset.factor = subUnd.factorconversion;\r\n                select?.appendChild(option);\r\n            });\r\n        }\r\n \r\n\r\n        /*const fila = (tablaAjustarCostos as any).row((idx:number, data:any, node:HTMLElement)=>{\r\n            return node.dataset.idproducto === subUnd.idsubproducto;\r\n        }).data();*/\r\n        //console.log(fila[4]);\r\n      /*fila[4] = `<select class=\"formulario__select\" required>\r\n                        <option value=\"\" disabled selected>-Seleccionar-</option>\r\n                        <option value=\"\"> Unidad </option>\r\n                    </select>`;\r\n        (tablaAjustarCostos as any).row(2).data(fila).draw();*/\r\n\r\n        //tablaAjustarCostos = ($('#tablaAjustarCostos') as any).DataTable(configdatatables);\r\n        \r\n        document.querySelector('#tablaAjustarCostos')?.addEventListener('input', (e:Event)=>{\r\n            var input = e.target as HTMLInputElement;\r\n            let tipoelemento:string = '', idelemento:string = '';\r\n            if((input as HTMLInputElement).classList.contains('inputAjustarCosto')){\r\n                \r\n                var tr = input.closest('tr');\r\n                const selectUnidad = tr?.querySelector('.formulario__select') as HTMLSelectElement;\r\n                const factor:number = Number(selectUnidad.options[selectUnidad.selectedIndex].dataset.factor);\r\n                \r\n                var trx = input.closest('.fila') as HTMLElement;\r\n                if(!trx)trx = input.closest('tr')?.previousSibling as HTMLElement;\r\n\r\n                if(trx.classList.contains('producto')){\r\n                    idelemento = trx.dataset.idproducto!;\r\n                    tipoelemento = '0'; //si es producto\r\n                }\r\n                else{\r\n                    idelemento = trx.dataset.idsubproducto!;\r\n                    tipoelemento = '1';  // si es un subproducto\r\n                }\r\n\r\n                ////////////// enviar datos por api para actualizar costos /////////////\r\n                actualizarcostos(tipoelemento, idelemento, factor, input);\r\n            }\r\n        });\r\n\r\n\r\n        function actualizarcostos(tipoelemento:string, idelemento:string, factor:number, input:HTMLInputElement){\r\n            if(input.value=='')input.value = '0';\r\n            const costo = Number(input.value)/factor;\r\n            console.log(costo);\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('tipoelemento', tipoelemento); //1 = subproducto\r\n                datos.append('idelemento', idelemento);\r\n                datos.append('precio_compra', costo+'');\r\n                try {\r\n                    const url = \"/admin/api/actualizarcostos\";  //asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        input.style.color = \"#02db02\";\r\n                        input.style.fontWeight = \"500\";\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n    }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.almacen')){\r\n        const btntrasladoinvnetario = document.querySelector('#btntrasladoinvnetario') as HTMLInputElement;\r\n        const btnXCerrarTrasladoInvnetario = document.querySelector('#btnXCerrarTrasladoInvnetario') as HTMLButtonElement;\r\n        const miDialogoTrasladoInvnetario = document.querySelector('#miDialogoTrasladoInvnetario') as any;\r\n        const reinciarinv = document.querySelector('#reinciarinv') as HTMLButtonElement;\r\n        const miDialogoStock = document.querySelector('#miDialogoStock') as any;\r\n        const modalStock = document.querySelector('#modalStock') as HTMLElement;\r\n        const selectStockRapidoUndmedida = document.querySelector('#selectStockRapidoUndmedida') as HTMLSelectElement;\r\n        let amount = document.querySelector('#cantidadStockRapido') as HTMLInputElement; //input cantidad de modal de stock rapido\r\n\r\n        const miDialogoIngresarProduccion = document.querySelector('#miDialogoIngresarProduccion') as any;\r\n        const selectitemAproducir = document.querySelector('#itemAproducir') as HTMLSelectElement;\r\n        const btnsproduccion = document.querySelectorAll<HTMLButtonElement>('.btnproduccion');  //btns ingresar descontar ajustar produccion\r\n        const selectIngresarProduccionUnidadmedida = document.querySelector('#selectIngresarProduccionUnidadmedida') as HTMLSelectElement;\r\n        const amountProduccion = document.querySelector('#stockIngresarProduccion') as HTMLInputElement;  //input cantidad cuando se ingresa orden de produccion\r\n        let cantidadactual = 0, indiceFila=0, endponit:string='', factorC = 0, tipoelemento:string = '', idelemento:string = '', tablaStockRapido:HTMLElement, tablaInventarioSedes:HTMLTableElement;\r\n    \r\n        const sedes = document.querySelector('#sedes');\r\n\r\n        interface datosProducto { stock: string, precio_compra: string, precio_venta: string }\r\n\r\n        type conversionunidadesapi = {\r\n            id:string,\r\n            idproducto:string,\r\n            idsubproducto: string,\r\n            idunidadmedidabase: string,\r\n            idunidadmedidadestino: string,\r\n            nombreunidadbase: string,\r\n            nombreunidaddestino: string,\r\n            factorconversion: string,\r\n          };\r\n\r\n          type productosXsucursal = {\r\n            productoid:string,\r\n            subproductoid: string,\r\n            nombreproducto:string,\r\n            sucursalid: string,\r\n            sucursal: string,\r\n            stock: string,\r\n          };\r\n\r\n        let allproductsXsucursal:productosXsucursal[]=[], allConversionUnidades:conversionunidadesapi[] = [];\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json();\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        //apertura de la venta modal para las opcionesde traslado de inventario\r\n        btntrasladoinvnetario.addEventListener('click', ()=>{\r\n            miDialogoTrasladoInvnetario.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n\r\n        reinciarinv.addEventListener('click', (e)=>{\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea reiniciar el inventario a cero?',\r\n                text: \"Todos los productos e insumos del inventario se reiniciaran a cero.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n                    (async ()=>{\r\n                        try {\r\n                            const url = \"/admin/api/reiniciarinv\"; //llamado a la API REST y se trae las direcciones segun cliente elegido\r\n                            const respuesta = await fetch(url); \r\n                            const resultado = await respuesta.json();\r\n                            (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n                            if(resultado.exito !== undefined){ \r\n                                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                                setTimeout(() => {\r\n                                window.location.reload();  \r\n                                }, 1270);\r\n                            }else{\r\n                                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();\r\n                }\r\n            });\r\n        });\r\n\r\n\r\n        sedes?.addEventListener('change', (e:Event)=>{\r\n            if((e.target as HTMLInputElement).checked){\r\n                (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n                (async ()=>{\r\n                    try {\r\n                        const url = \"/admin/api/getStockproductosXsucursal\"; //llamado a la API REST en el controlador almacencontrolador para treaer todos los productos con su respectiva sucursal y stock\r\n                        const respuesta = await fetch(url); \r\n                        allproductsXsucursal = await respuesta.json();\r\n                        printstockXsucursal();\r\n                        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();\r\n            }\r\n        });\r\n\r\n\r\n        /////////////////////////////////////  SOTCK RAPIDO ////////////////////////////////////////\r\n        /*document.querySelector('#stockproducto')?.addEventListener('click', (e)=>{\r\n            if((e.target as HTMLInputElement).checked){\r\n                 tablaStockRapido = ($('#tablaStockRapido') as any).DataTable(configdatatables);\r\n            }\r\n        })*/\r\n        tablaStockRapido = ($('#tablaStockRapido') as any).DataTable(configdatatablesstockrapido);\r\n\r\n        document.querySelector('#tablaStockRapido')?.addEventListener(\"click\", (e:Event)=>{ //evento click sobre toda la tabla\r\n            let options:string = '';\r\n            const target = e.target as HTMLElement;\r\n\r\n           if(target.closest('.btnsproducto')){\r\n                idelemento = target.closest('.btnsproducto')!.id;\r\n                tipoelemento = '0'; //si es producto\r\n                cantidadactual = Number((target.closest('.btnsproducto') as HTMLElement).dataset.stock);\r\n                document.querySelector('#nombreItemstockrapido')!.textContent = (target.closest('.btnsproducto') as HTMLElement).dataset.nombre!;\r\n            }\r\n            if(target.closest('.btnssubproducto')){\r\n                idelemento = target.closest('.btnssubproducto')!.id;\r\n                tipoelemento = '1'; //si es un subproducto\r\n                cantidadactual = Number((target.closest('.btnssubproducto') as HTMLElement).dataset.stock);\r\n                document.querySelector('#nombreItemstockrapido')!.textContent = (target.closest('.btnssubproducto') as HTMLElement).dataset.nombre!;\r\n            }\r\n\r\n            while(selectStockRapidoUndmedida.firstChild)selectStockRapidoUndmedida.removeChild(selectStockRapidoUndmedida.firstChild);\r\n            if(tipoelemento == '0'){\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == idelemento); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n                selectStockRapidoUndmedida.insertAdjacentHTML('afterbegin', options);\r\n            }\r\n            if(tipoelemento == '1'){\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == idelemento); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n                selectStockRapidoUndmedida.insertAdjacentHTML('afterbegin', options);\r\n            }\r\n            \r\n            if((e.target as HTMLElement)?.classList.contains(\"descontarStock\")||(e.target as HTMLElement).parentElement?.classList.contains(\"descontarStock\"))descontarStock(e);\r\n            if((e.target as HTMLElement)?.classList.contains(\"aumentarStock\")||(e.target as HTMLElement).parentElement?.classList.contains(\"aumentarStock\"))aumentarStock(e);\r\n            if((e.target as HTMLElement)?.classList.contains(\"ajustarStock\")||(e.target as HTMLElement).parentElement?.classList.contains(\"ajustarStock\"))ajustarStock(e);\r\n        });\r\n\r\n        //EDITAR STOCK\r\n        function descontarStock(e:Event){\r\n            modalStock.textContent = \"Descontar cantidad a inventario\"\r\n            endponit = \"descontarstock\";\r\n            indiceFila = (tablaStockRapido as any).row((e.target as HTMLElement).closest('tr')).index();\r\n            miDialogoStock.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n        function aumentarStock(e:Event){\r\n            modalStock.textContent = \"Ingreasar cantidad a inventario\"\r\n            endponit = \"aumentarstock\";\r\n            indiceFila = (tablaStockRapido as any).row((e.target as HTMLElement).closest('tr')).index();\r\n            miDialogoStock.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n        function ajustarStock(e:Event){\r\n            modalStock.textContent = \"Ajustar cantidad a inventario\"\r\n            endponit = \"ajustarstock\";\r\n            indiceFila = (tablaStockRapido as any).row((e.target as HTMLElement).closest('tr')).index();\r\n            miDialogoStock.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n\r\n        document.querySelector('#formStock')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            factorC = Number(selectStockRapidoUndmedida.options[selectStockRapidoUndmedida.selectedIndex].dataset.factor);\r\n            let info = (tablaStockRapido as any).page.info(), AmountItem:number = factorC*Number(amount.value);\r\n            \r\n            if(endponit == \"descontarstock\")cantidadactual = cantidadactual-AmountItem;\r\n            if(endponit == \"aumentarstock\")cantidadactual = cantidadactual+AmountItem;\r\n            if(endponit == \"ajustarstock\")cantidadactual = AmountItem;\r\n\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('tipoitem', tipoelemento);\r\n                datos.append('iditem', idelemento);\r\n                datos.append('cantidad', AmountItem.toString());\r\n                try{\r\n                    const url = \"/admin/api/\"+endponit;  //asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                        ////// reset form ///////\r\n                        (document.querySelector('#formStock') as HTMLFormElement)?.reset();\r\n                        //actualizar fila\r\n                        //(tablaStockRapido as any).cell(indiceFila, 3).data(cantidadactual).draw();\r\n                        //(tablaStockRapido as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                        //actualiza tabla stock rapido\r\n                        actualizarStockRapido([resultado.item[0]], tipoelemento);\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                    miDialogoStock.close();\r\n                    document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                }catch(error){\r\n                    console.log(error);\r\n                }\r\n            })();//cierre de async()\r\n        });\r\n\r\n    //////////////////////////  UTILIDAD PRODUCTO  ///////////////////////////\r\n    ($('#utilidadProductos') as any).DataTable(configdatatablesstockrapido);  \r\n\r\n\r\n    //////////////////////////// SOTCK POR SUCURSAL //////////////////////\r\n    function printstockXsucursal(){\r\n        const sucursales = [...new Set(allproductsXsucursal.map(d => d.sucursal))]; //lista unica de sucursales\r\n        \r\n        // 2. Reorganizar por producto\r\n        const productos: Record<string, { nombreproducto: string; stocks: Record<string, string> }> = {};\r\n        allproductsXsucursal.forEach(d => {\r\n            if(d.productoid){\r\n                if (!productos['p'+d.productoid]) { //si el obj no es creado se crea con el nombre del producto pero el stock vacio\r\n                    productos['p'+d.productoid] = { nombreproducto: d.nombreproducto, stocks: {} };\r\n                }\r\n                productos['p'+d.productoid].stocks[d.sucursal] = d.stock; //aqui se llena el stock, que es un obj y sus propiedades son las sedes\r\n            }\r\n            if(d.subproductoid){\r\n                if (!productos['s'+d.subproductoid]) { //si el obj no es creado se crea con el nombre del producto pero el stock vacio\r\n                    productos['s'+d.subproductoid] = { nombreproducto: 'S-'+d.nombreproducto, stocks: {} };\r\n                }\r\n                productos['s'+d.subproductoid].stocks[d.sucursal] = d.stock; //aqui se llena el stock, que es un obj y sus propiedades son las sedes\r\n            }\r\n        });\r\n\r\n        // 3. Columnas dinámicas\r\n        const columnas = [{ title: \"Producto\", data: \"nombreproducto\" }];\r\n        sucursales.forEach(s => {\r\n            columnas.push({ title: s, data: s });\r\n        });\r\n\r\n        // 4. Dataset\r\n        const dataset = Object.values(productos).map(prod => {\r\n            const fila: any = { nombreproducto: prod.nombreproducto };\r\n            sucursales.forEach(s => {\r\n                fila[s] = prod.stocks[s] ?? 0; //fila es un obj, se crea la propieadad con el nombre de la sucursal y se iguala al objeto stock copn propiedad sucursal.\r\n            });\r\n            return fila;\r\n        });\r\n\r\n        tablaInventarioSedes = ($('#tablaInventarioSedes') as any).DataTable({\r\n            data: dataset,\r\n            columns: columnas,\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                    {extend: 'copyHtml5', text: 'Copia'}, \r\n                    {extend: 'excelHtml5', title: 'InventarioXsede'}, \r\n                    {extend: 'pdfHtml5', title: 'InventarioXsede'}, \r\n                    {extend: 'print', title: 'InventarioXsede', text: 'Imprimir'},\r\n                    'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n            pageLength: 25,\r\n            paging: true,\r\n            lengthChange: true,\r\n            searching: true,\r\n            ordering: true,\r\n            info: true,\r\n            autoWidth: true,\r\n            responsive: true,\r\n            deferRender: true,\r\n            //retrieve: true,\r\n            processing: true,\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando 1 de _MAX_ registros',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            destroy: true, // importante si recargas la tabla\r\n        });\r\n\r\n    }\r\n\r\n\r\n    ///////////////////////////// INGRESAR ORDEN DE PRODUCCION /////////////////////////////////\r\n        \r\n        //SELECT2 DE itemAproducir\r\n        ($('#itemAproducir') as any).select2({\r\n            maximumSelectionLength: 1,\r\n        });\r\n\r\n        ////// evento al select del producto a producir ////// \r\n        $(\"#itemAproducir\").on('change', (e)=>{\r\n            const idproducto = (e.target as HTMLOptionElement).value;\r\n            const selectedOption = $(\"#itemAproducir option:selected\");\r\n            if(idproducto){\r\n                const prodund = allConversionUnidades.filter(x =>x.idproducto == idproducto);\r\n                mostrarSelectUnidades(prodund);\r\n                let producto: datosProducto; //inicializamos el objeto de tipo interfaz \r\n                producto = {\r\n                    stock: selectedOption.data('stock'),\r\n                    precio_compra: selectedOption.data('precio_compra'),\r\n                    precio_venta: selectedOption.data('precio_venta')\r\n                }\r\n                mostrarInfoItem(producto);\r\n            }\r\n        });\r\n\r\n        /////////// CARGAR LAS UNIDADES DE MEDIDA EN EL SELECT unidadmedida  ////////////\r\n        function mostrarSelectUnidades(prodund:conversionunidadesapi[]):void{\r\n            while(selectIngresarProduccionUnidadmedida?.firstChild)selectIngresarProduccionUnidadmedida.removeChild(selectIngresarProduccionUnidadmedida?.firstChild);\r\n            prodund.forEach(und =>{\r\n              const option = document.createElement('option');\r\n              option.textContent = und.nombreunidaddestino;\r\n              option.value = und.id;  //und.id  =  es el id de la tabla conversionunidades\r\n              option.dataset.factor = und.factorconversion;\r\n              selectIngresarProduccionUnidadmedida.appendChild(option);\r\n            });\r\n        }\r\n\r\n        btnsproduccion.forEach((btnproduccion, index) =>{\r\n            btnproduccion.addEventListener('click', (e)=>{\r\n               if(selectitemAproducir.value){    \r\n                    document.querySelector('#nombreItemAProducir')!.textContent = selectitemAproducir.options[selectitemAproducir.selectedIndex].textContent;\r\n                    if(index === 0){\r\n                        endponit = \"aumentarstock\";\r\n                        document.querySelector('#modalIngresarProduccion')!.textContent = \"Ingreasar produccion a inventario\";\r\n                    }\r\n                    if(index === 1){\r\n                        endponit = \"descontarstock\";\r\n                        document.querySelector('#modalIngresarProduccion')!.textContent = \"Descontar catnidad de inventario\";\r\n                    }\r\n                    if(index === 2){\r\n                        endponit = \"ajustarstock\";\r\n                        document.querySelector('#modalIngresarProduccion')!.textContent = \"Ajustar cantidad de inventario\";\r\n                    }\r\n                    miDialogoIngresarProduccion.showModal();\r\n                    document.addEventListener(\"click\", cerrarDialogoExterno);\r\n                }\r\n            });\r\n        });\r\n\r\n\r\n        document.querySelector('#formIngresarProduccion')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            factorC = Number(selectIngresarProduccionUnidadmedida.options[selectIngresarProduccionUnidadmedida.selectedIndex].dataset.factor);\r\n            let AmountItemProduccion:number = factorC*Number(amountProduccion.value);\r\n\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('tipoitem', '0'); //0 = producto,  1 = subproducto\r\n                datos.append('iditem', selectitemAproducir.value);\r\n                datos.append('cantidad', AmountItemProduccion.toString());\r\n                datos.append('construccion', '1');  //se indica al backend que es construccion y se debe descontar sus insumos\r\n                try{\r\n                    const url = \"/admin/api/\"+endponit;  //endpoint = aumentarstock para produccion, asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                        ////// reset form ///////\r\n                        (document.querySelector('#formIngresarProduccion') as HTMLFormElement)?.reset();\r\n                        //mostrar contaidad actual\r\n                        mostrarInfoItem(resultado.item[0]); //producto\r\n                        //actualizar tabla stock rapido\r\n                        if(resultado.insumos !== undefined)actualizarStockRapido(resultado.insumos[0], '1'); //subproductos\r\n                        //actualizar el selecto de los productos/insumos a producir\r\n                        $(\"#itemAproducir option:selected\").data('stock', resultado.item[0].stock);\r\n                        \r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                    miDialogoIngresarProduccion.close();\r\n                    document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                }catch(error){\r\n                    console.log(error);\r\n                }\r\n            })();//cierre de async()\r\n        });\r\n\r\n\r\n        function mostrarInfoItem(producto:{stock:string, precio_compra:string, precio_venta:string}){\r\n            document.querySelector('#stock')!.textContent = Number(producto.stock).toLocaleString();\r\n            document.querySelector('#costoProduccion')!.textContent = \"$\"+Number(producto.precio_compra).toLocaleString();\r\n            document.querySelector('#precioVenta')!.textContent = \"$\"+Number(producto.precio_venta).toLocaleString();\r\n        }\r\n\r\n\r\n        function actualizarStockRapido(insumosProductos:{id:string, productoid:string, subproductoid:string, sucursalid:string, stock:string, stockminimo:string}[], tipoItem:string){\r\n            insumosProductos.forEach(element => {\r\n                (tablaStockRapido as any).rows().every(function (this: any){\r\n                    const rowNode = this.node() as HTMLTableRowElement;\r\n                    let id_element = element.subproductoid, idAttr = rowNode.getAttribute('data-idsubproducto');\r\n                    if(tipoItem == '0'){\r\n                        idAttr = rowNode.getAttribute('data-idproducto');\r\n                        id_element = element.productoid;\r\n                    }\r\n                    if (idAttr && idAttr === id_element){\r\n                        this.cell(this.index(), 3).data(`<div class=\"text-center px-3 py-4 rounded-lg\">${element.stock}</div>`);\r\n\r\n                        // Obtén el <td> real\r\n                        const td = (tablaStockRapido as any).cell(this.index(), 3).node() as HTMLTableCellElement;\r\n                        if(Number(element.stock) <= Number(element.stockminimo)){\r\n                            td.firstElementChild?.classList.remove('bg-cyan-50', 'text-cyan-600');\r\n                            td.firstElementChild?.classList.add('bg-red-50', 'text-red-800');\r\n                        }else{\r\n                            td.firstElementChild?.classList.remove('bg-red-50', 'text-red-800');\r\n                            td.firstElementChild?.classList.add('bg-cyan-50', 'text-cyan-600');\r\n                        }\r\n                    } \r\n                });\r\n            })\r\n        }\r\n\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const btnxcerrartrasInv = (event.target as HTMLElement).parentElement?.id;\r\n            if (event.target === miDialogoTrasladoInvnetario || btnxcerrartrasInv == \"btnXCerrarTrasladoInvnetario\" || event.target === btnXCerrarTrasladoInvnetario || event.target === miDialogoStock || event.target === miDialogoIngresarProduccion || (event.target as HTMLInputElement).value === 'salir') {\r\n                miDialogoStock.close();\r\n                miDialogoIngresarProduccion.close();\r\n                miDialogoTrasladoInvnetario.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n            }\r\n        }\r\n\r\n\r\n    }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.categorias')){\r\n    const crearCategoria = document.querySelector('#crearCategoria');\r\n    const miDialogoCategoria = document.querySelector('#miDialogoCategoria') as any;\r\n    let indiceFila=0, control=0, tablaCategorias:HTMLElement;\r\n\r\n    type productsapi = {\r\n      id:string,\r\n      idcategoria: string,\r\n      nombre: string,\r\n      foto: string,\r\n      marca: string,\r\n      codigo: string,\r\n      descripcion: string,\r\n      peso: string,\r\n      medidas: string,\r\n      color: string,\r\n      funcion: string,\r\n      uso:string,\r\n      fabricante: string,\r\n      garantia: string,\r\n      stock: string,\r\n      categoria: string,\r\n      precio_compra: string,\r\n      precio_venta: string,\r\n      fecha_ingreso: string,\r\n      //idservicios:{idempleado:string, idservicio:string}[]\r\n    };\r\n\r\n    let products:productsapi[]=[], unproducto:productsapi;\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaCategorias = ($('#tablaCategorias') as any).DataTable(configdatatables25reg);\r\n\r\n    crearCategoria?.addEventListener('click', (e):void=>{\r\n      control = 0;\r\n      limpiarformdialog();\r\n      document.querySelector('#modalCategoria')!.textContent = \"Crear categoria\";\r\n      (document.querySelector('#btnEditarCrearCategoria') as HTMLInputElement).value = \"Crear\";\r\n      miDialogoCategoria.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    document.querySelector('#tablaCategorias')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarCategoria\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarCategoria\"))editarCategoria(e);\r\n      if(target?.classList.contains(\"eliminarCategoria\")||target.parentElement?.classList.contains(\"eliminarCategoria\"))eliminarCategoria(e);\r\n    });\r\n\r\n    function editarCategoria(e:Event){\r\n      control = 1;\r\n      let idcategoria = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idcategoria = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      //(document.querySelector('#formCrearUpdateCategoria') as HTMLFormElement).action = \"/admin/almacen/actualizar_categoria\";\r\n      document.querySelector('#modalCategoria')!.textContent = \"Actualizar categoria\";\r\n      (document.querySelector('#btnEditarCrearCategoria') as HTMLInputElement)!.value = \"Actualizar\";\r\n      (document.querySelector('#idcategoria') as HTMLInputElement).value = idcategoria;\r\n      (document.querySelector('#categoria') as HTMLInputElement).value = ((e.target as HTMLElement).closest('.acciones-btns') as HTMLElement)?.dataset.categoria!; \r\n      indiceFila = (tablaCategorias as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoCategoria.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar categoria  //////////////////////\r\n    document.querySelector('#formCrearUpdateCategoria')?.addEventListener('submit', e=>{\r\n      if(control){\r\n        e.preventDefault();\r\n        var info = (tablaCategorias as any).page.info();\r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', $('#idcategoria').val() as string);\r\n          datos.append('nombre', $('#categoria').val()as string);\r\n          try {\r\n              const url = \"/admin/api/actualizar_categoria\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json(); \r\n              console.log(resultado); \r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                ///////// cambiar la fila completa, su contenido //////////\r\n                const datosActuales = (tablaCategorias as any).row(indiceFila+=info.start).data();\r\n                /*Nombre categoria*/datosActuales[2] = $('#categoria').val();\r\n                /*data-categoria*/datosActuales[4] = `<div class=\"acciones-btns\" id=\"${$('#idcategoria').val()}\" data-categoria=\"${$('#categoria').val()}\"><button class=\"btn-md btn-turquoise editarCategoria\"><i class=\"fa-solid fa-pen-to-square\"></i></button><button class=\"btn-md btn-red eliminarCategoria\"><i class=\"fa-solid fa-trash-can\"></i></button></div>`;//$('#categoria').val();\r\n                \r\n                (tablaCategorias as any).row(indiceFila).data(datosActuales).draw();\r\n                (tablaCategorias as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n              document.addEventListener(\"click\", cerrarDialogoExterno);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n      } //fin if(control)\r\n    });\r\n\r\n    function eliminarCategoria(e:Event){\r\n      let idcategoria = (e.target as HTMLElement).parentElement!.id, info = (tablaCategorias as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idcategoria = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaCategorias as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar la categoria?',\r\n          text: \"La categoria y sus productos asociados, seran eliminados definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idcategoria);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarCategoria\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();\r\n                      if(resultado.length || resultado.exito !== undefined){\r\n                        (tablaCategorias as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaCategorias as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCategoria') as HTMLFormElement)?.reset();\r\n      (document.querySelector('#formCrearUpdateCategoria') as HTMLFormElement).action = \"/admin/almacen/crear_categoria\";\r\n      (document.querySelector('#idcategoria') as HTMLInputElement).value = '0';\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoCategoria || (event.target as HTMLInputElement).value === 'Salir' || (event.target as HTMLInputElement).value === 'Actualizar') {\r\n        miDialogoCategoria.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n  }\r\n\r\n})();","\r\n(()=>{\r\n    if(document.querySelector('.compras')){\r\n        const proveedor = document.querySelector('#proveedor') as HTMLSelectElement;\r\n        const impuesto = document.querySelector('#inputimpuesto') as HTMLInputElement;\r\n        const nfactura = document.querySelector('#nfactura') as HTMLInputElement;\r\n        const fecha = document.querySelector('#fecha') as HTMLDataElement;\r\n        const origenPago = document.querySelector('#origenPago') as HTMLSelectElement;\r\n        const origenCaja = document.querySelector('#origenCaja') as HTMLSelectElement;\r\n        const origenBanco = document.querySelector('#origenBanco') as HTMLSelectElement;\r\n        const formapago = document.querySelector('#formapago') as HTMLSelectElement;\r\n        const observacion = document.querySelector('#observacion') as HTMLInputElement;\r\n        const btnvaciar = document.querySelector('#btnvaciar');\r\n        const miDialogoVaciar = document.querySelector('#miDialogoVaciar') as any;\r\n        const miDialogoRegistrarcompra = document.querySelector('#miDialogoRegistrarcompra') as any;\r\n        const tablaCompras = document.querySelector('#tablaCompras tbody');\r\n\r\n        type conversionunidadesapi = {\r\n        id:string,\r\n        idproducto: string,\r\n        idsubproducto: string,\r\n        idunidadmedidabase: string,\r\n        idunidadmedidadestino: string,\r\n        nombreunidadbase: string,\r\n        nombreunidaddestino: string,\r\n        factorconversion: string,\r\n        //idservicios:{idempleado:string, idservicio:string}[]\r\n        };\r\n\r\n        let carrito:{iditem:string, idpx:string, idsx:string, tipo: string, nombreitem:string, unidad:string, cantidad: number, cantidadcomprado: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra: number, valorcompra: number}[]=[];\r\n        let allConversionUnidades:conversionunidadesapi[] = [];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json();\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json(); \r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n\r\n        impuesto?.addEventListener('input', ()=>resumen());\r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#articulo') as any).select2({ \r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n                /*\r\n                templateResult: function (data:{id:string, text:string, tipo:string}) {\r\n                    // Personalizar cómo se muestra cada opción en el dropdown\r\n                    if (!data.id) { return data.text; }  // Si no hay id, solo mostrar el texto\r\n                    const html = `\r\n                        <div class=\"custom-option\">\r\n                            <span class=\"item-name\">${data.text}</span> \r\n                            <span class=\"item-type\">${data.tipo}</span>  <!-- Mostrar tipo adicional -->\r\n                        </div>`;\r\n                    return $(html);  // Devolver el HTML personalizado\r\n                }*/\r\n            });\r\n        }\r\n\r\n\r\n        //////////  ELEGIR ORIGEN DEL PAGO DE LA COMPRA, CAJA O BANCO ///////////\r\n        origenPago.addEventListener('change', (e:Event)=>{\r\n            if((e.target as HTMLOptionElement).value == '0'){ //0 = origen caja\r\n                document.querySelector('#divBanco')?.classList.add('hidden');\r\n                document.querySelector('#divBanco')?.removeAttribute(\"required\");\r\n            }else{  //1 = origen banco\r\n                document.querySelector('#divBanco')?.classList.remove('hidden');\r\n                document.querySelector('#divBanco')?.setAttribute(\"required\", \"\");\r\n            }\r\n        });\r\n\r\n\r\n        ////// EVENTO AL SELECT ARTICULOS O ITEMS PARA SELECCIONAR EL ITEM Y AÑADIR AL CARRITO ////// \r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.iditem==datos.id&&x.tipo==datos.tipo);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!; //products es el arreglo de todos los productos traido por api\r\n                    const item:{iditem: string, idpx: string, idsx: string, tipo: string, nombreitem: string, unidad: string, cantidad: number, cantidadcomprado: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra:number, valorcompra: number} = {\r\n                        iditem: itemselected?.id!,\r\n                        idpx: itemselected.tipo=='0'?itemselected.id:'NULL',\r\n                        idsx: itemselected.tipo=='1'?itemselected.id:'NULL',\r\n                        tipo: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n                        nombreitem: itemselected.text,\r\n                        unidad: itemselected.unidadmedida,\r\n                        cantidad: 1,\r\n                        cantidadcomprado: 1,\r\n                        factor: 1,\r\n                        impuesto: 0,\r\n                        valorunidad: 0,\r\n                        subtotal: 0,\r\n                        precio_compra: 0,\r\n                        valorcompra: 0,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(datos.id, datos.tipo, datos.unidadmedida);\r\n                }\r\n            }\r\n        });\r\n\r\n\r\n        function printItemTable(id:string, tipo:string, unidadmedida:string){\r\n            let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            const unItem = filteredData.find(x=>x.id==id&&x.tipo==tipo)!;\r\n            if(tipo=='1'){   //si es un subproducto\r\n                options = \"\";\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == id); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            if(tipo=='0'){\r\n                options = \"\";\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.dataset.tipo = `${tipo}`;\r\n            tr.insertAdjacentHTML('afterbegin', `<td class=\"!px-0 !py-2 text-xl text-gray-500 leading-5\">${unItem?.text}</td> \r\n            <td class=\"!p-2 text-xl text-gray-500 leading-5\">\r\n                <select class=\"formulario__select selectunidad\">\r\n                    ${options}  \r\n                </select>\r\n            </td>\r\n            <td class=\"!px-0 !py-2\"><div class=\"flex\"><button type=\"button\"><span class=\"menos material-symbols-outlined\">remove</span></button><input type=\"text\" class=\"inputcantidad w-20 px-2 text-center\" value=\"1\" oninput=\"this.value = parseInt(this.value.replace(/[,.]/g, '')||1)\"><button type=\"button\"><span class=\"mas material-symbols-outlined\">add</span></button></div></td>\r\n            <td class=\"!p-2 text-xl text-gray-500 leading-5\"><input type=\"text\" placeholder=\"Ingresa Valor Total Producto\" class=\"inputcompra text-base sm:text-lg md:text-xl lg:text-2xl placeholder:text-sm sm:placeholder:text-base md:placeholder:text-lg lg:placeholder:text-xl bg-gray-50 border border-gray-300 text-gray-900 rounded-lg focus:border-indigo-600 block w-full p-2.5 dark:bg-gray-600 dark:border-gray-500 dark:placeholder-gray-400 dark:text-white h-14 focus:outline-none focus:ring-1\" value=\"\" oninput=\"this.value = parseInt(this.value.replace(/[,.]/g, '')||0)\"></td>\r\n            <td class=\"accionestd\"><div class=\"acciones-btns\"><button class=\"btn-md btn-red eliminarItem\"><i class=\"fa-solid fa-trash-can\"></i></button></div></td>`);\r\n            tablaCompras?.appendChild(tr);\r\n        }\r\n        \r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaCompras?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n\r\n            const itemCarrito = carrito.find(x=>x.iditem==iditem&&x.tipo==tipoitem)!;\r\n\r\n            if((e.target as HTMLElement).classList.contains('selectunidad')){\r\n                if((e.target as HTMLElement).dataset.event != \"eventSelect\"){\r\n                    e.target?.addEventListener('change', (e:Event)=>{\r\n                        const unit = e.target as HTMLSelectElement;\r\n                        itemCarrito.factor = Number(unit.options[unit.selectedIndex].dataset.factor);\r\n                    });\r\n                    (e.target as HTMLElement).dataset.event = \"eventSelect\"; //se marca al input que ya tiene evento añadido\r\n                }\r\n            }\r\n            \r\n            if((e.target as HTMLElement).classList.contains('menos')){\r\n                itemCarrito.cantidadcomprado--;\r\n                if(itemCarrito.cantidadcomprado<0)itemCarrito.cantidadcomprado = 0;\r\n            }\r\n\r\n            if((e.target as HTMLElement).classList.contains('inputcantidad')){\r\n                if((e.target as HTMLElement).dataset.event != \"eventInput\"){\r\n                    e.target?.addEventListener('input', (e:Event)=>{\r\n                        itemCarrito.cantidadcomprado = Number((e.target as HTMLInputElement).value);\r\n                        itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n                    });\r\n                    (e.target as HTMLElement).dataset.event = \"eventInput\"; //se marca al input que ya tiene evento añadido\r\n                }\r\n            }\r\n\r\n            if((e.target as HTMLElement).classList.contains('mas'))itemCarrito.cantidadcomprado++;\r\n            \r\n            //////// INPUT CANTIDAD DE LA TABLA DE ITEMS DE COMPRA, SE ACTUALIZA CADA VEZ QUE SE DE CLICK EN MENOS O MAS\r\n            (tablaCompras?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"] .inputcantidad`) as HTMLInputElement).value = itemCarrito?.cantidadcomprado+'';\r\n\r\n            /////// EVENTO AL INPUT VALOR DE COMPRA DE LA TABLA DE ITEMS DE COMPRA  ///////\r\n            if((e.target as HTMLElement).classList.contains('inputcompra')){\r\n                if((e.target as HTMLElement).dataset.event != \"eventInput\"){\r\n                    e.target?.addEventListener('input', (e:Event)=>{\r\n                        itemCarrito.valorcompra = Number((e.target as HTMLInputElement).value);\r\n                        itemCarrito.precio_compra = itemCarrito.valorcompra/itemCarrito.cantidad;\r\n                        resumen();\r\n                    });\r\n                    (e.target as HTMLElement).dataset.event = \"eventInput\"; //se marca al input que ya tiene evento añadido\r\n                }\r\n            }\r\n\r\n            if((e.target as HTMLElement).classList.contains('eliminarItem') || (e.target as HTMLElement).tagName == \"I\"){\r\n                carrito = carrito.filter(x=> {\r\n                    if(x.iditem==iditem){\r\n                        if(x.tipo==tipoitem){\r\n                            return false;\r\n                        }else{\r\n                            return true;\r\n                        }\r\n                    }else{\r\n                        return true;\r\n                    }\r\n                });\r\n                tablaCompras?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"]`)?.remove();\r\n                resumen();\r\n            }\r\n\r\n            itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n\r\n        btnvaciar?.addEventListener('click', ()=>{\r\n            if(carrito.length){\r\n              miDialogoVaciar.showModal();\r\n              document.addEventListener(\"click\", cerrarDialogoExterno);\r\n            }\r\n        });\r\n\r\n        document.querySelector('#formComprar')?.addEventListener('submit', e=>{\r\n            e.preventDefault();\r\n            miDialogoRegistrarcompra.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n  \r\n        async function procesarpedido(estado:string){\r\n            const datos = new FormData();\r\n            datos.append('idproveedor', proveedor.options[proveedor.selectedIndex].value);\r\n            //datos.append('idformapago', formapago.options[formapago.selectedIndex].value);\r\n            datos.append('idorigencaja', origenCaja.options[origenCaja.selectedIndex].value);\r\n            datos.append('idorigenbanco', origenBanco.options[origenBanco.selectedIndex].value);\r\n            datos.append('nombreproveedor', proveedor.options[proveedor.selectedIndex].textContent!);\r\n            //datos.append('formapago', formapago.options[formapago.selectedIndex].text);\r\n            datos.append('nfactura', nfactura.value);\r\n            datos.append('impuesto', impuesto.value);\r\n            datos.append('origenpago', origenPago.options[origenPago.selectedIndex].value); //0 = si el origen viene de la caja,  1 = banco\r\n            datos.append('nombreorigenpago', origenPago.options[origenPago.selectedIndex].textContent+''); //caja o banco\r\n            datos.append('nombreorigencaja', origenCaja.options[origenCaja.selectedIndex].textContent+'');\r\n            datos.append('nombreorigenbanco', origenBanco.options[origenBanco.selectedIndex].value?origenBanco.options[origenBanco.selectedIndex].textContent+'':'');\r\n            datos.append('cantidaditems', carrito.reduce((total, item)=>item.cantidad+total, 0)+'');\r\n            datos.append('observacion', observacion.value);\r\n            datos.append('estado', estado);\r\n            datos.append('subtotal', carrito.reduce((total, item)=>item.valorcompra+total, 0)+'');\r\n            datos.append('valortotal', carrito.reduce((total, item)=>item.valorcompra+total, 0)+'');\r\n            datos.append('fechacompra', fecha.value);\r\n            datos.append('carrito', JSON.stringify(carrito));  ////arreglo de objetos de producto simple y subproducto\r\n            datos.append('subID', JSON.stringify(carrito.map(item=>{if(item.idsx){return item.idsx}}))); //envia solo los id de los subproductos\r\n            try {\r\n                const url = \"/admin/api/registrarCompra\";  //va al controlador ventascontrolador\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json();\r\n                if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                /////// reinciar campos de la compra\r\n                vaciarcompra();\r\n                (document.querySelector('#formComprar') as HTMLFormElement)?.reset();\r\n                }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        }\r\n\r\n        function validarValorCompra():boolean{\r\n            return carrito.some(item=>Number.isNaN(item.valorcompra)||item.valorcompra==0);\r\n        }\r\n\r\n        function resumen():void{\r\n            document.querySelector('#impuesto')!.textContent = '% '+impuesto.value;\r\n            document.querySelector('#total')!.textContent = '$ '+carrito.reduce((total, item)=>item.valorcompra+total, 0).toLocaleString()+'';\r\n        \r\n        }\r\n\r\n        function vaciarcompra():void\r\n        {\r\n            carrito.length = 0;\r\n            while(tablaCompras?.firstChild)tablaCompras.removeChild(tablaCompras?.firstChild);\r\n            document.querySelector('#impuesto')!.textContent = '% 0';\r\n            document.querySelector('#total')!.textContent = '$ 0';\r\n        }\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n            if (f === miDialogoVaciar || f === miDialogoRegistrarcompra || (f as HTMLInputElement).closest('.novaciar') || (f as HTMLInputElement).closest('.sivaciar') || (f as HTMLInputElement).closest('.nocomprar') || (f as HTMLInputElement).closest('.sicomprar')) {\r\n              miDialogoVaciar.close();\r\n              miDialogoRegistrarcompra.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              if((f as HTMLInputElement).closest('.sicomprar')){\r\n                if(!validarValorCompra()){\r\n                    procesarpedido('paga');\r\n                }else{\r\n                    msjalertToast('error', '¡Error!', 'Verifica el valor de compra de la lista de productos');\r\n                }\r\n              }\r\n              if((f as HTMLInputElement).closest('.sivaciar'))vaciarcompra();\r\n            }\r\n        }\r\n        \r\n    }\r\n\r\n})();","(()=>{\r\n    \r\n    if(document.querySelector('.ensamblaje')){\r\n        const listaSubproductos = document.querySelector('.listaSubproductos');\r\n        //const subproducto:HTMLSelectElement = document.querySelector('#subproducto')!;\r\n        const selectUnidadMedida = document.querySelector('#unidadmedida')! as HTMLSelectElement;\r\n        let amount = document.querySelector('#cantidad') as HTMLInputElement; //input cantidad\r\n\r\n        type conversionunidadesapi = {\r\n            id:string,\r\n            idsubproducto: string,\r\n            idunidadmedidabase: string,\r\n            idunidadmedidadestino: string,\r\n            nombreunidadbase: string,\r\n            nombreunidaddestino: string,\r\n            factorconversion: string,\r\n            //idservicios:{idempleado:string, idservicio:string}[]\r\n          };\r\n\r\n        let allConversionUnidades:conversionunidadesapi[] = [], factorC = 0;\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json(); \r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        \r\n        ($('#subproducto') as any).select2({\r\n            maximumSelectionLength: 1,\r\n        });\r\n\r\n\r\n        ////// EVENTO AL SUBPRODUCTO PARA CARGAR LAS UNIDADES DE MEDIDA EQUIVALENTES ////// \r\n        $(\"#subproducto\").on('change', (e)=>{\r\n            const idsub = (e.target as HTMLOptionElement).value;\r\n            const subund = allConversionUnidades.filter(x =>x.idsubproducto == idsub);\r\n            mostrarSelectUnidades(subund);\r\n        });\r\n\r\n        /////////// CARGAR LAS UNIDADES DE MEDIDA EN EL SELECT unidadmedida  ////////////\r\n        function mostrarSelectUnidades(subund:conversionunidadesapi[]):void{\r\n            while(selectUnidadMedida?.firstChild)selectUnidadMedida.removeChild(selectUnidadMedida?.firstChild);\r\n            subund.forEach(und =>{\r\n              const option = document.createElement('option');\r\n              option.textContent = und.nombreunidaddestino;\r\n              option.value = und.id;  //und.id  =  es el id de la tabla conversionunidades\r\n              //option.dataset.idunidadmedidabase = und.idunidadmedidabase;\r\n              //option.dataset.nombreunidadbase = und.nombreunidadbase;\r\n              selectUnidadMedida.appendChild(option);\r\n            });\r\n            calcularFactor();\r\n        }\r\n\r\n        ////////// EVENTO AL SELECT DE UNIDAD DE MEDIDA ///////////\r\n        selectUnidadMedida.addEventListener('change', calcularFactor);\r\n\r\n        (document.querySelector('#cantidad') as HTMLInputElement).addEventListener('input', (e:Event)=>{\r\n            calcularFactor();\r\n        });\r\n\r\n        function calcularFactor():void{\r\n            const idConversionUnidad:string|undefined = selectUnidadMedida.options[selectUnidadMedida.selectedIndex]?.value;\r\n            const reg = allConversionUnidades.find(x=>x.id == idConversionUnidad);\r\n            factorC = Number(reg?.factorconversion);\r\n        }\r\n\r\n        //////////////  EVENTO AL INPUT RENDIMIENTO ESTANDAR /////////////////\r\n        document.querySelector('#rendimientoestandar')?.addEventListener('input', (e:Event)=>{\r\n            const inputRendimiendoEstandar = (e.target as HTMLInputElement);\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('id', (document.querySelector('#idproducto') as HTMLInputElement).value);\r\n                datos.append('rendimientoestandar', inputRendimiendoEstandar.value);\r\n                try {\r\n                    const url = \"/admin/api/setrendimientoestandar\";\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        inputRendimiendoEstandar.style.color = \"#02db02\";\r\n                        inputRendimiendoEstandar.style.fontWeight = \"500\";\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        \r\n        });\r\n\r\n        ///////////////// EVENTO AL FORMULARIO ASOCIAR SUBPRODUCTO //////////////////\r\n        document.querySelector('#formAddSubproducto')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            const subproducto = $('#subproducto').find('option:selected');\r\n            const unidadmedida:string = $('#unidadmedida').find('option:selected').text();\r\n            let AmountSubpx:number = factorC*Number(amount.value);\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('id_producto', (document.querySelector('#idproducto') as HTMLInputElement).value);\r\n                datos.append('id_subproducto', $('#subproducto').val()as string);\r\n                datos.append('cantidadsubproducto', AmountSubpx.toString());\r\n                datos.append('costo', (Number(subproducto.data('costo'))*AmountSubpx)+'');\r\n                try {\r\n                    const url = \"/admin/api/ensamblar\";  //asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                      msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                        /////validar si es el mismo subproducto, y actualizar \r\n                        validarSubproducto($('#subproducto').val()as string, unidadmedida, subproducto.data('subproducto'));\r\n                        ////// reset form ///////\r\n                        ($('#subproducto') as any).val([]).trigger('change');\r\n                        //$(`#subproducto option[value=\"${$('#subproducto').val()}\"]`).remove();\r\n                        (document.querySelector('#formAddSubproducto') as HTMLFormElement)?.reset();\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();//cierre de async()\r\n        });\r\n\r\n\r\n        function validarSubproducto(idsubproducto:string, unidadmedida:string, subproducto:string){\r\n            const sub = document.querySelector(`.listaSubproductos div[id=\"${idsubproducto}\"]`);\r\n            if(sub){\r\n                sub.querySelector('strong')!.textContent = amount.value+' '+unidadmedida;\r\n            }else{\r\n                listaSubproductos?.insertAdjacentHTML('beforeend', `\r\n                <div id=\"${idsubproducto}\" class=\"mb-4 flex items-center justify-between p-4 text-blue-600 bg-blue-100 rounded-lg shadow-md shadow-blue-500/30\" role=\"alert\">\r\n                    <p class=\"m-0\"><strong>${amount.value} ${unidadmedida}</strong>.  ${subproducto}</p>\r\n                    <button type=\"button\"><span id=\"${idsubproducto}\" class=\"material-symbols-outlined\">cancel</span></button>\r\n                </div>`\r\n                );\r\n            }\r\n        }\r\n\r\n\r\n        listaSubproductos?.addEventListener('click', (e:Event)=>{\r\n            const btn = (e.target as HTMLSpanElement);\r\n            if(btn.tagName == \"SPAN\")desasociarSubproducto((document.querySelector('#idproducto') as HTMLInputElement).value, btn.id);\r\n        });\r\n\r\n\r\n        function desasociarSubproducto(idproducto:string, idsubproducto:string){\r\n            const sub = document.querySelector(`.listaSubproductos div[id=\"${idsubproducto}\"]`);\r\n            (async ()=>{\r\n                try {\r\n                  const url = \"/admin/api/desasociarsubproducto?idproducto=\"+idproducto+\"&idsubproducto=\"+idsubproducto; //llamado a la API REST para desasociar subproducto del producto principal\r\n                  const respuesta = await fetch(url); \r\n                  const resultado = await respuesta.json();\r\n                  if(resultado.exito !== undefined){\r\n                    sub?.remove();\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                  }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n\r\n\r\n    }\r\n\r\n})();","(():void=>{\r\n  if(document.querySelector('.gestionproveedores')){\r\n    const crearProveedor = document.querySelector('#crearProveedor') as HTMLButtonElement;\r\n    const miDialogoProveedor = document.querySelector('#miDialogoProveedor') as any;\r\n\r\n    let indiceFila=0, control=0, tablaProveedores:HTMLElement;\r\n\r\n    type proveedoresapi = {\r\n        id:string,\r\n        nit: string,\r\n        nombre: string,\r\n        telefono: string,\r\n        email: string,\r\n        direccion: string,\r\n        pais: string,\r\n        ciudad: string,\r\n        created_at: string\r\n      };\r\n  \r\n      let proveedores:proveedoresapi[]=[], unproveedor:proveedoresapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allproveedores\"; //llamado a la API REST y se trae todos los proveedores\r\n            const respuesta = await fetch(url); \r\n            proveedores = await respuesta.json(); \r\n            console.log(proveedores);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaProveedores = ($('#tablaProveedores') as any).DataTable(configdatatables);\r\n\r\n    crearProveedor.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalProveedor')!.textContent = \"Crear proveedor\";\r\n        (document.querySelector('#btnEditarCrearProveedor') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoProveedor.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaProveedores')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarProveedor\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarProveedor\"))editarProveedor(e);\r\n      if(target?.classList.contains(\"eliminarProveedor\")||target.parentElement?.classList.contains(\"eliminarProveedor\"))eliminarProveedor(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar proveedor  //////////////////////\r\n    function editarProveedor(e:Event){\r\n      let idproveedor = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idproveedor = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalProveedor')!.textContent = \"Actualizar proveedor\";\r\n      (document.querySelector('#btnEditarCrearProveedor') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unproveedor = proveedores.find(x => x.id==idproveedor); //me trae a la proveedor seleccionada\r\n      (document.querySelector('#nit')as HTMLInputElement).value = unproveedor?.nit!;\r\n      (document.querySelector('#nombreProveedor')as HTMLInputElement).value = unproveedor?.nombre!;\r\n      \r\n      indiceFila = (tablaProveedores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoProveedor.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar proveedor  //////////////////////\r\n    document.querySelector('#formCrearUpdateProveedor')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearProveedor\";\r\n      if(control)urlApi = \"actualizarProveedor\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaProveedores as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unproveedor?.id?unproveedor?.id:'');\r\n          datos.append('nit', $('#nit').val()as string);\r\n          datos.append('nombre', $('#nombreProveedor').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoProveedor.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de los proveedores ///\r\n                  proveedores = [...proveedores, resultado.proveedor];\r\n                  (tablaProveedores as any).row.add([\r\n                      (tablaProveedores as any).rows().count() + 1,\r\n                      resultado.proveedor.nit,\r\n                      resultado.proveedor.nombre,\r\n                      resultado.proveedor.created_at,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.proveedor.id}\" data-proveedor=\"${resultado.proveedor.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarProveedor\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarProveedor\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de proveedores ///\r\n                  proveedores.forEach(a=>{if(a.id == unproveedor?.id)a = Object.assign(a, resultado.proveedor[0]);});\r\n                  const datosActuales = (tablaProveedores as any).row(indiceFila+=info.start).data();\r\n                  /*NIT*/       datosActuales[1] = resultado.proveedor[0].nit;\r\n                  /*PROVEEDOR*/ datosActuales[2] = resultado.proveedor[0].nombre;\r\n                  (tablaProveedores as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaProveedores as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar proveedor  //////////////////////\r\n    function eliminarProveedor(e:Event){\r\n      let idproveedor = (e.target as HTMLElement).parentElement!.id, info = (tablaProveedores as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idproveedor = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaProveedores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el proveedor?',\r\n          text: \"el proveedor sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idproveedor);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarProveedor\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaProveedores as any).row(indiceFila).remove().draw(); \r\n                        (tablaProveedores as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoProveedor || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoProveedor.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateProveedor') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.productos')){\r\n    const crearProducto = document.querySelector('#crearProducto');\r\n    const btnUploadExcel = document.querySelector('#btnUploadExcel');\r\n    const miDialogoProducto = document.querySelector('#miDialogoProducto') as any;\r\n    const miDialogoImportarExcel = document.querySelector('#miDialogoImportarExcel') as any;\r\n    const btnXCerrarModalproducto = document.querySelector('#btnXCerrarModalproducto') as HTMLButtonElement;\r\n    const inputupImage = document.querySelector('#upImage') as HTMLInputElement;  //input para cargar el archivo imagen\r\n    const btncustomUpImage = document.querySelector('#customUpImage');\r\n    const imginputfile = document.querySelector('#imginputfile') as HTMLImageElement;  //img\r\n    const tipoproducto = document.querySelector('#tipoproducto') as HTMLSelectElement;\r\n    const contentnuevosprecios = document.querySelector('#contentnuevosprecios') as HTMLElement;\r\n    let indiceFila=0, control=0, tablaProductos:HTMLElement;\r\n    \r\n\r\n    type productsapi = {\r\n      id:string,\r\n      idcategoria: string,\r\n      idunidadmedida: string,\r\n      nombre: string,\r\n      foto: string,\r\n      impuesto: string,\r\n      marca: string,\r\n      tipoproducto: string,\r\n      tipoproduccion: string,\r\n      sku: string,\r\n      unidadmedida: string;\r\n      descripcion: string,\r\n      peso: string,\r\n      medidas: string,\r\n      color: string,\r\n      funcion: string,\r\n      uso:string,\r\n      fabricante: string,\r\n      garantia: string,\r\n      stock: string,\r\n      stockminimo: string,\r\n      categoria: string,\r\n      precio_compra: string,\r\n      precio_venta: string,\r\n      fecha_ingreso: string,\r\n      preciosadicionales: {id:string, idproductoid:string, precio:string, estado:string, created_at:string}[]\r\n      //idservicios:{idempleado:string, idservicio:string}[]\r\n    };\r\n\r\n    let products:productsapi[]=[], unproducto:productsapi;\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/allproducts\"; //llamado a la API REST y se trae todos los productos\r\n          const respuesta = await fetch(url); \r\n          products = await respuesta.json(); \r\n          console.log(products);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n    const divAlert = document.querySelector('.divmsjalerta0') as HTMLElement;\r\n    if(divAlert)borrarMsjAlert(divAlert);\r\n\r\n    ///////// Habilita el select precio de compra, y deshabilita el select de tipo de produccion si es producto simple, si es compuesto lo deshabilita y habilita el select de tipo de produccion\r\n    tipoproducto?.addEventListener('change', (e:Event)=>{\r\n      const targetDom = e.target as HTMLSelectElement;\r\n      const preciocompra = document.querySelector('.preciocompra') as HTMLElement;\r\n      const stock = document.querySelector('.stock') as HTMLElement;\r\n      const habtipoproduccion = document.querySelector('.habtipoproduccion') as HTMLElement;\r\n      if(targetDom.value == '0'){  //  0 = simple\r\n        stock.style.display = 'flex';\r\n        preciocompra.style.display = 'flex';\r\n        habtipoproduccion.style.display = \"none\";\r\n        document.querySelector('#preciocompra')?.setAttribute(\"required\", \"\");\r\n        document.querySelector('#tipoproduccion')?.removeAttribute(\"required\");\r\n      }\r\n      else{\r\n        stock.style.display = 'none';\r\n        preciocompra.style.display = 'none';\r\n        habtipoproduccion.style.display = \"flex\";\r\n        document.querySelector('#preciocompra')?.removeAttribute(\"required\");\r\n        document.querySelector('#tipoproduccion')?.setAttribute(\"required\", \"\");\r\n      }\r\n    });\r\n\r\n\r\n    btnXCerrarModalproducto.addEventListener('click', (e)=>{\r\n        miDialogoProducto.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    //AÑADOR INPUTS PARA PRECIOS PERSONALIZADOS\r\n    const btnAddNewPrice = document.querySelector('#btnAddNewPrice') as HTMLButtonElement;\r\n    if(btnAddNewPrice){\r\n        let i=1;\r\n        btnAddNewPrice.addEventListener('click', (e:Event)=>{\r\n          let clone = (e.target as HTMLButtonElement).previousElementSibling?.cloneNode(true) as HTMLInputElement;  \r\n          //console.log(clone.children[1].name = `niveles[nombrenivel${++i}]`);\r\n          clone.removeAttribute('id');\r\n          clone.required = false;\r\n          clone.value='';\r\n          clone.name = `nuevosprecios[]`;\r\n          clone.classList.add('nuevosprecios');\r\n          contentnuevosprecios.appendChild(clone);\r\n          console.log(clone);\r\n        });\r\n    }\r\n\r\n\r\n    btnUploadExcel?.addEventListener('click', ()=>{\r\n      miDialogoImportarExcel.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaProductos = ($('#tablaProductos') as any).DataTable(configdatatables);\r\n\r\n    //btn para crear producto\r\n    crearProducto?.addEventListener('click', (e):void=>{\r\n      control = 0;\r\n      limpiarformdialog();\r\n      while(contentnuevosprecios.firstChild)contentnuevosprecios.removeChild(contentnuevosprecios.firstChild);\r\n      document.querySelector('#modalProducto')!.textContent = \"Crear producto\";\r\n      (document.querySelector('#btnEditarCrearProducto') as HTMLInputElement).value = \"Crear\";\r\n      (document.querySelector('.stock')as HTMLInputElement).style.display = \"block\";\r\n      (document.querySelector('.preciocompra')as HTMLInputElement).style.display = \"block\";\r\n      miDialogoProducto.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    //evento a la tabla\r\n    document.querySelector('#tablaProductos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarProductos\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarProductos\"))editarProductos(e);\r\n      if(target?.classList.contains(\"bloquearProductos\")||target.parentElement?.classList.contains(\"bloquearProductos\"))bloquearProductos(e);\r\n      if(target?.classList.contains(\"eliminarProductos\")||target.parentElement?.classList.contains(\"eliminarProductos\"))eliminarProductos(e);\r\n    });\r\n\r\n    function editarProductos(e:Event){\r\n      let idproducto = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idproducto = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      control = 1;\r\n      document.querySelector('#modalProducto')!.textContent = \"Actualizar producto\";\r\n      (document.querySelector('#btnEditarCrearProducto') as HTMLInputElement)!.value = \"Actualizar\";\r\n      unproducto = products.find(x=>x.id === idproducto)!; //obtengo el producto.\r\n      $('#categoria').val(unproducto?.idcategoria??'');\r\n      (document.querySelector('#nombre')as HTMLInputElement).value = unproducto?.nombre!;\r\n      $('#tipoproducto').val(unproducto?.tipoproducto??'0');  //0 = simple,  1 = compuesto\r\n      $('#idunidadmedida').val(unproducto?.idunidadmedida??'1');\r\n      (document.querySelector('.stock')as HTMLInputElement).style.display = \"block\";\r\n      (document.querySelector('.preciocompra')as HTMLInputElement).style.display = \"block\";\r\n      (document.querySelector('.habtipoproduccion') as HTMLElement).style.display = \"none\";\r\n      if(unproducto?.tipoproducto == '1'){\r\n        (document.querySelector('.stock')as HTMLInputElement).style.display = \"none\";\r\n        (document.querySelector('.preciocompra')as HTMLInputElement).style.display = \"none\";\r\n        (document.querySelector('.habtipoproduccion') as HTMLElement).style.display = \"block\";\r\n        $('#tipoproduccion').val(unproducto.tipoproduccion);\r\n      }\r\n      (document.querySelector('#stock')as HTMLInputElement).value = unproducto?.stock??'';\r\n      (document.querySelector('#preciocompra')as HTMLInputElement).value = unproducto?.precio_compra??'';\r\n      (document.querySelector('#precioventa')as HTMLInputElement).value = unproducto?.precio_venta??'';\r\n      (document.querySelector('#precioventa')as HTMLInputElement).dataset.idproductoid = unproducto.id;\r\n      imprimirpreciosadicionales(unproducto.preciosadicionales);\r\n      (document.querySelector('#sku')as HTMLInputElement).value = unproducto?.sku??'';\r\n      (document.querySelector('#impuesto')as HTMLInputElement).value = unproducto?.impuesto??'';\r\n      (document.querySelector('#stockminimo')as HTMLInputElement).value = unproducto?.stockminimo??'';\r\n      imginputfile.src = \"/build/img/\"+unproducto?.foto;\r\n      indiceFila = (tablaProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoProducto.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function imprimirpreciosadicionales(preciosadicionales:{id:string, idproductoid:string, precio:string, estado:string, created_at:string}[]){\r\n      while(contentnuevosprecios.firstChild)contentnuevosprecios.removeChild(contentnuevosprecios.firstChild);\r\n      preciosadicionales.forEach(z =>{\r\n        contentnuevosprecios.insertAdjacentHTML('afterbegin', `<input \r\n          data-id=\"${z.id}\"\r\n          class=\"nuevosprecios bg-gray-50 border border-gray-300 text-gray-900 rounded-lg focus:border-indigo-600 block w-full p-2.5 dark:bg-gray-600 dark:border-gray-500 dark:placeholder-gray-400 dark:text-white h-14 text-xl focus:outline-none focus:ring-1\"\r\n          type=\"number\" \r\n          min=\"0\" \r\n          step=\"0.01\"\r\n          placeholder=\"Precio de venta incluido el impuesto\" \r\n          name=\"nuevosprecios[]\" \r\n          value=\"${z.precio}\" \r\n          >`);\r\n      });\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar producto  //////////////////////\r\n    document.querySelector('#formCrearUpdateProducto')?.addEventListener('submit', e=>{\r\n\r\n      let w = document.querySelectorAll<HTMLInputElement>('.nuevosprecios');\r\n      //console.log(Array.from(w).map(input=>({id: input.dataset.id, precio: parseFloat(input.value) })).filter(x=>x.precio>0));\r\n      if(control){\r\n        e.preventDefault();\r\n        var imgFile:(string|File), info = (tablaProductos as any).page.info();\r\n        imgFile=unproducto.foto;\r\n        if(!imginputfile.src.includes(unproducto.foto)){ //se lee la etiqueta img para cambio de imagen\r\n          imgFile = ((e.target as HTMLFormElement).elements.namedItem(\"upImage\") as HTMLInputElement).files?.[0]!; //obtengo el archivo\r\n          if(imgFile){\r\n            if(imgFile.type!==\"image/png\"&&imgFile.type!==\"image/jpeg\"){\r\n              msjAlert('error', 'No es un formato valido para la foto', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n              return;\r\n            }\r\n            if(imgFile.size>31000000){ //si es mayor a 31MB\r\n              msjAlert('error', 'La imagen no debe superar los 500KB', document.querySelector('#divmsjalerta1')!);\r\n              return;\r\n            }\r\n          }\r\n        }\r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unproducto!.id);\r\n          datos.append('idcategoria', $('#categoria').val()as string);\r\n          datos.append('nombre', $('#nombre').val()as string);\r\n          datos.append('foto', imgFile); //en el backend no se lee con $_POST, se lee con $_FILES\r\n          datos.append('tipoproducto', $('#tipoproducto').val()as string);  //0=simple o 1=compuesto\r\n          datos.append('idunidadmedida', $('#idunidadmedida').val()as string);\r\n          datos.append('unidadmedida', $('#idunidadmedida option:selected').text());\r\n          datos.append('stock', $('#stock').val()as string);\r\n          datos.append('precio_compra', $('#preciocompra').val()as string);\r\n          datos.append('precio_venta', $('#precioventa').val()as string);\r\n          datos.append('nuevosprecios', JSON.stringify(Array.from(w).map(input=>({id: input.dataset.id, idproductoid: input.dataset.idproductoid, precio: parseFloat(input.value), estado:1 })).filter(x=>x.precio>=0)));\r\n          datos.append('idprecionsadicionales', JSON.stringify(Array.from(w).filter(input => input.dataset.id && parseFloat(input.value) > 0).map( input=>input.dataset.id ))); //solo los ids de la tabla precios_personalizados\r\n          datos.append('sku', $('#sku').val()as string);\r\n          datos.append('tipoproduccion', ($('#tipoproduccion').val()as string)==null?'0':($('#tipoproduccion').val()as string));\r\n          datos.append('impuesto', $('#impuesto').val()as string);\r\n          datos.append('stockminimo', $('#stockminimo').val()as string);\r\n          try {\r\n              const url = \"/admin/api/actualizarproducto\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json(); \r\n              console.log(resultado); \r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                /// actualizar el arregle del producto ///\r\n                products.forEach(a=>{if(a.id == unproducto.id)a = Object.assign(a, resultado.producto[0]);});\r\n                ///////// cambiar la fila completa, su contenido //////////\r\n                const datosActuales = (tablaProductos as any).row(indiceFila).data();\r\n                /*img*/datosActuales[1] = `<div class=\"text-center\"><img class=\"inline\" style=\"width: 50px;\" src=\"/build/img/${resultado.producto[0].foto}\" alt=\"\"></div>`;\r\n                /*NOMBRE*/datosActuales[2] ='<div class=\"w-80 whitespace-normal\">'+$('#nombre').val()+'</div>';\r\n                /*CATEGORIA*/datosActuales[3] = $('#categoria option:selected').text();\r\n                /*MARCA*/datosActuales[4] = '';\r\n                /*CODIGO*/datosActuales[5] = $('#sku').val();\r\n                /*PRECIOVENTA*/datosActuales[6] = $('#precioventa').val();\r\n                \r\n                (tablaProductos as any).row(indiceFila).data(datosActuales).draw();\r\n                (tablaProductos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n              miDialogoProducto.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n      } //fin if(control)\r\n    });\r\n\r\n\r\n    function bloquearProductos(e:Event){\r\n      let reg = (e.target as HTMLElement).parentElement, info = (tablaProductos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'SPAN')reg = (e.target as HTMLElement).parentElement!.parentElement;\r\n      indiceFila = (tablaProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      (async ()=>{\r\n\r\n          const datos = new FormData();\r\n          datos.append('id', reg!.id);\r\n          try {\r\n              const url = \"/admin/api/cambiarestadoproducto\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                \r\n                const s1 = `<div class=\"acciones-btns my-[0.7rem]\" id=\"${reg!.id}\">\r\n                              ${resultado.tipoproducto[0] == 1?`<a class=\"btn-xs btn-blue\" title=\"Agregar Materia Prima\" href=\"/admin/almacen/componer?id=${reg!.id}\"><i class=\"fa-solid fa-subscript text-[17px] leading-none\"></i></a>`:''}\r\n                              <button class=\"btn-xs btn-lima\" title=\"Más opciones\"><i class=\"fa-solid fa-circle-plus text-[17px] leading-none\"></i></button>\r\n                              <button class=\"btn-xs btn-turquoise editarProductos\" title=\"Actualizar Producto\"><i class=\"fa-solid fa-pen-to-square text-[17px] leading-none\"></i></button>\r\n                              <button class=\"btn-xs ${resultado.estado[0]==1?'btn-light':'btn-orange'} bloquearProductos\" title=\"Bloquear Producto\"><span class=\"material-symbols-outlined text-[18px] leading-none\">hide_source</span></button>\r\n                              <button class=\"btn-xs btn-red eliminarProductos\" title=\"Eliminar Producto\"><i class=\"fa-solid fa-trash-can text-[17px] leading-none\"></i></button>\r\n                            </div>`;\r\n                            \r\n                (tablaProductos as any).cell((tablaProductos as any).row(indiceFila), 7).data(s1).draw(); //se modifica solo la columna con la fila correspondiente, y destruye la que habai antes\r\n                (tablaProductos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              }else{\r\n                  Swal.fire(resultado.error[0], '', 'error')\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n      })();//cierre de async()\r\n    }\r\n\r\n    function eliminarProductos(e:Event){\r\n      let idproducto = (e.target as HTMLElement).parentElement!.id, info = (tablaProductos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idproducto = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el prducto?',\r\n          text: \"El prducto sera eliminado definitivamente de todas las SEDES.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idproducto);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarProducto\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaProductos as any).row(indiceFila).remove().draw(); \r\n                        (tablaProductos as any).page(info.page).draw('page');\r\n                        Swal.fire(resultado.exito[0], '', 'success') \r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    //////////////////// Cargar imagen como preview  //////////////////////\r\n    btncustomUpImage?.addEventListener('click', ()=>inputupImage?.click());\r\n    inputupImage?.addEventListener('change', function(){\r\n      const file = this.files?.[0];\r\n      if(file){\r\n        const reader = new FileReader();\r\n        reader.onload = function(){\r\n          const resrult = reader.result;\r\n          if(typeof resrult == \"string\")imginputfile.src = resrult;\r\n        } \r\n        reader.readAsDataURL(file);\r\n      }\r\n    });\r\n\r\n    function limpiarformdialog():void{\r\n      (document.querySelector('#formCrearUpdateProducto') as HTMLFormElement)?.reset();\r\n      imginputfile.src = '';\r\n    }\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoImportarExcel || (event.target as HTMLInputElement).value === 'salir' || (event.target as HTMLInputElement).value === 'Cancelar') {\r\n        miDialogoProducto.close();\r\n        miDialogoImportarExcel.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.subproductos')){\r\n      const crearSubProducto = document.querySelector('#crearSubProducto');\r\n      const miDialogoSubProducto = document.querySelector('#miDialogoSubProducto') as any;\r\n      let indiceFila=0, control=0, tablaSubProductos:HTMLElement;\r\n      \r\n      type subproductsapi = {\r\n        id:string,\r\n        id_unidadmedida: string,\r\n        unidadmedida: string,\r\n        nombre: string,\r\n        sku: string,\r\n        proveedor: string,\r\n        descripcion: string,\r\n        medidas: string,\r\n        color: string,\r\n        uso:string,\r\n        stock: string,\r\n        stockminimo: string,\r\n        precio_compra: string,\r\n        fecha_ingreso: string,\r\n      };\r\n  \r\n      let subproducts:subproductsapi[]=[], unsubproducto:subproductsapi;\r\n  \r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allsubproducts\"; //llamado a la API REST\r\n            const respuesta = await fetch(url); \r\n            subproducts = await respuesta.json(); \r\n            console.log(subproducts);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n  \r\n      //////////////////  TABLA //////////////////////\r\n      tablaSubProductos = ($('#tablaSubProductos') as any).DataTable(configdatatables);\r\n  \r\n      crearSubProducto?.addEventListener('click', (e):void=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalSubProducto')!.textContent = \"Crear sub producto\";\r\n        (document.querySelector('#btnEditarCrearSubProducto') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoSubProducto.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n  \r\n      ///////////// EVENTOS A LA TABLA SUBPRODUCTOS /////////////\r\n      document.querySelector('#tablaSubProductos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n        const target = e.target as HTMLElement;\r\n        if(target?.classList.contains(\"editarSubProductos\")||target.parentElement?.classList.contains(\"editarSubProductos\"))editarSubProductos(e);\r\n        if(target?.classList.contains(\"eliminarSubProductos\")||target.parentElement?.classList.contains(\"eliminarSubProductos\"))eliminarSubProductos(e);\r\n      });\r\n  \r\n      function editarSubProductos(e:Event){\r\n        let idsubproducto = (e.target as HTMLElement).parentElement?.id!;\r\n        if((e.target as HTMLElement)?.tagName === 'I')idsubproducto = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n        control = 1;\r\n        document.querySelector('#modalSubProducto')!.textContent = \"Actualizar producto\";\r\n        (document.querySelector('#btnEditarCrearSubProducto') as HTMLInputElement)!.value = \"Actualizar\";\r\n        unsubproducto = subproducts.find(x=>x.id === idsubproducto)!;\r\n        $('#unidadmedida').val(unsubproducto?.id_unidadmedida??'');\r\n        (document.querySelector('#nombre')as HTMLInputElement).value = unsubproducto?.nombre!;\r\n        (document.querySelector('#sku')as HTMLInputElement).value = unsubproducto?.sku!;\r\n        (document.querySelector('#preciocompra')as HTMLInputElement).value = unsubproducto?.precio_compra??'';\r\n        (document.querySelector('#stockminimo')as HTMLInputElement).value = unsubproducto?.stockminimo??'';\r\n        \r\n        indiceFila = (tablaSubProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n        miDialogoSubProducto.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n  \r\n      ////////////////////  Actualizar/Editar producto  //////////////////////\r\n      document.querySelector('#formCrearUpdateSubProducto')?.addEventListener('submit', e=>{\r\n        if(control){\r\n          e.preventDefault();\r\n          var info = (tablaSubProductos as any).page.info();\r\n          \r\n          (async ()=>{ \r\n            const datos = new FormData();\r\n            datos.append('id', unsubproducto!.id);\r\n            datos.append('id_unidadmedida', $('#unidadmedida').val()as string);\r\n            datos.append('unidadmedida', $('#unidadmedida').find('option:selected').text());\r\n            datos.append('nombre', $('#nombre').val()as string);\r\n            datos.append('sku', $('#sku').val()as string);\r\n            datos.append('precio_compra', $('#preciocompra').val()as string);\r\n             datos.append('stockminimo', $('#stockminimo').val()as string);\r\n            try {\r\n                const url = \"/admin/api/actualizarsubproducto\";\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json(); \r\n                console.log(resultado); \r\n                if(resultado.exito !== undefined){\r\n                  msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  /// actualizar el arregle del subproducto ///\r\n                  subproducts.forEach(a=>{if(a.id == unsubproducto.id)a = Object.assign(a, resultado.subproducto[0]);});\r\n                  ///////// cambiar la fila completa, su contenido //////////\r\n                  const datosActuales = (tablaSubProductos as any).row(indiceFila+=info.start).data();\r\n                  /*NOMBRE*/datosActuales[1] ='<div class=\"w-80 whitespace-normal\">'+$('#nombre').val()+'</div>';\r\n                  /*proveedor*/datosActuales[2] = '';\r\n                  /*SKU*/datosActuales[3] = $('#sku').val();\r\n                  /*UNIDADMEDIDA*/datosActuales[4] = $('#unidadmedida option:selected').text();\r\n                  /*PRECIOCOMPRA*/datosActuales[5] = '$'+Number($('#preciocompra').val())?.toLocaleString();\r\n                  (tablaSubProductos as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaSubProductos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }else{\r\n                  msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n                document.addEventListener(\"click\", cerrarDialogoExterno);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n          })();//cierre de async()\r\n        } //fin if(control)\r\n      });\r\n  \r\n      function eliminarSubProductos(e:Event){\r\n        let idsubproducto = (e.target as HTMLElement).parentElement!.id, info = (tablaSubProductos as any).page.info();\r\n        if((e.target as HTMLElement).tagName === 'I')idsubproducto = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n        indiceFila = (tablaSubProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n        Swal.fire({\r\n            customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n            icon: 'question',\r\n            title: 'Desea eliminar el sub prducto?',\r\n            text: \"El sub prducto sera eliminado definitivamente.\",\r\n            showCancelButton: true,\r\n            confirmButtonText: 'Si',\r\n            cancelButtonText: 'No',\r\n        }).then((result:any) => {\r\n            if (result.isConfirmed) {\r\n                (async ()=>{ \r\n                    const datos = new FormData();\r\n                    datos.append('id', idsubproducto);\r\n                    try {\r\n                        const url = \"/admin/api/eliminarSubProducto\";\r\n                        const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                        const resultado = await respuesta.json();  \r\n                        if(resultado.exito !== undefined){\r\n                          (tablaSubProductos as any).row(indiceFila).remove().draw(); \r\n                          (tablaSubProductos as any).page(info.page).draw('page');\r\n                          Swal.fire(resultado.exito[0], '', 'success') \r\n                        }else{\r\n                            Swal.fire(resultado.error[0], '', 'error')\r\n                        }\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();//cierre de async()\r\n            }\r\n        });\r\n      }\r\n\r\n  \r\n      function limpiarformdialog(){\r\n        (document.querySelector('#formCrearUpdateSubProducto') as HTMLFormElement)?.reset();\r\n        (document.querySelector('#formCrearUpdateSubProducto') as HTMLFormElement).action = \"/admin/almacen/crear_subproducto\";\r\n      }\r\n      function cerrarDialogoExterno(event:Event) {\r\n        if (event.target === miDialogoSubProducto || (event.target as HTMLInputElement).value === 'salir' || (event.target as HTMLInputElement).value === 'Actualizar') {\r\n            miDialogoSubProducto.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n    }\r\n  \r\n  })();","(()=>{\r\n\r\n    if(document.querySelector('.unidadesmedida')){\r\n        const btnCrearUnidadMedida = document.querySelector('#btnCrearUnidadMedida');\r\n        const miDialogoUnidadMedida = document.querySelector('#miDialogoUnidadMedida') as any;\r\n        let tablaUnidadesMedida:HTMLElement;\r\n\r\n        tablaUnidadesMedida = ($('#tablaUnidadesMedida') as any).DataTable(configdatatables);\r\n\r\n        ///////////////BTN PARA CREAR UNIDAD DE MEDIDA////////////////\r\n        btnCrearUnidadMedida?.addEventListener('click', (e):void=>{\r\n            limpiarformdialog();\r\n            document.querySelector('#modalUnidadMedida')!.textContent = \"Crear unidad de medida\";\r\n            (document.querySelector('#btnEditarCrearUnidadMedida') as HTMLInputElement).value = \"Crear\";\r\n            miDialogoUnidadMedida.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n        document.querySelector('#tablaUnidadesMedida')?.addEventListener('click', (e:Event)=>{\r\n            var btn = e.target as HTMLElement;\r\n            if(btn?.classList.contains('editarUnidadMedida')||btn.parentElement?.classList.contains(\"editarUnidadMedida\"))editarUnidadMedida(e);\r\n            if(btn?.classList.contains('eliminarUnidadMedida')||btn.parentElement?.classList.contains(\"eliminarUnidadMedida\"))eliminarUnidadMedida(e);   \r\n        });\r\n\r\n\r\n        ///////////////EDITAR UNIDAD DE MEDIDA////////////////\r\n        function editarUnidadMedida(e:Event){\r\n            let idunidadmedida = (e.target as HTMLElement).parentElement?.id!;\r\n            if((e.target as HTMLElement)?.tagName === 'I')idunidadmedida = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n            (document.querySelector('#formCrearUpdateUnidad') as HTMLFormElement).action = \"/admin/almacen/editarunidademedida\";\r\n            document.querySelector('#modalUnidadMedida')!.textContent = \"Actualizar unidad de medida\";\r\n            (document.querySelector('#btnEditarCrearUnidadMedida') as HTMLInputElement)!.value = \"Actualizar\";\r\n            (document.querySelector('#idunidadmedida') as HTMLInputElement).value = idunidadmedida;\r\n            (document.querySelector('#unidad') as HTMLInputElement).value = ((e.target as HTMLElement).closest('.acciones-btns') as HTMLElement)?.dataset.unidadmedida!; \r\n            miDialogoUnidadMedida.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n\r\n        function eliminarUnidadMedida(e:Event):void{\r\n            let form = (e.target as HTMLElement).parentElement!;\r\n            if((e.target as HTMLElement).tagName === 'I')form = form.parentElement!;\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar la unidad de medida?',\r\n                text: \"La unidad de medida sera eliminado definitivamente.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed)(form as HTMLFormElement).submit();\r\n            });\r\n        }\r\n\r\n        /*document.querySelector('.eliminarUnidadMedida')?.addEventListener('submit', (e:Event)=>{\r\n            console.log(55);\r\n            e.preventDefault();\r\n        });*/\r\n\r\n        /*function eliminarUnidadMedida(e:Event):void{\r\n            let idunidadmedida = (e.target as HTMLElement).parentElement?.id!;\r\n            if((e.target as HTMLElement)?.tagName === 'I')idunidadmedida = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n            console.log(idunidadmedida);\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar la unidad de medida?',\r\n                text: \"La unidad de medida sera eliminado definitivamente.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {*/\r\n                    /*(async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('id', idproducto);\r\n                        try {\r\n                            const url = \"/admin/api/eliminarProducto\";\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                              (tablaProductos as any).row(indiceFila+info.start).remove().draw(); \r\n                              (tablaProductos as any).page(info.page).draw('page');\r\n                              Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();*///cierre de async()\r\n                /*}\r\n            });\r\n        }*/\r\n        \r\n        function limpiarformdialog(){\r\n            (document.querySelector('#formCrearUpdateUnidad') as HTMLFormElement)?.reset();\r\n            (document.querySelector('#formCrearUpdateUnidad') as HTMLFormElement).action = \"/admin/almacen/crear_unidadmedida\";\r\n        }\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n        if (f === miDialogoUnidadMedida || (f as HTMLInputElement).value === 'Salir' || (f as HTMLInputElement).value === 'Actualizar') {\r\n            miDialogoUnidadMedida.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n        }\r\n    }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.adicionarProducto')){\r\n        \r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const btnUpdateCreditoSeparado = document.querySelector('#btnUpdateCreditoSeparado') as HTMLButtonElement;\r\n\r\n        interface i_itemDetalle {\r\n            id:string, //id del registro de la tabla productosseparados\r\n            idcredito:string,\r\n            fk_producto: string,\r\n            idproducto?:string,\r\n            idunidadmedida:string,\r\n            tipoproducto:string,\r\n            tipoproduccion:string,\r\n            rendimientoestandar?:string,\r\n            factor?:number,\r\n            nombreproducto:string,\r\n            unidadmedida:string,\r\n            preciopersonalizado:string,\r\n            sku:string,\r\n            stockminimo?:string,\r\n\r\n            capital?:number,            //DATOS DEL CREDITO\r\n            abonoinicial?:number,      //abono inicial en el credito\r\n            saldopendiente?:number,\r\n            cantidadcuotas?:number,\r\n            interes?:string,           // 1 = si interes en el credito, 0 = no interes en el credito\r\n            interestotal?:number,      //interes total dlecredito en porcentaje\r\n            valorinterestotal?:number, //valor del interes total de credito\r\n            montototal?:number,\r\n            descuentocredito?:number,  //descuneto general en el credito\r\n            \r\n            costo:number,\r\n            valorunidad:number,\r\n            descuento:number,  //se calcula para productos nuevos agregados\r\n            cantidad:number,   //se calcula para productos nuevos agregados\r\n            base:number,       //se calcula para productos nuevos agregados\r\n            impuesto:string,\r\n            valorimp:number,   //se calcula para productos nuevos agregados\r\n            subtotal:number,   //se calcula para productos nuevos agregados\r\n            total:number,      //se calcula para productos nuevos agregados\r\n        }\r\n\r\n        interface i_allProducts {\r\n            id:string,  //id del producto\r\n            idunidadmedida:string, \r\n            nombre:string,\r\n            impuesto:string,\r\n            tipoproducto:string, \r\n            tipoproduccion:string, \r\n            sku:string, \r\n            unidadmedida:string, \r\n            preciopersonalizado:string,\r\n            rendimientoestandar:string, \r\n            stockminimo:string,\r\n            precio_compra:number,\r\n            precio_venta:number\r\n            habilitarventa:string, \r\n            visible:string,\r\n        }\r\n\r\n        interface Item {\r\n            id_impuesto: number,\r\n            facturaid: number,\r\n            basegravable: number,\r\n            valorimpuesto: number\r\n            }\r\n\r\n\r\n        let factimpuestos:Item[] = [];\r\n        let carrito:i_itemDetalle[]=[];\r\n        let allproducts:i_allProducts[] = [];\r\n        let filteredData: {id:string, text:string, tipo:string, tipoproducto:string, tipoproduccion:string, sku:string, unidadmedida:string}[];   //tipoproducto = 0 es producto simple,  1 = compuesto,  si no viene es subproducto, tipo=0 es producto(simple o compuesto), tipo=1 es subproducto\r\n        const valorTotal = {subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, total: 0}; //datos global de la venta\r\n        const dataCredit = {capital:0, abonoinicial:0, saldopendiente:0, cantidadcuotas:0, interes:'0', interestotal:0, valorinterestotal:0, montototal:0, descuentocredito: 0};\r\n\r\n        const constImp: {[key:string]: number} = {};\r\n        constImp['excluido'] = 0;\r\n        constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n        constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n        constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n        constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n        constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allproducts\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y compuestos\r\n                const respuesta = await fetch(url);\r\n                const resultado:i_allProducts[] = await respuesta.json();\r\n                filteredData = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1').map(item => ({ id: item.id, text: item.nombre, tipo:item.tipoproducto??'1', tipoproducto: item.tipoproducto, tipoproduccion: item.tipoproduccion, sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2();\r\n                allproducts = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1');\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n        \r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const idcreditoURL = parametrosURL.get('id');\r\n        if(idcreditoURL!=null && /^\\d+$/.test(idcreditoURL) && Number(idcreditoURL) >= 1){\r\n            (async ()=>{\r\n                try {\r\n                    const url = \"/admin/api/detalleProductosCredito?id=\"+idcreditoURL; //llamado a la API REST y trae el detalle de los productos de credito/separado\r\n                    const respuesta = await fetch(url); \r\n                    const resultado:i_itemDetalle[] = await respuesta.json();\r\n                    console.log(resultado);\r\n                    carrito = resultado.map(item =>{\r\n                        \r\n                        return {\r\n                            id: item.id,\r\n                            idcredito: item.idcredito,\r\n                            fk_producto: item.idproducto!,\r\n                            idproducto:item.idproducto,\r\n                            idunidadmedida: item.idunidadmedida,\r\n                            tipoproducto: item.tipoproducto, \r\n                            tipoproduccion: item.tipoproduccion,\r\n                            rendimientoestandar: item.rendimientoestandar,\r\n                            nombreproducto: item.nombreproducto, \r\n                            unidadmedida: item.unidadmedida,\r\n                            preciopersonalizado: item.preciopersonalizado,\r\n                            sku: item.sku,\r\n                            costo: Number(item.costo),\r\n                            valorunidad: Number(item.valorunidad),\r\n                            descuento: Number(item.descuento), //descuento del producto\r\n                            cantidad: Number(item.cantidad),\r\n                            base: Number(item.base),\r\n                            impuesto: item.impuesto,\r\n                            valorimp: Number(item.valorimp),\r\n                            subtotal: Number(item.subtotal),\r\n                            total: Number(item.total),\r\n                            factor: 1\r\n                        }\r\n                    });\r\n                    carrito.forEach(c =>printItemTable(c.fk_producto, c.unidadmedida, c.cantidad, c.nombreproducto, c.valorunidad, c.total));\r\n                    //obtener datos del credito\r\n\r\n                    dataCredit.capital = Number(resultado[0].capital);\r\n                    dataCredit.abonoinicial = Number(resultado[0].abonoinicial!);\r\n                    dataCredit.saldopendiente = Number(resultado[0].saldopendiente);\r\n                    dataCredit.cantidadcuotas = Number(resultado[0].cantidadcuotas);\r\n                    dataCredit.interes = resultado[0].interes!;\r\n                    dataCredit.interestotal = resultado[0].interestotal!;\r\n                    dataCredit.valorinterestotal = Number(resultado[0].valorinterestotal!);\r\n                    dataCredit.montototal = Number(resultado[0].montototal);\r\n                    dataCredit.descuentocredito = Number(resultado[0].descuentocredito!);\r\n                    \r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n        \r\n        \r\n\r\n        function activarselect2(){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });  \r\n        }\r\n\r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos)(document.querySelector('#unidadmedida') as HTMLInputElement).value = datos.unidadmedida;\r\n        });\r\n\r\n        btnAddItem.addEventListener('click', (e)=>{\r\n            let cantidad = parseFloat((document.querySelector('#cantidad') as HTMLInputElement).value);\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            console.log(datos);\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.idproducto==datos.id);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    //const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!;\r\n                    const productSelected = allproducts.find(x=>x.id==datos.id)!;\r\n\r\n                    const productototal = Number(productSelected.precio_venta)*cantidad;\r\n                    const productovalorimp = productototal*constImp[productSelected.impuesto??'0']; //si producto.impuesto es null toma el valor de cero\r\n\r\n                    const item:i_itemDetalle = {\r\n                        id: '',\r\n                        idcredito: idcreditoURL!,\r\n                        fk_producto: productSelected.id, \r\n                        idproducto:productSelected.id,\r\n                        idunidadmedida: productSelected.idunidadmedida,\r\n                        //tipo: itemselected.tipo,  ////tipo = 0 es producto (simple o compuesto produccion),  1 = subproducto\r\n                        tipoproducto: productSelected.tipoproducto, \r\n                        tipoproduccion: productSelected.tipoproduccion,\r\n                        rendimientoestandar: productSelected.rendimientoestandar,\r\n                        nombreproducto: productSelected.nombre, \r\n                        unidadmedida: productSelected.unidadmedida,\r\n                        preciopersonalizado: productSelected.preciopersonalizado,\r\n                        sku: productSelected.sku,\r\n                        costo: Number(productSelected.precio_compra),\r\n                        valorunidad: Number(productSelected.precio_venta),\r\n                        descuento: 0,\r\n                        cantidad: cantidad,\r\n                        base: productototal-productovalorimp,\r\n                        impuesto: productSelected.impuesto,\r\n                        valorimp: productovalorimp,\r\n                        subtotal: productototal,\r\n                        total: productototal,\r\n                        factor: 1,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(productSelected.id, productSelected.unidadmedida, cantidad, productSelected.nombre, productSelected.precio_venta, item.total);\r\n                    valorCarritoTotal();\r\n                }else{\r\n                    carrito[index].cantidad = cantidad;\r\n                    carrito[index].subtotal = (carrito[index].valorunidad)*carrito[index].cantidad;\r\n                    carrito[index].total = carrito[index].subtotal;\r\n                    //calculo del impuesto y base por producto en el carrito deventas\r\n                    carrito[index].valorimp = parseFloat((carrito[index].total*constImp[carrito[index].impuesto??0]).toFixed(3));\r\n                    carrito[index].base = parseFloat((carrito[index].total-carrito[index].valorimp).toFixed(3));\r\n                    //calcular valores\r\n                    const tr = document.querySelector(`[data-id=\"${carrito[index].fk_producto}\"]`)!;\r\n                    tr.children[1].textContent = carrito[index].cantidad+'';\r\n                    valorCarritoTotal();\r\n                }\r\n\r\n            }\r\n        });\r\n\r\n        function printItemTable(id:string, unidadmedida:string, cantidad:number, nombre:string, valorunidad:number, total:number){\r\n            //let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            /*\r\n            options = \"\";\r\n            const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n            productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            */\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.insertAdjacentHTML('afterbegin', \r\n                `<td class=\"p-4\">${nombre}</td>\r\n                <td class=\"p-4\">${cantidad}</td>\r\n                <td class=\"p-4\">${unidadmedida}</td>\r\n                <td class=\"p-4\">$ ${valorunidad.toLocaleString()}</td>\r\n                <td class=\"p-4\">$ ${total.toLocaleString()}</td>\r\n                <td class=\"p-4 flex items-center justify-center gap-2\">\r\n                    <button class=\"flex items-center gap-1 px-3 py-1 text-base text-indigo-600 border border-indigo-200 rounded-lg hover:bg-indigo-50\">\r\n                        👁 Ver\r\n                    </button>\r\n                    <button class=\"eliminarItem w-11 h-11 flex items-center justify-center text-rose-600 border border-rose-200 rounded-full hover:bg-rose-50 text-xl\">❌</button>\r\n                </td>`);\r\n            tablaItems?.appendChild(tr);\r\n        }\r\n\r\n\r\n        function valorCarritoTotal(){\r\n            //calcular el impuesto discriminado por tarifa\r\n            const idimpuesto: Record<string, number> = {'0': 1, '5': 2, '16': 3, '19': 4, 'excluido': 5, '8': 6 };\r\n            const objbase:{'0':number, '5':number, '16':number, '19':number, 'excluido':number, '8':number} = {'0': 0, '5': 0, '16': 0, '19': 0, 'excluido':0, '8': 0};\r\n\r\n            const mapImpuesto = new Map();\r\n            carrito.forEach(x=>{\r\n                if(x.impuesto){\r\n                if(mapImpuesto.has(x.impuesto)){\r\n                    const valor = mapImpuesto.get(x.impuesto) + x.total*constImp[x.impuesto];\r\n                    mapImpuesto.set(x.impuesto, valor);\r\n                }else{\r\n                    mapImpuesto.set(x.impuesto, x.total*constImp[x.impuesto]);\r\n                }\r\n                }\r\n                if(x.impuesto == null)x.impuesto = \"excluido\";\r\n                objbase[x.impuesto as keyof typeof objbase] += x.base;\r\n                const impValor = mapImpuesto.get(x.impuesto)??0;\r\n                const index = factimpuestos.findIndex(Obj=>Obj.id_impuesto == idimpuesto[x.impuesto]);\r\n                if(index!=-1){ //si existe remplazar obj\r\n                    factimpuestos[index] = {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor};\r\n                }else{\r\n                    factimpuestos = [...factimpuestos, {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor}];\r\n                }\r\n            });\r\n\r\n            //Valor del impuesto total de todos los productos, es decir de la factura;\r\n            let valorTotalImp:number = 0;\r\n            for(let valorImp of mapImpuesto.values())valorTotalImp += valorImp;\r\n            \r\n            valorTotal.valorimpuestototal = parseFloat(valorTotalImp.toFixed(3));  //valor del impuesto total factura de todos los productos\r\n            valorTotal.subtotal = carrito.reduce((total, x)=>x.total+total, 0);\r\n            valorTotal.base = valorTotal.subtotal - valorTotal.valorimpuestototal;  //valor de la base total factura de todos los productos\r\n            valorTotal.total = valorTotal.subtotal+dataCredit.valorinterestotal-dataCredit.descuentocredito-dataCredit.abonoinicial;\r\n            //console.log(valorTotal);\r\n            //console.log(factimpuestos);\r\n            document.querySelector('#subTotal')!.textContent = '$'+valorTotal.subtotal.toLocaleString();\r\n            (document.querySelector('#impuesto') as HTMLElement).textContent = '$'+valorTotalImp.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n            document.querySelector('#total')!.textContent = '$ '+(valorTotal.total).toLocaleString(); //+ interes - descuneto - abonoinicial\r\n            \r\n        }\r\n\r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaItems?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            //const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n        \r\n            if((e.target as HTMLElement).classList.contains('eliminarItem')){ //se trae todoscon true menos el que coincida con iditem y tipoitem\r\n                carrito = carrito.filter(x => x.fk_producto!==iditem);\r\n                tablaItems?.querySelector(`TR[data-id=\"${iditem}\"]`)?.remove();\r\n            }\r\n            valorCarritoTotal();\r\n            //itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n\r\n        btnUpdateCreditoSeparado.addEventListener('click', ()=>{\r\n            //validar que el montototal no sea menor a lo abonado hasta la fecha\r\n            if(valorTotal.total< (dataCredit.montototal-dataCredit.saldopendiente)){\r\n                Swal.fire('El valor del credito es inferior de lo que se ha abonado.', '', 'error')\r\n                return;\r\n            }\r\n\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Esta seguro de actualizar la orden?',\r\n                text: \"Se procesara la orden con todos los productos del separado\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('idcredito', idcreditoURL!);\r\n                        datos.append('ids', JSON.stringify(carrito.map(x=>x.id)));\r\n                        datos.append('nuevosproductos', JSON.stringify(carrito));\r\n\r\n                        datos.append('factimpuestos', JSON.stringify(factimpuestos));\r\n                        datos.append('capital', valorTotal.subtotal+'');\r\n                        datos.append('saldopendiente', (dataCredit.saldopendiente+valorTotal.total-dataCredit.montototal)+'');\r\n                        datos.append('montocuota', (Math.ceil((valorTotal.total/dataCredit.cantidadcuotas)*100)/100)+'');\r\n                        datos.append('montototal', valorTotal.total+'');\r\n                        datos.append('totalunidades', carrito.reduce((total, x)=>x.cantidad+total, 0)+'');\r\n                        \r\n                        datos.append('base', valorTotal.base.toFixed(3));  //base global del credito\r\n                        datos.append('valorimpuestototal', valorTotal.valorimpuestototal+''); //valor total del impuesto dle credito. \r\n                        datos.append('dctox100', valorTotal.dctox100+'');\r\n                        datos.append('descuento', dataCredit.descuentocredito+''); //descuento global de credito\r\n                    \r\n                        try {\r\n                            const url = \"/admin/api/editarOrdenCreditoSeparado\";  //api llamada a trasladosinvcontrolador\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                                /*setTimeout(() => {\r\n                                    window.location.href = `/admin/almacen/trasladarinventario`;\r\n                                }, 1600);*/\r\n                                Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()\r\n                }\r\n            });\r\n        });\r\n\r\n    }\r\n})();","(()=>{\r\n  if(document.querySelector('.detallecredito')){\r\n\r\n     \r\n    const btnajustarCredito = document.querySelector('#ajustarCredito') as HTMLButtonElement;\r\n    const btnDetalleProductos = document.querySelector('#btnDetalleProductos') as HTMLButtonElement;\r\n    const btnAbonar = document.querySelector('#btnAbonar') as HTMLButtonElement;\r\n    const btnEditarCrearAbono = document.querySelector('#btnEditarCrearAbono') as HTMLInputElement;\r\n    const btnEditarCrearPagoTotal = document.querySelector('#btnEditarCrearPagoTotal') as HTMLInputElement;\r\n    const btnPagarTodo = document.querySelector('#btnPagarTodo') as HTMLButtonElement;\r\n    const miDialogoAjustarCredito = document.querySelector('#miDialogoAjustarCredito') as any;\r\n    const miDialogoAbono = document.querySelector('#miDialogoAbono') as any;\r\n    const miDialogoPagoTotal = document.querySelector('#miDialogoPagoTotal') as any;\r\n    const miDialogoDetalleProducto = document.querySelector('#miDialogoDetalleProducto') as any;\r\n    const modalcambioMedioPago:any = document.querySelector(\"#cambioMedioPago\");\r\n    //const pagarTodo = document.querySelector('#pagarTodo') as HTMLButtonElement;\r\n    const totalPagado = document.querySelector('#totalPagado') as HTMLSpanElement;\r\n    const numCuota = document.querySelector('#numCuota') as HTMLLabelElement;\r\n    const selectMediopago = document.querySelector('#selectMediopago') as HTMLSelectElement;\r\n    const inputDescuentoAjustarCredito = document.querySelector('#inputDescuentoAjustarCredito') as HTMLInputElement;\r\n    let contentMP:HTMLButtonElement, idcuota:string = '0', idcredito:string = '0', totalpagado:string = '0', idmediopago:string = '0', mediopagado:string = '0';\r\n    \r\n    let indiceFila=0, tablacuotas:HTMLElement;\r\n\r\n    interface clavesApi {\r\n      clave:string,\r\n      valor_default:string|null,\r\n      valor_final:string|null,\r\n      valor_local:string|null\r\n    };\r\n\r\n    let clavedcto:clavesApi[];\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          clavedcto = resultado;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n    \r\n    document.addEventListener(\"click\", cerrarDialogoExterno);\r\n     \r\n    //////////////////  TABLA //////////////////////\r\n    tablacuotas = ($('#tablacuotas') as any).DataTable(configdatatables);\r\n\r\n\r\n    btnajustarCredito?.addEventListener('click', ():void=>{\r\n      miDialogoAjustarCredito.showModal();\r\n    });\r\n\r\n    btnDetalleProductos?.addEventListener('click', ():void=>{\r\n      miDialogoDetalleProducto.showModal();\r\n    });\r\n\r\n    //btn para abonar credito\r\n    btnAbonar?.addEventListener('click', ():void=>{\r\n      miDialogoAbono.showModal();\r\n    });\r\n\r\n    //btn para abonar credito\r\n    btnPagarTodo?.addEventListener('click', ():void=>{\r\n      miDialogoPagoTotal.showModal();\r\n    });\r\n\r\n\r\n    btnEditarCrearAbono.addEventListener('click', ()=>{\r\n      btnEditarCrearAbono.disabled = true;\r\n      (document.querySelector('#formCrearUpdateAbono') as HTMLFormElement).submit();\r\n    });\r\n    btnEditarCrearPagoTotal.addEventListener('click', ()=>{\r\n      btnEditarCrearPagoTotal.disabled = true;\r\n      (document.querySelector('#formCrearUpdatePagoTotal') as HTMLFormElement).submit();\r\n    });\r\n    \r\n\r\n    const saldopendiente = (document.querySelector('#saldopendiente') as HTMLInputElement).value;\r\n    document.querySelector('#abonoTotalAntiguo')?.addEventListener(\"input\", (e:Event)=>{\r\n      const abonoTotalAntiguo = (e.target as HTMLInputElement);\r\n      if(Number(abonoTotalAntiguo.value)>Number(saldopendiente))abonoTotalAntiguo.value = '';\r\n    });\r\n\r\n    ////////////// Evento a la tabla cuotas ///////////////\r\n    document.querySelector('#tablacuotas')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLButtonElement;\r\n      if(target?.classList.contains(\"mediosdepago\")||target.parentElement?.classList.contains(\"mediosdepago\"))cambiomediopago(target);\r\n      if(target?.classList.contains(\"printPOSAbono\"))printPOSComprobanteAbono(target.id);\r\n    });\r\n\r\n\r\n    function cambiomediopago(target:HTMLButtonElement){\r\n      document.querySelector('#textMP')!.textContent = 'Pago por '+target.textContent+': ';\r\n      idcuota = target.id;\r\n      totalpagado = target.dataset.totalpagado??'0';\r\n      idcredito = target.dataset.idcredito??'0';\r\n      idmediopago = target.dataset.idmediopago??'0';\r\n      mediopagado = target.dataset.mediopagado??'0';\r\n      contentMP = target;\r\n      totalPagado.textContent = '$ '+Number(mediopagado).toLocaleString();\r\n      numCuota.textContent = 'Credito N° : '+idcredito;\r\n      selectMediopago.value = idmediopago;\r\n      modalcambioMedioPago.showModal();\r\n    }\r\n\r\n\r\n    document.querySelector('#formCambioMedioPago')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      actualizarMediosPago();\r\n    });\r\n\r\n\r\n    async function actualizarMediosPago(){\r\n      const datos = new FormData();\r\n      datos.append('id', idcuota);\r\n      datos.append('idmediopago', idmediopago);\r\n      datos.append('id_credito', idcredito);\r\n      datos.append('idnuevomediopago', selectMediopago.value);\r\n      datos.append('valor', mediopagado);\r\n      try {\r\n          const url = \"/admin/api/cuota/cambioMedioPagoSeparado\";  //va al controlador creditoscontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            updateMP(resultado.mediosPagoUpdate);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n      modalcambioMedioPago.close();\r\n    }\r\n\r\n\r\n    function updateMP(mediosPagoUpdate:{id:string, idcuota:string, mediopago_id:string, valor:string}){\r\n      const {mediopago_id} = mediosPagoUpdate;\r\n      contentMP.textContent = selectMediopago.options[selectMediopago.selectedIndex].textContent;\r\n      contentMP.dataset.idmediopago = mediopago_id;\r\n    }\r\n\r\n\r\n\r\n    document.querySelector('#formAjustarCredito')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      const v:number = validarPasswordDcto();\r\n      if(!v)return;\r\n      ajustarCreditoAntiguo();\r\n    });\r\n\r\n    function validarPasswordDcto():number{\r\n      const clave = clavedcto.find(c => c.clave=='clave_para_ajustar_credito');\r\n      if(clave?.valor_final!==null && inputDescuentoAjustarCredito.value !== clave?.valor_final){\r\n        msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalertaClaveAjustarCredito') as HTMLElement));\r\n        return 0;\r\n      }\r\n      return 1;\r\n    }\r\n\r\n\r\n    async function ajustarCreditoAntiguo(){\r\n      const id:string = (document.querySelector('#idcredito') as HTMLInputElement).value;\r\n      const abonototalantiguo = (document.querySelector('#abonoTotalAntiguo') as HTMLInputElement).value||'0';\r\n      const recargo = (document.querySelector('#recargo') as HTMLInputElement).value||'0';\r\n      const datos = new FormData();\r\n      datos.append('id', id);\r\n      datos.append('recargo', recargo);\r\n      datos.append('abonototalantiguo', abonototalantiguo);\r\n      datos.append('fechainicio', (document.querySelector('#ajustarFechaInicio') as HTMLInputElement).value);\r\n      try {\r\n          const url = \"/admin/api/ajustarCreditoAntiguo\";  //va al controlador creditoscontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            ajustarIndicadores(abonototalantiguo, recargo);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n      miDialogoAjustarCredito.close();\r\n    }\r\n\r\n\r\n    function ajustarIndicadores(abonototalantiguo:string, recargo:string){\r\n      const capital:number = Number((document.querySelector('#capital') as HTMLInputElement).value);\r\n      const abonoinicial:number = Number((document.querySelector('#abonoinicial') as HTMLInputElement).value);\r\n      const montototal:number = Number((document.querySelector('#montototal') as HTMLInputElement).value);\r\n      const saldopendiente:number = Number((document.querySelector('#saldopendiente') as HTMLInputElement).value);\r\n      document.querySelector('#abonoInicialText')!.textContent = '$ '+abonototalantiguo;\r\n      document.querySelector('#interesText')!.textContent = '$ '+recargo;\r\n      document.querySelector('#creditoTotalText')!.textContent = '$ '+(capital - abonoinicial + Number(recargo)).toLocaleString();\r\n      document.querySelector('#saldopendientetext')!.textContent = '$ '+(capital+Number(recargo)-abonoinicial-Number(abonototalantiguo)).toLocaleString();\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if (f=== miDialogoAjustarCredito || f === miDialogoAbono || f === miDialogoDetalleProducto || f === modalcambioMedioPago || (f as HTMLInputElement).value === 'salir' || (f as HTMLInputElement).value === 'Cancelar' \r\n          || (f as HTMLButtonElement).id == 'btnXCerrarModalDetalleProducto' || (f as HTMLButtonElement).id == 'btnXCerrarModalAbono' || f === miDialogoPagoTotal\r\n          || (f as HTMLButtonElement).id == 'btnXCerrarModalPagoTotal' ) {\r\n        miDialogoAbono.close();\r\n        miDialogoPagoTotal.close();\r\n        miDialogoDetalleProducto.close();\r\n        modalcambioMedioPago.close();\r\n        miDialogoAjustarCredito.close();\r\n      }\r\n    }\r\n\r\n\r\n    function printPOSComprobanteAbono(idabono:string){\r\n      if(!isNaN(Number(idabono)))\r\n        window.open(\"/admin/printPDFAbonoCredito?id=\" + idabono, \"_blank\"); //controlador printcontrolador\r\n    }\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.creditos')){\r\n\r\n    type creditsapi = {\r\n      id:string,\r\n      id_fksucursal: string,\r\n      factura_id: string,\r\n      cliente_id: string,\r\n      nombrecliente: string,\r\n      capital: string,\r\n      abonoinicial: string,\r\n      saldopendiente: string,\r\n      numcuota: string,\r\n      cantidadcuotas: string,\r\n      montocuota: string,\r\n      frecuenciapago: string,\r\n      fechainicio: string,\r\n      interes: string,\r\n      interesxcuota: string,\r\n      interestotal: string,\r\n      valorinteresxcuota: string,\r\n      valorinterestotal: string,\r\n      montototal: string,\r\n      fechavencimiento: string,\r\n      productoentregado: string,\r\n      estado: string,\r\n      created_at: string,\r\n    };\r\n    \r\n    /*interface Item {\r\n      id_impuesto: number,\r\n      facturaid: number,\r\n      basegravable: number,\r\n      valorimpuesto: number\r\n    }\r\n    let factimpuestos:Item[] = [];*/\r\n\r\n    let credits:creditsapi[]=[], uncredito:creditsapi;\r\n    let indiceFila=0, control=0;\r\n\r\n\r\n    /*(async ()=>{\r\n      try {\r\n          const url = \"/admin/api/allcredits\"; //llamado a la API REST y se trae todos los productos\r\n          const respuesta = await fetch(url); \r\n          credits = await respuesta.json(); \r\n          console.log(credits);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();*/\r\n\r\n\r\n\r\n    \r\n    //////////////////  TABLA //////////////////////\r\n    Object.assign(configdatatablesgenerico, {order: [[ 0, 'desc' ]]});\r\n    let tablaCreditos = ($('#tablaCreditos') as any).DataTable(configdatatablesgenerico);\r\n\r\n\r\n    //evento a la tabla\r\n    document.querySelector('#tablaCreditos tbody')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"anularCredito\")||(e.target as HTMLElement).parentElement?.classList.contains(\"anularCredito\"))anularCredito(e);\r\n      if(target?.classList.contains(\"printPOSSeparado\"))printPOSSeparado(target.id);\r\n    });\r\n\r\n\r\n    function anularCredito(e:Event){\r\n      let idcredito = (e.target as HTMLElement).parentElement?.id!, info = (tablaCreditos as any).page.info();\r\n      if((e.target as HTMLElement)?.tagName === 'I')idcredito = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      indiceFila = (tablaCreditos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      \r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el credito',\r\n          text: \"El credito, seran anulado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idcredito);\r\n                  try {\r\n                      const url = \"/admin/api/anularSeparado\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();\r\n                      if(resultado.exito !== undefined){\r\n                        const datosActuales = (tablaCreditos as any).row(indiceFila).data();\r\n                        datosActuales[10] = 'Anulado';\r\n                        datosActuales[11] = `<a class=\"btn-xs btn-bluedark\" href=\"/admin/creditos/detallecredito?id=${idcredito}\" title=\"Ver estadisticas del cliente\"><i class=\"fa-solid fa-chart-simple\"></i></a>`;\r\n                        (tablaCreditos as any).row(indiceFila).data(datosActuales).draw();\r\n                        (tablaCreditos as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success');\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error');\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    function printPOSSeparado(idcredito:string){\r\n      //printTicketPOS(resultado.idfactura, resultado.dataInvoice);\r\n      console.log(idcredito);\r\n      if(!isNaN(Number(idcredito)))\r\n        window.open(\"/admin/printPDFPOSSeparado?id=\" + idcredito, \"_blank\"); //controlador printcontrolador\r\n    }\r\n\r\n    \r\n    async function printTicketPOS(idfactura:string, datainvoice:DataInvoice){\r\n      try {\r\n        const url = \"http://localhost:3100/api/printPOS/ticket1/CAJA\"; //llamado a la API REST apidiancontrolador.php\r\n        const respuesta = await fetch(url, {\r\n          method: 'POST',\r\n          headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n          body: JSON.stringify(datainvoice)\r\n        });\r\n        const resultado = await respuesta.json();\r\n        console.log(resultado);\r\n      } catch (error) {\r\n        console.log(error);\r\n      }\r\n    }\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.crearseparado')){\r\n\r\n    const POS = (window as any).POS;\r\n     \r\n    const btnCrearSeparado = document.querySelector('#btnCrearSeparado');\r\n    const miDialogoFacturar = document.querySelector('#miDialogoFacturar') as any;\r\n    const tablaSeparado = document.querySelector('#tablaSeparado tbody');\r\n    const btnPagar = document.getElementById('btnPagar') as HTMLInputElement;\r\n    const btnCaja = document.querySelector('#caja') as HTMLSelectElement; //select de la caja en el modal pagar\r\n\r\n\r\n    type conversionunidadesapi = {\r\n      id:string,\r\n      idproducto: string,\r\n      idsubproducto: string,\r\n      idunidadmedidabase: string,\r\n      idunidadmedidadestino: string,\r\n      nombreunidadbase: string,\r\n      nombreunidaddestino: string,\r\n      factorconversion: string,\r\n    };\r\n\r\n    interface Item {\r\n      id_impuesto: number,\r\n      facturaid: number,\r\n      basegravable: number,\r\n      valorimpuesto: number\r\n    }\r\n\r\n    let allConversionUnidades:conversionunidadesapi[] = [];\r\n    let filteredData: {id:string, text:string, tipo:string, tipoproduccion:string, impuesto:string, sku:string, unidadmedida:string, rendimientoestandar:string, precio_compra:string, precio_venta:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n    let carrito:{id:string, fk_producto:string,  tipoproducto: string, tipoproduccion:string, foto:string,costo:number, valorunidad:string, nombreproducto:string,  rendimientoestandar:string, unidad:string, cantidad: number, factor: number, precio_venta: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total: number, precio_compra: number}[]=[];\r\n    const valorTotal = {subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, idtarifa: 0, valortarifa: 0, total: 0}; //datos global de la venta\r\n    let factimpuestos:Item[] = [], tipoventa:string=\"Contado\";\r\n    const mapMediospago = new Map();\r\n    \r\n    const constImp: {[key:string]: number} = {};\r\n    constImp['excluido'] = 0;\r\n    constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n    constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n    constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n    constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n    constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n    ($('#cliente') as any).select2({ placeholder: \"Seleccionar el cliente\", maximumSelectionLength: 1});\r\n    ($('#frecuenciapago') as any).select2({ placeholder: \"Seleccionar el cliente\", maximumSelectionLength: 1});\r\n\r\n     document.addEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n    (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allproducts\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n            const respuesta = await fetch(url); \r\n            const resultado:{id:string, nombre:string, tipoproducto:string, tipoproduccion:string, impuesto:string, sku:string, unidadmedida:string, rendimientoestandar:string, precio_compra:string, precio_venta:string, visible:string, habilitarventa:string}[] = await respuesta.json();\r\n            filteredData = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1').map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'0', tipoproduccion: item.tipoproduccion??'0', impuesto: item.impuesto, sku: item.sku, unidadmedida: item.unidadmedida, rendimientoestandar: item.rendimientoestandar, precio_compra: item.precio_compra, precio_venta: item.precio_venta }));\r\n            activarselect2(filteredData);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    })();\r\n\r\n    (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n            const respuesta = await fetch(url); \r\n            allConversionUnidades = await respuesta.json();\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    })();\r\n\r\n    //DESACTIVADO EL CANAL DE VENTA\r\n    document.querySelector('#contenedorCanalVenta')?.classList.add('hidden');\r\n    document.querySelector('#canalVenta')?.removeAttribute('required');\r\n\r\n    function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n      ($('#articulo') as any).select2({ \r\n          data: filteredData,\r\n          placeholder: \"Selecciona un item\",\r\n          maximumSelectionLength: 1,\r\n          /*\r\n          templateResult: function (data:{id:string, text:string, tipo:string}) {\r\n              // Personalizar cómo se muestra cada opción en el dropdown\r\n              if (!data.id) { return data.text; }  // Si no hay id, solo mostrar el texto\r\n              const html = `\r\n                  <div class=\"custom-option\">\r\n                      <span class=\"item-name\">${data.text}</span> \r\n                      <span class=\"item-type\">${data.tipo}</span>  <!-- Mostrar tipo adicional -->\r\n                  </div>`;\r\n              return $(html);  // Devolver el HTML personalizado\r\n          }*/\r\n      });\r\n    }\r\n\r\n    ////// EVENTO AL SELECT ARTICULOS O ITEMS PARA SELECCIONAR EL ITEM Y AÑADIR AL CARRITO ////// \r\n    $(\"#articulo\").on('change', (e)=>{\r\n        let datos = ($('#articulo') as any).select2('data')[0];\r\n        if(datos){\r\n          let cantidad = 1, itemselected = carrito.find(x=>x.fk_producto==datos.id);\r\n          if(itemselected != undefined)cantidad += itemselected.cantidad;\r\n          actualizarCarrito(datos.id, cantidad, true);\r\n          $(\"#articulo\").val('null').trigger('change');\r\n        }\r\n    });\r\n\r\n    function actualizarCarrito(id:string, cantidad:number = 1, stateinput:boolean){\r\n      const index = carrito.findIndex(x=>x.fk_producto==id);\r\n      if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n          const itemselected = filteredData.find(x=>x.id==id)!; //products es el arreglo de todos los productos traido por api\r\n          \r\n          const productototal = Number(itemselected.precio_venta)*cantidad;\r\n          const productovalorimp = productototal*constImp[itemselected.impuesto??'0']; //si producto.impuesto es null toma el valor de cero\r\n          \r\n          const item:{id: string, fk_producto: string, tipoproducto: string, tipoproduccion:string, foto:string, costo:number, valorunidad:string, nombreproducto: string, rendimientoestandar:string, unidad: string, cantidad: number, factor: number, precio_venta: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total: number, precio_compra:number} = {\r\n              id: '',\r\n              fk_producto: itemselected?.id!,\r\n              tipoproducto: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n              tipoproduccion: itemselected.tipoproduccion,\r\n              foto: '',\r\n              costo: Number(itemselected.precio_compra),\r\n              valorunidad: itemselected.precio_venta,\r\n              nombreproducto: itemselected.text,\r\n              rendimientoestandar: itemselected.rendimientoestandar,\r\n              unidad: itemselected.unidadmedida,\r\n              cantidad: 1,\r\n              factor: 1,\r\n              impuesto: itemselected.impuesto,\r\n              precio_venta: productototal,\r\n              subtotal: productototal,\r\n              base: productototal-productovalorimp,\r\n              valorimp: productovalorimp,\r\n              descuento: 0,\r\n              total: Number(itemselected.precio_venta),\r\n              precio_compra: Number(itemselected.precio_compra),\r\n          }\r\n          carrito = [...carrito, item];\r\n          POS.carrito = carrito;\r\n          printItemTable(id);\r\n      }else{  //si ya existe en el carrito, sumar\r\n        if(cantidad <= 0){\r\n          cantidad = 0;\r\n          carrito[index].total = 0;\r\n          //carrito = carrito.filter(x=>x.iditem != id);\r\n        }\r\n        \r\n        carrito[index].cantidad = cantidad;\r\n        /*const total:number = carrito[index].cantidad*carrito[index].precio_venta;\r\n        carrito[index].subtotal = total;\r\n        carrito[index].total = total;*/\r\n        carrito[index].subtotal = (carrito[index].precio_venta)*carrito[index].cantidad;\r\n        carrito[index].total = carrito[index].subtotal;\r\n        //calculo del impuesto y base por producto en el carrito deventas\r\n        carrito[index].valorimp = parseFloat((carrito[index].total*constImp[carrito[index].impuesto??0]).toFixed(3));\r\n        carrito[index].base = parseFloat((carrito[index].total-carrito[index].valorimp).toFixed(3));\r\n\r\n        if(stateinput)\r\n          (tablaSeparado?.querySelector(`TR[data-id=\"${id}\"] .inputcantidad`) as HTMLInputElement).value = carrito[index].cantidad+'';\r\n        (tablaSeparado?.querySelector(`TR[data-id=\"${id}\"]`)?.children?.[3] as HTMLElement).textContent = \"$\"+carrito[index].total.toLocaleString();\r\n        valorCarritoTotal();\r\n      }\r\n      //console.log(carrito);\r\n      /*if(cantidad<1){\r\n          carrito = carrito.filter(x=>x.iditem != id);\r\n      }*/\r\n    }\r\n\r\n    function printItemTable(id:string){\r\n        const uncarrito = carrito.find(x=>x.fk_producto==id)!;\r\n        let options:string = '';\r\n\r\n        const productounidades = allConversionUnidades.filter(x => x.idproducto === id); \r\n        productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n\r\n        const tr = document.createElement('TR');\r\n        tr.classList.add('productselect');\r\n        tr.dataset.id = `${id}`;\r\n        //tr.dataset.tipo = `${item.tipo}`;\r\n        tr.insertAdjacentHTML('afterbegin', `\r\n          <td class=\"!p-2 !py-0 text-xl text-gray-500 leading-5\">${uncarrito.nombreproducto}</td> \r\n          <td class=\"!p-2 !py-0 text-xl text-gray-500 leading-5\"><select class=\"formulario__select selectunidad\">${options}</select></td>\r\n          <td class=\"!p-2 !py-0\"><div class=\"flex\"><button type=\"button\"><span class=\"menos material-symbols-outlined\">remove</span></button><input type=\"text\" class=\"inputcantidad w-20 px-2 text-center\" name=\"inputcantidad\" value=\"${uncarrito.cantidad}\"><button type=\"button\"><span class=\"mas material-symbols-outlined\">add</span></button></div></td>\r\n          <td class=\"!p-2 !py-0 text-xl text-gray-500 leading-5\">${uncarrito.precio_venta*uncarrito.cantidad}</td>\r\n          <td class=\"accionestd\"><div class=\"acciones-btns\"><button class=\"btn-md btn-red eliminarProducto\"><i class=\"fa-solid fa-trash-can\"></i></button></div></td>`);\r\n        tablaSeparado?.appendChild(tr);\r\n        valorCarritoTotal();\r\n    }\r\n\r\n    function valorCarritoTotal(){\r\n       //calcular el impuesto discriminado por tarifa\r\n      const idimpuesto: Record<string, number> = {'0': 1, '5': 2, '16': 3, '19': 4, 'excluido': 5, '8': 6 };\r\n      const objbase:{'0':number, '5':number, '16':number, '19':number, 'excluido':number, '8':number} = {'0': 0, '5': 0, '16': 0, '19': 0, 'excluido':0, '8': 0};\r\n\r\n      const mapImpuesto = new Map();\r\n      carrito.forEach(x=>{\r\n        if(x.impuesto){\r\n          if(mapImpuesto.has(x.impuesto)){\r\n            const valor = mapImpuesto.get(x.impuesto) + x.total*constImp[x.impuesto];\r\n            mapImpuesto.set(x.impuesto, valor);\r\n          }else{\r\n            mapImpuesto.set(x.impuesto, x.total*constImp[x.impuesto]);\r\n          }\r\n        }\r\n        if(x.impuesto == null)x.impuesto = \"excluido\";\r\n          objbase[x.impuesto as keyof typeof objbase] += x.base;\r\n          const impValor = mapImpuesto.get(x.impuesto)??0;\r\n          const index = factimpuestos.findIndex(Obj=>Obj.id_impuesto == idimpuesto[x.impuesto]);\r\n          if(index!=-1){ //si existe remplazar obj\r\n            factimpuestos[index] = {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor};\r\n          }else{\r\n            factimpuestos = [...factimpuestos, {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor}];\r\n          }\r\n      });\r\n\r\n      //Valor del impuesto total de todos los productos, es decir de la factura;\r\n      let valorTotalImp:number = 0;\r\n      for(let valorImp of mapImpuesto.values())valorTotalImp += valorImp;\r\n      \r\n      valorTotal.valorimpuestototal = parseFloat(valorTotalImp.toFixed(3));  //valor del impuesto total factura de todos los productos\r\n      valorTotal.subtotal = carrito.reduce((total, x)=>x.total+total, 0);\r\n      valorTotal.base = valorTotal.subtotal - valorTotal.valorimpuestototal;  //valor de la base total factura de todos los productos\r\n      valorTotal.total = valorTotal.subtotal + valorTotal.valortarifa - valorTotal.descuento;\r\n      //console.log(valorTotal);\r\n      //console.log(factimpuestos);\r\n      document.querySelector('#subTotal')!.textContent = '$'+valorTotal.subtotal.toLocaleString();\r\n      (document.querySelector('#impuesto') as HTMLElement).textContent = '$'+valorTotalImp.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n      document.querySelector('#total')!.textContent = '$ '+valorTotal.total.toLocaleString();\r\n      (document.querySelector('#montocuota') as HTMLInputElement).value = valorTotal.total+'';\r\n      //valorTotal.total = Number((document.querySelector('#abonoinicial') as HTMLInputElement).value);\r\n      //POS.gestionSubirModalPagar.valoresCredito\r\n      POS.valorTotal = valorTotal;\r\n      POS.mapMediospago = mapMediospago;\r\n      //**** recalcular valores del credito\r\n      POS.gestionSubirModalPagar.calculoTasaInteres();\r\n    }\r\n\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaSeparado?.addEventListener('click', (e:Event)=>{\r\n      const elementProduct = (e.target as HTMLElement)?.closest('.productselect');\r\n      const idProduct = (elementProduct as HTMLElement).dataset.id!;\r\n      //const precio = (elementProduct as HTMLElement).dataset.precio!;\r\n      const productoCarrito = carrito.find(x=>x.fk_producto==idProduct);\r\n      if((e.target as HTMLElement).classList.contains('menos')){\r\n        actualizarCarrito(idProduct, productoCarrito!.cantidad-1, true);\r\n      }\r\n      \r\n      if((e.target as HTMLElement).classList.contains('inputcantidad')){\r\n        if((e.target as HTMLElement).dataset.event != \"eventInput\"){\r\n          e.target?.addEventListener('input', (e)=>{\r\n            let val = (e.target as HTMLInputElement).value;\r\n            val = val.replace(/[^0-9.]/g, '');\r\n            const partes = val.split('.');\r\n            if(partes.length > 2)val = partes[0]+'.'+partes.slice(1).join('');\r\n            if (val.startsWith('.'))val = '1';\r\n            if (val === '' || isNaN(parseFloat(val))) val = '0';\r\n\r\n            (e.target as HTMLInputElement).value = val;\r\n            actualizarCarrito(idProduct, Number((e.target as HTMLInputElement).value), false);\r\n          });\r\n          (e.target as HTMLElement).dataset.event = \"eventInput\"; //se marca al input que ya tiene evento añadido\r\n        }\r\n      }\r\n\r\n      if((e.target as HTMLElement).classList.contains('mas')){\r\n        actualizarCarrito(idProduct, productoCarrito!.cantidad+1, true);\r\n      }\r\n      \r\n      if((e.target as HTMLElement).classList.contains('eliminarProducto') || (e.target as HTMLElement).tagName == \"I\"){\r\n        carrito = carrito.filter(x=>x.fk_producto != idProduct);\r\n        valorCarritoTotal();\r\n        tablaSeparado?.querySelector(`TR[data-id=\"${idProduct}\"]`)?.remove();\r\n      }\r\n    });\r\n\r\n\r\n    //btn para abrir modal de pago\r\n    btnCrearSeparado?.addEventListener('click', (e)=>{\r\n      e.preventDefault();\r\n      if((document.querySelector('#cliente') as HTMLSelectElement).value === ''){\r\n        msjAlert('error', 'Debe seleccionar el cliente.', (document.querySelector('#divmsjalerta') as HTMLElement));\r\n        return;\r\n      }\r\n      if((document.querySelector('#cantidadcuotas') as HTMLSelectElement).value === ''){\r\n        msjAlert('error', 'Debe indicar la cantidad de cuotas.', (document.querySelector('#divmsjalerta') as HTMLElement));\r\n        return;\r\n      }\r\n      if(carrito.length){\r\n        document.querySelector('.Efectivo')?.removeAttribute('readonly');\r\n        document.querySelector('#inputscreditos')?.remove();  //elimina los inputs de credito en el modal de procesar pago.\r\n        document.querySelector('#abonoTotal')?.classList.remove('hidden');\r\n        document.querySelector('#textPrint')!.textContent = '¿Desea imprimir comprobante?';\r\n        tipoventa = \"Credito\";\r\n        //mapMediospago.clear();\r\n        POS.tipoventa = tipoventa;\r\n        //POS.valorTotal = valorTotal;\r\n        //POS.mapMediospago = mapMediospago;\r\n        POS.gestionSubirModalPagar.subirModalPagar();\r\n        miDialogoFacturar.showModal();\r\n      }\r\n    });\r\n\r\n\r\n    document.querySelector('#formfacturar')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      if(valorTotal.total <= 0 || valorTotal.subtotal <= 0){\r\n        msjAlert('error', 'Medio de pago no indicado', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n      //calcular si el totoal de los medios de pago es menor al abono inicial, abortar pago...\r\n      let totalMediosPago:number = 0;\r\n      for(let value of mapMediospago.values())totalMediosPago+=value;\r\n      if(totalMediosPago<POS.gestionSubirModalPagar.valoresCredito.abonoinicial){\r\n        msjAlert('error', 'Valor a pagar no corresponde', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n\r\n      btnPagar.disabled = true;\r\n      btnPagar.value = 'Procesando...';\r\n      procesarSeparado();\r\n    });\r\n\r\n\r\n    async function procesarSeparado(){\r\n      const imprimir = document.querySelector('input[name=\"imprimir\"]:checked') as HTMLInputElement;\r\n      const valoresCredito = POS.gestionSubirModalPagar.valoresCredito;\r\n      valoresCredito.cliente_id = (document.querySelector('#cliente') as HTMLSelectElement).value;\r\n      valoresCredito.valorpagado = valoresCredito.abonoinicial;\r\n      valoresCredito.cajaid = btnCaja.value;\r\n      valoresCredito.totalunidades = carrito.reduce((total, producto)=>producto.cantidad+total, 0)+'';\r\n      valoresCredito.base = valorTotal.base.toFixed(3);\r\n      valoresCredito.valorimpuestototal = valorTotal.valorimpuestototal+'';\r\n      valoresCredito.dctox100 = valorTotal.dctox100+'';\r\n      valoresCredito.descuento = valorTotal.descuento+'';\r\n      valoresCredito.nota = (document.querySelector('#nota') as HTMLInputElement).value;\r\n\r\n      const datos = new FormData();\r\n      datos.append('cliente_id', $('#cliente').val()as string);\r\n      datos.append('abonoinicial', $('#abonoinicial').val()as string);\r\n      datos.append('cantidadcuotas', $('#cantidadcuotas').val()as string);\r\n      datos.append('montocuota', $('#montocuota').val()as string);\r\n      datos.append('frecuenciapago', $('#frecuenciapago').val()as string);\r\n      datos.append('carrito', JSON.stringify(carrito.filter(x=>x.cantidad>0)));  //envio de todos los productos con sus cantidades\r\n      datos.append('mediospago', JSON.stringify(Array.from(mapMediospago, ([mediopago_id, valor])=>({mediopago_id, idcuota:0, valor}))));\r\n      datos.append('valorefectivo', mapMediospago.get('1')??'0');\r\n      datos.append('factimpuestos', JSON.stringify(factimpuestos));\r\n      datos.append('valoresCredito', JSON.stringify(valoresCredito));\r\n\r\n      datos.append('totalunidades', carrito.reduce((total, producto)=>producto.cantidad+total, 0)+'');\r\n      datos.append('base', valorTotal.base.toFixed(3));\r\n      datos.append('valorimpuestototal', valorTotal.valorimpuestototal+''); //valor total del impuesto. \r\n      datos.append('dctox100', valorTotal.dctox100+'');\r\n      datos.append('descuento', valorTotal.descuento+'');\r\n      //datos.append('nota', (document.querySelector('#nota') as HTMLInputElement).value);\r\n      try {\r\n          const url = \"/admin/api/crearSeparado\";  //va al controlador creditoscontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            /////// reinciar modulo de ventas\r\n            //vaciarventa();\r\n            btnPagar.disabled = false;\r\n            btnPagar.value = 'Pagar';\r\n            miDialogoFacturar.close();\r\n            \r\n            if(resultado.idcredito && imprimir.value === '1')\r\n              await printTicketSeparado(resultado.idcredito);\r\n            \r\n            setTimeout(() => { window.location.href = \"/admin/creditos\"; }, 900);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n    function printTicketSeparado(idcredito:string): Promise<void>{\r\n      return new Promise<void>((resolve, reject) => {\r\n        setTimeout(() => {\r\n          window.open(\"/admin/printPDFPOSSeparado?id=\" + idcredito, \"_blank\");\r\n          resolve();\r\n        }, 700);\r\n      })\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const miDialogoDescuento = POS.gestionarDescuentos.miDialogoDescuento;\r\n      const f = event.target;\r\n      if (f === miDialogoFacturar || f === miDialogoDescuento || (f as HTMLInputElement).closest('.salir') || (f as HTMLInputElement).value === 'salir' || (f as HTMLInputElement).value === 'Cancelar') {\r\n        miDialogoFacturar.close();\r\n        miDialogoDescuento.close();\r\n      }\r\n    }\r\n\r\n\r\n    POS.cerrarDialogoExterno = cerrarDialogoExterno;\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.clientes')){\r\n      const btncrearCliente = document.querySelector('#crearCliente');\r\n      const btncrearDireccion = document.querySelector('#crearDireccion');\r\n      const miDialogoCliente = document.querySelector('#miDialogoCliente') as any;\r\n      const miDialogoCrearDireccion = document.querySelector('#miDialogoCrearDireccion') as any;\r\n      const miDialogoUpDireccion = document.querySelector('#miDialogoUpDireccion') as any;\r\n      const selectdirecciones = document.querySelector('#selectdirecciones') as HTMLSelectElement;\r\n      const btnCerrarUpDireccion = document.querySelector('#btnCerrarUpDireccion') as HTMLButtonElement;\r\n      let select2Init = false, indiceFila=0, control=0, tablaClientes:HTMLElement;\r\n      \r\n      type direccionesapi = {\r\n        id:string,\r\n        idcliente:string,\r\n        idtarifa:string,\r\n        tarifa:{id:string, idcliente:string, nombre:string, valor:string},\r\n        direccion:string,\r\n        ciudad:string,\r\n        departamento:string\r\n      };\r\n      let direcciones:direccionesapi[]=[];\r\n  \r\n      type clientesapi = {\r\n        id:string,\r\n        nombre: string,\r\n        apellido: string,\r\n        tipodocumento: string,\r\n        identificacion: string,\r\n        telefono: string,\r\n        email: string,\r\n        fecha_nacimiento: string,\r\n        total_compras: string,\r\n        ultima_compra: string;\r\n        data1: string,\r\n        //idservicios:{idempleado:string, idservicio:string}[]\r\n      };\r\n  \r\n      let clientes:clientesapi[]=[], uncliente:clientesapi;\r\n  \r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allclientes\"; //llamado a la API REST y se trae todos los productos\r\n            const respuesta = await fetch(url); \r\n            clientes = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n  \r\n      \r\n  \r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      //////////////////  TABLA //////////////////////\r\n      tablaClientes = ($('#tablaClientes') as any).DataTable(configdatatables);\r\n  \r\n      btncrearCliente?.addEventListener('click', (e):void=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalCliente')!.textContent = \"Crear cliente\";\r\n        (document.querySelector('#btnEditarCrearCliente') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoCliente.showModal();\r\n      });\r\n\r\n\r\n      btncrearDireccion?.addEventListener('click', (e):void=>{\r\n        control = 0;\r\n        document.querySelector('#modalDireccion')!.textContent = \"Crear direccion\";\r\n        (document.querySelector('#btnEditarCrearDireccion') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoCrearDireccion.showModal();\r\n        activarSelect2();\r\n      });\r\n\r\n\r\n      function activarSelect2(){\r\n        if(select2Init)return;\r\n        ($('#selectcliente') as any).select2({\r\n          dropdownParent: $('#miDialogoCrearDireccion'),\r\n          placeholder: \"Seleccionar el cliente\",\r\n          maximumSelectionLength: 1\r\n        });\r\n        select2Init = true;\r\n      }\r\n  \r\n      document.querySelector('#tablaClientes')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n        const target = e.target as HTMLElement;\r\n        if((e.target as HTMLElement)?.classList.contains(\"editarClientes\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarClientes\"))editarClientes(e);\r\n        if(target?.classList.contains(\"eliminarClientes\")||target.parentElement?.classList.contains(\"eliminarClientes\"))eliminarClientes(e);\r\n        if(target?.classList.contains(\"editarEliminarDireccion\")||target.parentElement?.classList.contains(\"editarEliminarDireccion\"))upRemoveDir(e);\r\n      });\r\n  \r\n      function editarClientes(e:Event){\r\n        let idcliente = (e.target as HTMLElement).parentElement?.id!;\r\n        if((e.target as HTMLElement)?.tagName === 'I')idcliente = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n        control = 1;\r\n        document.querySelector('#modalCliente')!.textContent = \"Actualizar cliente\";\r\n        (document.querySelector('#btnEditarCrearCliente') as HTMLInputElement)!.value = \"Actualizar\";\r\n        uncliente = clientes.find(x=>x.id === idcliente)!;\r\n        (document.querySelector('#nombre')as HTMLInputElement).value = uncliente?.nombre!;\r\n        (document.querySelector('#apellido')as HTMLInputElement).value = uncliente?.apellido!;\r\n        $('#tipodocumento').val(uncliente?.tipodocumento??'');\r\n        (document.querySelector('#identificacion')as HTMLInputElement).value = uncliente?.identificacion??'';\r\n        (document.querySelector('#telefono')as HTMLInputElement).value = uncliente?.telefono??'';\r\n        (document.querySelector('#email')as HTMLInputElement).value = uncliente?.email??'';\r\n        (document.querySelector('#fecha_nacimiento')as HTMLInputElement).value = uncliente?.fecha_nacimiento??'';\r\n        \r\n        miDialogoCliente.showModal();\r\n      }\r\n  \r\n      ////////////////////  Actualizar/Editar clientes  //////////////////////\r\n      document.querySelector('#formCrearUpdateCliente')?.addEventListener('submit', e=>{\r\n        if(control){\r\n          e.preventDefault();\r\n          var info = (tablaClientes as any).page.info();\r\n          \r\n          (async ()=>{ \r\n            const datos = new FormData();\r\n            datos.append('idcliente', uncliente!.id);\r\n            datos.append('nombre', $('#nombre').val()as string);\r\n            datos.append('apellido', $('#apellido').val()as string);\r\n            datos.append('tipodocumento', $('#tipodocumento').val()as string);\r\n            datos.append('identificacion', $('#identificacion').val()as string);\r\n            datos.append('telefono', $('#telefono').val()as string);\r\n            datos.append('email', $('#email').val()as string);\r\n            datos.append('fecha_nacimiento', $('#fecha_nacimiento').val()as string);\r\n            try {\r\n                const url = \"/admin/api/actualizarCliente\";\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json(); \r\n                if(resultado.exito !== undefined){\r\n                  msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  /// actualizar el arregle de clientes ///\r\n                  clientes.forEach(a=>{if(a.id == uncliente.id)a = Object.assign(a, resultado.cliente[0]);});\r\n                  ///////// cambiar la fila completa, su contenido //////////\r\n                  const datosActuales = (tablaClientes as any).row(indiceFila).data();\r\n                  /*NOMBRE*/datosActuales[1] = $('#nombre').val();\r\n                  /*APELLIDO*/datosActuales[2] = $('#apellido').val();\r\n                  /*TELEFONO*/datosActuales[3] = $('#telefono').val();\r\n                  /*EMAIL*/datosActuales[4] = $('#email').val();\r\n                  \r\n                  (tablaClientes as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaClientes as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }else{\r\n                  msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n                miDialogoCliente.close();\r\n                \r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n          })();//cierre de async()\r\n        } //fin if(control)\r\n      });\r\n  \r\n\r\n      function upRemoveDir(e:Event){ //actualizar o eliminar direccion\r\n        let idcliente = (e.target as HTMLElement).parentElement!.id, info = (tablaClientes as any).page.info();\r\n        if((e.target as HTMLElement).tagName === 'I')idcliente = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n        (async ()=>{\r\n          try {\r\n            const url = \"/admin/api/direccionesXcliente?id=\"+idcliente; //llamado a la API REST y se trae las direcciones segun cliente elegido\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json(); \r\n            direcciones = resultado;\r\n            addDireccionSelect(resultado);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();\r\n        miDialogoUpDireccion.showModal();\r\n      }\r\n\r\n\r\n       ////// añade direccion al select de direcciones al miDialogoUpDireccion, cuando se desea actualizar o eliminar la direccion de un cliente\r\n      function addDireccionSelect<T extends {id:string, idcliente:string, idtarifa:string, tarifa:{id:string, idcliente:string, nombre:string, valor:string}, direccion:string, ciudad:string, departamento:string}>(addrs: T[]):void{\r\n        while(selectdirecciones?.firstChild)selectdirecciones.removeChild(selectdirecciones?.firstChild);\r\n        addrs.forEach(dir =>{\r\n          const option = document.createElement('option');\r\n          option.textContent = dir.direccion;\r\n          option.value = dir.id;\r\n          option.dataset.idcliente = dir.idcliente;\r\n          option.dataset.idtarifa = dir.idtarifa;\r\n          selectdirecciones.appendChild(option);\r\n        });\r\n        $('#uptarifa').val(addrs[0].idtarifa);\r\n        (document.querySelector('#updepartamento') as HTMLInputElement).value = addrs[0].departamento;\r\n        (document.querySelector('#upciudad') as HTMLInputElement).value = addrs[0].ciudad;\r\n        (document.querySelector('#updireccion') as HTMLInputElement).value = addrs[0].direccion;\r\n      }\r\n\r\n\r\n      ///////// Evento al select de direcciones en el modal actualizar direciones de cada cliente ////////////\r\n      selectdirecciones?.addEventListener('change', (e)=>{\r\n        const select = (e.target as HTMLSelectElement);\r\n        const idDir:string = select.options[select.selectedIndex].value;\r\n        const objDireccion = direcciones.find(x=>x.id == idDir)!;\r\n        $('#uptarifa').val(objDireccion?.idtarifa??1);\r\n        (document.querySelector('#updepartamento') as HTMLInputElement).value = objDireccion.departamento;\r\n        (document.querySelector('#upciudad') as HTMLInputElement).value = objDireccion.ciudad;\r\n        (document.querySelector('#updireccion') as HTMLInputElement).value = objDireccion.direccion;\r\n      });\r\n\r\n\r\n      document.querySelector('#formUpDireccion')?.addEventListener('submit', e=>{\r\n          e.preventDefault();\r\n          // verificar si se oprimio el btn eliminar o actualizar del modal actualizar direccion\r\n        });\r\n        \r\n\r\n      function eliminarClientes(e:Event){\r\n        let idcliente = (e.target as HTMLElement).parentElement!.id, info = (tablaClientes as any).page.info();\r\n        if((e.target as HTMLElement).tagName === 'I')idcliente = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n        indiceFila = (tablaClientes as any).row((e.target as HTMLElement).closest('tr')).index();\r\n        Swal.fire({\r\n            customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n            icon: 'question',\r\n            title: 'Desea eliminar el cliente?',\r\n            text: \"El cliente sera eliminado por completo.\",\r\n            showCancelButton: true,\r\n            confirmButtonText: 'Si',\r\n            cancelButtonText: 'No',\r\n        }).then((result:any) => {\r\n            if (result.isConfirmed) {\r\n                (async ()=>{ \r\n                    const datos = new FormData();\r\n                    datos.append('id', idcliente);\r\n                    try {\r\n                        const url = \"/admin/api/eliminarCliente\";\r\n                        const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                        const resultado = await respuesta.json();  \r\n                        if(resultado.exito !== undefined){\r\n                          (tablaClientes as any).row(indiceFila+info.start).remove().draw(); \r\n                          (tablaClientes as any).page(info.page).draw('page');\r\n                          Swal.fire(resultado.exito[0], '', 'success') \r\n                        }else{\r\n                            Swal.fire(resultado.error[0], '', 'error')\r\n                        }\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();//cierre de async()\r\n            }\r\n        });\r\n      }\r\n\r\n\r\n      btnCerrarUpDireccion.addEventListener('click', ()=>miDialogoUpDireccion.close());\r\n  \r\n  \r\n      function limpiarformdialog(){\r\n        (document.querySelector('#formCrearUpdateCliente') as HTMLFormElement)?.reset();\r\n      }\r\n      function cerrarDialogoExterno(event:Event) {\r\n        if (event.target === miDialogoCliente || event.target === miDialogoCrearDireccion || event.target === miDialogoUpDireccion || (event.target as HTMLInputElement).value === 'salir') {\r\n          miDialogoCliente.close();\r\n          miDialogoCrearDireccion.close();\r\n          miDialogoUpDireccion.close();\r\n          \r\n        }\r\n      }\r\n    }\r\n  \r\n  })();","(():void=>{\r\n\r\n    if(document.querySelector('.detallecliente')){\r\n\r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n\r\n        function clientesGraficas($url:string, $dato:string){\r\n            if(id!=null&&!Number.isNaN(id))\r\n                (async ()=>{\r\n                    try {\r\n                        const url = $url+id;\r\n                        const respuesta = await fetch(url); \r\n                        const resultado = await respuesta.json();\r\n                        if($dato == 'comprasXMes')comprasXMesXCliente(resultado);\r\n                        if($dato == 'ventasXCategorias')ventasXCategoriasXCliente(resultado);\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();\r\n        }\r\n\r\n        clientesGraficas('/admin/api/clientes/comprasXMesXCliente?id=', 'comprasXMes');\r\n        clientesGraficas('/admin/api/clientes/ventasXCategoriasXCliente?id=', 'ventasXCategorias');\r\n        \r\n\r\n        function comprasXMesXCliente(resultado:{periodo:string, ventas_totales:string}[]){\r\n            // Compras por mes\r\n            const ctxMes = (document.getElementById(\"chartComprasMes\") as HTMLCanvasElement).getContext('2d');\r\n            if (ctxMes) {\r\n                new Chart(ctxMes, {\r\n                type: \"line\",\r\n                data: {\r\n                    labels: resultado.map(x=>x.periodo),\r\n                    datasets: [{\r\n                    label: \"Compras\",\r\n                    data: resultado.map(x=>x.ventas_totales),\r\n                    borderColor: \"rgba(99, 102, 241, 1)\",\r\n                    backgroundColor: \"rgba(99, 102, 241, 0.2)\",\r\n                    tension: 0.4,\r\n                    fill: true,\r\n                    }]\r\n                },\r\n                options: { responsive: true }\r\n                });\r\n            }\r\n        }\r\n\r\n        function ventasXCategoriasXCliente(resultado:{categoria:string, idcategoria:string, unidades_vendidas:string, venta_total_categoria:string}[]){\r\n            // Categorías más compradas\r\n            const ctxCat = (document.getElementById(\"chartCategorias\") as HTMLCanvasElement).getContext('2d');\r\n            if (ctxCat) {\r\n                new Chart(ctxCat, {\r\n                type: \"doughnut\",\r\n                data: {\r\n                    labels: resultado.map(x=>x.categoria),\r\n                    datasets: [{\r\n                    data: resultado.map(x=>x.unidades_vendidas),\r\n                    backgroundColor: [\r\n                        \"rgba(99, 102, 241, 0.8)\",   // Indigo\r\n                        \"rgba(16, 185, 129, 0.8)\",   // Emerald\r\n                        \"rgba(249, 115, 22, 0.8)\",   // Orange\r\n                        \"rgba(107, 114, 128, 0.8)\"   // Gray\r\n                    ],\r\n                    }]\r\n                },\r\n                options: { responsive: true }\r\n                });\r\n            }\r\n        }\r\n\r\n    }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('modorapido')){\r\n\r\n        interface i_itemDetalle {\r\n            id:string, //id del registro de la tabla productosseparados\r\n            idcredito:string,\r\n            fk_producto: string,\r\n            idproducto?:string,\r\n            idunidadmedida:string,\r\n            tipoproducto:string,\r\n            tipoproduccion:string,\r\n            rendimientoestandar?:string,\r\n            factor?:number,\r\n            nombreproducto:string,\r\n            unidadmedida:string,\r\n            preciopersonalizado:string,\r\n            sku:string,\r\n            stockminimo?:string,\r\n\r\n            capital?:number,            //DATOS DEL CREDITO\r\n            abonoinicial?:number,      //abono inicial en el credito\r\n            saldopendiente?:number,\r\n            cantidadcuotas?:number,\r\n            interes?:string,           // 1 = si interes en el credito, 0 = no interes en el credito\r\n            interestotal?:number,      //interes total dlecredito en porcentaje\r\n            valorinterestotal?:number, //valor del interes total de credito\r\n            montototal?:number,\r\n            descuentocredito?:number,  //descuneto general en el credito\r\n            \r\n            costo:number,\r\n            valorunidad:number,\r\n            descuento:number,  //se calcula para productos nuevos agregados\r\n            cantidad:number,   //se calcula para productos nuevos agregados\r\n            base:number,       //se calcula para productos nuevos agregados\r\n            impuesto:string,\r\n            valorimp:number,   //se calcula para productos nuevos agregados\r\n            subtotal:number,   //se calcula para productos nuevos agregados\r\n            total:number,      //se calcula para productos nuevos agregados\r\n        }\r\n\r\n        interface i_allProducts {\r\n            id:string,  //id del producto\r\n            idunidadmedida:string, \r\n            nombre:string,\r\n            impuesto:string,\r\n            tipoproducto:string, \r\n            tipoproduccion:string, \r\n            sku:string, \r\n            unidadmedida:string, \r\n            preciopersonalizado:string,\r\n            rendimientoestandar:string, \r\n            stockminimo:string,\r\n            precio_compra:number,\r\n            precio_venta:number\r\n            habilitarventa:string, \r\n            visible:string,\r\n        }\r\n\r\n        interface Item {\r\n            id_impuesto: number,\r\n            facturaid: number,\r\n            basegravable: number,\r\n            valorimpuesto: number\r\n            }\r\n\r\n\r\n        let factimpuestos:Item[] = [];\r\n        let carrito:i_itemDetalle[]=[];\r\n        let allproducts:i_allProducts[] = [];\r\n        let filteredData: {id:string, text:string, tipo:string, tipoproducto:string, tipoproduccion:string, sku:string, unidadmedida:string}[];   //tipoproducto = 0 es producto simple,  1 = compuesto,  si no viene es subproducto, tipo=0 es producto(simple o compuesto), tipo=1 es subproducto\r\n        const valorTotal = {subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, total: 0}; //datos global de la venta\r\n        const dataCredit = {capital:0, abonoinicial:0, saldopendiente:0, cantidadcuotas:0, interes:'0', interestotal:0, valorinterestotal:0, montototal:0, descuentocredito: 0};\r\n\r\n        const constImp: {[key:string]: number} = {};\r\n        constImp['excluido'] = 0;\r\n        constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n        constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n        constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n        constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n        constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allproducts\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y compuestos\r\n                const respuesta = await fetch(url);\r\n                const resultado:i_allProducts[] = await respuesta.json();\r\n                filteredData = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1').map(item => ({ id: item.id, text: item.nombre, tipo:item.tipoproducto??'1', tipoproducto: item.tipoproducto, tipoproduccion: item.tipoproduccion, sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2();\r\n                allproducts = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1');\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        function activarselect2(){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });  \r\n        }\r\n\r\n    }\r\n\r\n})();","\r\n(()=>{\r\n    if(document.querySelector('.ventas')){\r\n\r\n      const POS = (window as any).POS;\r\n\r\n      const inputBuscar = document.querySelector<HTMLInputElement>('#buscarproducto');\r\n      const filtrocategorias = document.querySelectorAll('.filtrocategorias');  //los btns de las categorias\r\n      const btnCategorias = document.querySelector<HTMLButtonElement>('#btnCategorias');\r\n      const menuCategorias = document.querySelector<HTMLDivElement>('#menuCategorias');\r\n\r\n      var options = {\r\n        valueNames: [ 'card-producto', { data: ['categoria', 'code'] }],\r\n        page: 18,\r\n        pagination: true,\r\n      };\r\n      const productos = document.querySelectorAll<HTMLElement>('.producto');\r\n      if(productos.length)\r\n      var hackerList = new List('hacker-list', options);\r\n      POS.hackerList = hackerList;  //exportar\r\n\r\n      filtrocategorias.forEach(element => {\r\n        element.addEventListener('click', (e)=>{\r\n          const categoria:string = (e.target as HTMLElement).dataset.categoria!;\r\n          document.querySelector('#categorySelect')!.textContent = categoria;\r\n          if(hackerList)\r\n            hackerList.filter((item: any)=>{\r\n              hackerList.search('');\r\n              if(categoria === 'Todos')return true;\r\n              return item.values().categoria === categoria\r\n            });\r\n        });\r\n      });\r\n\r\n\r\n      inputBuscar?.addEventListener('keydown', (e) => {\r\n        if (e.key !== 'Enter') return;\r\n\r\n        e.preventDefault();\r\n\r\n        if (!hackerList) return;\r\n\r\n        const items = hackerList.visibleItems;\r\n\r\n        if (!items.length) return;\r\n\r\n        const productosku = items[0].elm as HTMLElement;\r\n        const products = POS.products as productsapi[];\r\n        const precio = products.find(x=>x.id == productosku.dataset.id)?.precio_venta;\r\n        POS.actualizarCarrito(productosku.dataset.id, 1, true, true, precio);\r\n\r\n        inputBuscar.value = '';\r\n        hackerList.search('');\r\n      });\r\n\r\n\r\n      //////--------  Apertura y cierre del btn Categorias\r\n\r\n      btnCategorias?.addEventListener('click', (e) => {\r\n        e.stopPropagation(); // evita cierre inmediato\r\n        menuCategorias?.classList.toggle('hidden');\r\n        if(!menuCategorias?.classList.contains('hidden'))document.addEventListener('click', cerrarMenuCategorias);\r\n      });\r\n      // cerrar al hacer click en una categoría\r\n      document.querySelectorAll('.filtrocategorias').forEach(el => {\r\n        el.addEventListener('click', () => {\r\n          menuCategorias?.classList.add('hidden');\r\n          document.removeEventListener('click', cerrarMenuCategorias);\r\n        });\r\n      });\r\n      // cerrar al hacer click fuera del menú\r\n      function cerrarMenuCategorias() {\r\n        menuCategorias?.classList.add('hidden');\r\n        document.removeEventListener('click', cerrarMenuCategorias);\r\n      }\r\n\r\n\r\n\r\n      //////---------------------------------------------------------------------------\r\n\r\n\r\n      const btnCarritoMovil = document.querySelector('#btnCarritoMovil') as HTMLButtonElement; //btn para abrir el modal del carrito de ventas en movil\r\n      const contenidocarrito = document.getElementById('contenidocarrito') as HTMLElement;\r\n      const contenedorDesktop = document.getElementById('contenedorDesktop') as HTMLDivElement;\r\n      const miDialogoCarritoMovil = document.getElementById('miDialogoCarritoMovil') as HTMLDialogElement;\r\n      const btnCerrarCarritoMovil = document.querySelector('#btnCerrarCarritoMovil') as HTMLButtonElement;\r\n      const screenWidth:number = window.innerWidth;\r\n\r\n      if(screenWidth<992)miDialogoCarritoMovil.appendChild(contenidocarrito);\r\n\r\n      window.addEventListener('resize', ()=>{\r\n        if (window.innerWidth >= 992) {\r\n          contenedorDesktop.appendChild(contenidocarrito);\r\n          miDialogoCarritoMovil.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        } else {\r\n          miDialogoCarritoMovil.appendChild(contenidocarrito);\r\n        }\r\n      });\r\n\r\n      // btn para abrir el carrito de ventas en movil\r\n      btnCarritoMovil?.addEventListener('click', (e)=>{\r\n        miDialogoCarritoMovil.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n      btnCerrarCarritoMovil.addEventListener('click', ()=>{\r\n        miDialogoCarritoMovil.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n      function cerrarDialogoExterno(event:Event) {\r\n        const f = event.target;\r\n        if (f === miDialogoCarritoMovil ) {\r\n          miDialogoCarritoMovil.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n\r\n\r\n      /*const paginador ={\r\n\r\n      }\r\n      POS.paginador = paginador;*/\r\n\r\n    }\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n  const POS = (window as any).POS;\r\n\r\n  interface getAdquirienteDian {\r\n    ReceiverEmail:string, \r\n    ReceiverName:string, \r\n    StatusCode:string\r\n  }\r\n\r\n  interface adquirientes {\r\n    id?:string,\r\n    type_document_identification_id:string,\r\n    identification_number:string,\r\n    business_name:string,\r\n    email:string,\r\n    address:string,\r\n    municipality_id?:string,\r\n    department_id?:string,\r\n    ciudad_nombre:string\r\n    type_organization_id:string,\r\n    type_regime_id:string,\r\n    phone:string\r\n  }\r\n\r\n  type municipalities = {\r\n        id:string,\r\n        department_id:string,\r\n        name:string,\r\n        code:string,\r\n  };\r\n  let cities:municipalities[]=[];\r\n\r\n  const facturarA = document.querySelector('#facturarA') as HTMLButtonElement;\r\n  const miDialogoFacturarA = document.querySelector('#miDialogoFacturarA') as any;\r\n  const formFacturarA = document.querySelector('#formFacturarA') as HTMLFormElement;\r\n  const documentinput = document.querySelector('#identification_number') as HTMLInputElement;\r\n  const btnBuscarAdquiriente = document.querySelector('#btnBuscarAdquiriente') as HTMLButtonElement;\r\n  const selectDepartments = document.querySelector('#department_id') as HTMLSelectElement;\r\n  const selectdCities = document.querySelector('#municipality_id') as HTMLSelectElement;\r\n  let customers:adquirientes[] = [];\r\n  let customersfiltrados:adquirientes[] = [], token:string|undefined;\r\n\r\n\r\n  (async ()=>{\r\n    const url = `/admin/api/filterAdquirientes`; \r\n    const respuesta = await fetch(url);\r\n    const resultado = await respuesta.json();\r\n    customers = resultado;\r\n    //formatearponentes(resultado);\r\n  })();\r\n\r\n  //consultar token\r\n  (async ()=>{\r\n    const url = `/admin/api/getCompaniesAll`; \r\n    const respuesta = await fetch(url);\r\n    const resultado:{id:string, identification_number:string, business_name:string, idsoftware:string, token:string, estado:string}[] = await respuesta.json();\r\n    token = resultado.find(x=>x.estado==='1')?.token;\r\n  })();\r\n\r\n  btnBuscarAdquiriente.addEventListener('click', (e:Event)=>{\r\n    if(documentinput.value.trim().length > 4 && token!=undefined){\r\n      console.log(documentinput.value.trim());\r\n      GetAcquirerDian(documentinput.value.trim());\r\n    }\r\n  });\r\n\r\n  const GetAcquirerDian = async (identificationnumber: string)=>{\r\n    try {\r\n          const url = \"https://apidianj2.com/api/ubl2.1/getAcquirer/13/\"+identificationnumber;  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {\r\n                                    method: 'GET',\r\n                                    headers: { \r\n                                      \"Accept\": \"application/json\", \r\n                                      \"Content-Type\": \"application/json\",\r\n                                      \"Authorization\": \"Bearer \"+token\r\n                                    },\r\n                                  }); \r\n          const resultado = await respuesta.json();\r\n          const {ReceiverEmail, ReceiverName, StatusCode}:getAdquirienteDian = resultado.data.GetAcquirerResult;\r\n          if(StatusCode === '200'){\r\n            (formFacturarA['business_name'] as HTMLInputElement).value = ReceiverName;\r\n            (formFacturarA['email'] as HTMLInputElement).value = ReceiverEmail;\r\n          }else{\r\n            msjAlert('error', 'No se encontro cliente en base de datos de la Dian', document.querySelector('#divmsjalertanoclienteDian') as HTMLElement);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n  }\r\n\r\n\r\n\r\n  //buscar adquiriente\r\n  documentinput.addEventListener('input', buscarAquiriente);\r\n\r\n  function buscarAquiriente(e:Event){\r\n      const busqueda:string = (e.target as HTMLInputElement).value;\r\n      if(busqueda.length > 3 && /^\\d+$/.test(busqueda)){\r\n          //const expresionregular = new RegExp(busqueda, \"i\");\r\n          customersfiltrados = customers.filter(document => { \r\n              if(document.identification_number.trim() === busqueda.trim()){\r\n                  return document;\r\n              }\r\n          });   \r\n      }else{\r\n          customersfiltrados = [];\r\n      }\r\n      mostrarAdquiriente();\r\n  }\r\n\r\n  function mostrarAdquiriente(){\r\n    if(customersfiltrados.length>0){\r\n      $('#type_document_identification_id').val(customersfiltrados[0].type_document_identification_id);\r\n      (document.querySelector('#business_name') as HTMLInputElement).value = customersfiltrados[0].business_name;\r\n      (document.querySelector('#email') as HTMLInputElement).value = customersfiltrados[0].email;\r\n      (document.querySelector('#address') as HTMLInputElement).value = customersfiltrados[0].address;\r\n      if(customersfiltrados[0].department_id){\r\n        $('#department_id').val(customersfiltrados[0].department_id);\r\n        imprimirCiudades(customersfiltrados[0].department_id);\r\n      }\r\n      //$('#municipality_id').val(customersfiltrados[0].municipality_id);\r\n      $('#type_organization_id').val(customersfiltrados[0].type_organization_id);\r\n      $('#type_regime_id').val(customersfiltrados[0].type_regime_id);\r\n      (document.querySelector('#phone') as HTMLInputElement).value = customersfiltrados[0].phone;\r\n    }else{\r\n      $('#type_document_identification_id').val(\"\");\r\n      (document.querySelector('#business_name') as HTMLInputElement).value = '';\r\n      (document.querySelector('#email') as HTMLInputElement).value = '';\r\n      (document.querySelector('#address') as HTMLInputElement).value = '';\r\n      $('#department_id').val(\"\");\r\n      $('#municipality_id').val(\"\");\r\n      $('#type_organization_id').val(\"\");\r\n      $('#type_regime_id').val(\"\");\r\n      (document.querySelector('#phone') as HTMLInputElement).value = \"\";\r\n    }\r\n  }\r\n\r\n\r\n\r\n  /////       Obtener municipio segun departamento        ///////\r\n  selectDepartments?.addEventListener('change', (e:Event)=>{\r\n    const x:HTMLOptionElement = (e.target as HTMLOptionElement);\r\n    imprimirCiudades(x.value);\r\n  });\r\n\r\n  function imprimirCiudades(x:string){\r\n    (async ()=>{\r\n      try {\r\n        const url = \"/admin/api/citiesXdepartments?id=\"+x; //llamado a la API REST y se trae las cities segun cliente elegido\r\n        const respuesta = await fetch(url); \r\n        const resultado = await respuesta.json(); \r\n        if(resultado.error){\r\n          Swal.fire(resultado.error[0], '', 'error')\r\n        }else{\r\n          cities = resultado;\r\n          addCitiesToSelect(cities);\r\n        }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n  }\r\n  \r\n  function addCitiesToSelect<T extends {id:string, department_id:string, name:string, code:string}>(addrs: T[]):void{\r\n    while(selectdCities?.firstChild)selectdCities.removeChild(selectdCities?.firstChild);\r\n    addrs.forEach(x =>{\r\n      const option = document.createElement('option');\r\n      option.textContent = x.name;\r\n      option.value = x.id;\r\n      option.dataset.code = x.code;\r\n      option.dataset.department_id = x.department_id;\r\n      selectdCities.appendChild(option);\r\n    });\r\n    if(customersfiltrados.length>0&&customersfiltrados[0].municipality_id)$('#municipality_id').val(customersfiltrados[0].municipality_id);\r\n  }\r\n\r\n\r\n  ///////////////////// evento al btn facturar A /////////////////////\r\n  facturarA.addEventListener('click', (e:Event)=>{\r\n    miDialogoFacturarA.showModal();\r\n    document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n  });\r\n\r\n   \r\n  formFacturarA.addEventListener('submit', (e:Event)=>{\r\n    e.preventDefault();\r\n    const data = new FormData(formFacturarA);\r\n    const datosAdquiriente: Record<string, FormDataEntryValue> = Object.fromEntries(data.entries());\r\n    miDialogoFacturarA.close();\r\n    document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n\r\n    const identification = datosAdquiriente.identification_number as string;\r\n    const requiereEmail = identification && identification!='222222222222';\r\n    // Validar email solo si identification_number es distinto de 222222222222 y no vacío\r\n    if (requiereEmail && !validarEmail(datosAdquiriente.email as string)) {\r\n        Swal.fire(\"Correo incorrecto\", \"Debe ingresar un email válido o enviar a consumidor final o generico: 222222222222\", \"error\");\r\n        return; // detiene el proceso\r\n    }\r\n\r\n    if(identification && identification!='222222222222'){\r\n      const dv = getDgv(Number(identification));\r\n      datosAdquiriente.dv = dv.toString();\r\n    }\r\n\r\n    console.log(datosAdquiriente);\r\n\r\n    POS.gestionarAdquiriente.datosAdquiriente = datosAdquiriente; //guarda en el objeto global\r\n    //guardar adquiriente en DB.\r\n    guardarAdquiriente(datosAdquiriente);\r\n  });\r\n\r\n  function validarEmail(correo: string): boolean {\r\n      const regex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;\r\n      return regex.test(correo);\r\n  }\r\n\r\n\r\n  async function guardarAdquiriente(datosAdquiriente: Record<string, FormDataEntryValue>){\r\n    try {\r\n          const url = \"/admin/api/guardarAdquiriente\";  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {\r\n                                    method: 'POST',\r\n                                    headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                    body: JSON.stringify(datosAdquiriente)\r\n                                  }); \r\n          const resultado = await respuesta.json();\r\n          //añadir o actualizar al arreglo customers\r\n          if(resultado.tipo == \"crear\"){\r\n            customers = [...customers, resultado.obj];\r\n          }else{\r\n            /// actualizar el arregle del adquiriente o customers ///\r\n            customers.forEach(a=>{if(a.identification_number == resultado.obj.identification_number)a = Object.assign(a, resultado.obj);});\r\n          }\r\n          datosAdquiriente.id = resultado.obj.id;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n  }\r\n  \r\n\r\n  const gestionarAdquiriente = {  //objeto a exportar\r\n    miDialogoFacturarA,\r\n    datosAdquiriente: {} //inicializar \r\n  };\r\n\r\n  POS.gestionarAdquiriente = gestionarAdquiriente;\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n  const productosAPI = {\r\n\r\n    async getProductosAPI(){\r\n      try {\r\n          const url = \"/admin/api/allproducts\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const products = await respuesta.json();\r\n          return products;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n    \r\n  };\r\n\r\n  (window as any).POS.productosAPI = productosAPI;\r\n\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const btnAddCliente = document.querySelector('#addcliente') as HTMLElement;\r\n    const btnAddDir = document.querySelector('#adddir') as HTMLElement;\r\n    const miDialogoAddCliente = document.querySelector('#miDialogoAddCliente') as any;\r\n    //const miDialogoAddDir = document.querySelector('#miDialogoAddDir') as any;\r\n    const selectCliente = document.querySelector('#selectCliente') as HTMLSelectElement;\r\n    const dirEntrega = document.querySelector('#direccionEntrega')! as HTMLSelectElement;\r\n\r\n  const gestionClientes = {\r\n    selectCliente,\r\n    dirEntrega,\r\n    miDialogoAddCliente,\r\n    //miDialogoAddDir,\r\n\r\n    clientes(){\r\n        \r\n        //////////// evento al boton añadir cliente nuevo //////////////\r\n        btnAddCliente?.addEventListener('click', (e)=>{\r\n            miDialogoAddCliente.showModal();\r\n            ($('#selectCliente') as any).select2({\r\n                dropdownParent: $('#miDialogoAddCliente'),\r\n                placeholder: \"Seleccionar el cliente\",\r\n                maximumSelectionLength: 1\r\n            });\r\n            document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });\r\n        //////////// evento al boton añadir nueva direccion //////////////\r\n        /*btnAddDir?.addEventListener('click', (e)=>{\r\n            miDialogoAddDir.showModal();\r\n            document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });*/\r\n        //////////// evento al btn submit del formulario add nuevo cliente //////////////\r\n        document.querySelector('#formAddCliente')?.addEventListener('submit', e=>{\r\n            e.preventDefault();\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('idcliente', selectCliente?.value??null); //id del cliente\r\n                datos.append('nombre', (document.querySelector('#nombreclientenuevo') as HTMLInputElement).value);\r\n                datos.append('apellido', (document.querySelector('#clientenuevoapellido') as HTMLInputElement).value || '  ');\r\n                datos.append('tipodocumento', (document.querySelector('#tipodocumento') as HTMLInputElement).value);\r\n                datos.append('telefono', (document.querySelector('#telefono') as HTMLInputElement).value);\r\n                datos.append('iddireccion', (document.querySelector('#direccionEntrega') as HTMLSelectElement).value);\r\n                //datos.append('idtarifa', (document.querySelector('#clientenuevotarifa') as HTMLSelectElement).value);\r\n                datos.append('tipodocumento', (document.querySelector('#tipodocumento') as HTMLInputElement).value);\r\n                datos.append('identificacion', (document.querySelector('#identificacion') as HTMLInputElement).value);\r\n                datos.append('email', (document.querySelector('#clientenuevoemail') as HTMLInputElement).value);\r\n                datos.append('departamento', (document.querySelector('#departamento') as HTMLInputElement).value||'No definido');\r\n                datos.append('ciudad', (document.querySelector('#ciudad') as HTMLInputElement).value || 'No definido');\r\n                datos.append('direccion', (document.querySelector('#clientenuevodireccion') as HTMLInputElement).value);\r\n                try {\r\n                    let url = \"/admin/api/apiCrearCliente\";\r\n                    if(selectCliente.value!=='')url = \"/admin/api/actualizarCliente\";\r\n\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    if(selectCliente.value=='')addClienteSelect(resultado.nextID);\r\n                    if(selectCliente.value!=='')$('#selectCliente').val(resultado.nextID).trigger('change');\r\n                    //POS.limpiarformdialog();\r\n                    }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n            miDialogoAddCliente.close();\r\n            document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });\r\n        /////////////// añadir cliente al select despues de crearse ///////////////////\r\n        function addClienteSelect(clienteID:string): void{\r\n            const option = document.createElement('option');\r\n            option.textContent = (document.querySelector('#nombreclientenuevo') as HTMLInputElement).value + \" \" + (document.querySelector('#clientenuevoapellido') as HTMLInputElement).value;\r\n            option.value = clienteID;\r\n            option.dataset.tipodocumento = (document.querySelector('#tipodocumento') as HTMLInputElement).value;\r\n            option.dataset.identidad = (document.querySelector('#identificacion') as HTMLInputElement).value;\r\n            selectCliente?.appendChild(option);\r\n            $('#selectCliente').val(clienteID).trigger('change'); // seleccionar el cliente nuevo, en el select y dispara evento\r\n        }\r\n        \r\n        //evento 'cambio' al selecionar cliente, tambien se ejecuta cuando se crea cliente nuevo//\r\n        $(\"#selectCliente\").on('change', (e)=>{\r\n            const idcli = (e.target as HTMLInputElement).value;\r\n            if(idcli){\r\n                (async ()=>{\r\n                    try {\r\n                        const url = \"/admin/api/direccionesXcliente?id=\"+idcli; //llamado a la API REST y se trae el cliente y sus direcciones direccionescontrolador\r\n                        const respuesta = await fetch(url); \r\n                        const resultado = await respuesta.json();\r\n                        (document.querySelector('#nombreclientenuevo') as HTMLInputElement).value = resultado.nombre;\r\n                        (document.querySelector('#clientenuevoapellido') as HTMLInputElement).value = resultado.apellido;\r\n                        (document.querySelector('#telefono') as HTMLInputElement).value =  resultado.telefono;\r\n                        addDireccionSelect(resultado);\r\n                        (document.querySelector('#tipodocumento') as HTMLSelectElement).value = resultado.tipodocumento;\r\n                        (document.querySelector('#identificacion') as HTMLInputElement).value = resultado.identificacion;\r\n                        (document.querySelector('#clientenuevoemail') as HTMLInputElement).value = resultado.email;\r\n                        (document.querySelector('#resumenCliente') as HTMLParagraphElement).textContent = resultado.nombre+' '+resultado.apellido;\r\n                        (document.querySelector('#badgeEstado') as HTMLParagraphElement).textContent = 'SELECCIONADO';\r\n                        (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.remove('bg-gray-100', 'text-gray-700');\r\n                        (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.add('bg-green-100', 'text-green-600');\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();   \r\n            }else{\r\n                (document.querySelector('#resumenCliente') as HTMLParagraphElement).textContent = 'Seleccionar cliente';\r\n                (document.querySelector('#badgeEstado') as HTMLParagraphElement).textContent = 'SIN CLIENTE';\r\n                (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.remove('bg-green-100', 'text-green-600');\r\n                (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.add('bg-gray-100', 'text-gray-700');\r\n            }\r\n        });\r\n\r\n        ////// añade direccion al select de direcciones, cuando se selecciona o se agrega un cliente o si se agrega un nueva direccion/////\r\n        function addDireccionSelect<T extends {id:string, nombre:string, apellido:string, telefono:string, identificacion:string, email:string, direcciones:{id:string, idcliente:string, idtarifa:string, tarifa:{id:string, idcliente:string, nombre:string, valor:string}, direccion:string, departamento:string, ciudad:string}[]}>(addrs: T):void{\r\n            while(dirEntrega?.firstChild)dirEntrega.removeChild(dirEntrega?.firstChild);\r\n            const setTarifas = new Set();\r\n            POS.tarifas.length = 0;\r\n            console.log(addrs);\r\n            addrs.direcciones.forEach(dir =>{\r\n                const option = document.createElement('option');\r\n                option.textContent = dir.direccion;\r\n                option.value = dir.id;\r\n                option.dataset.idcliente = dir.idcliente;\r\n                option.dataset.idtarifa = dir.idtarifa;\r\n                option.dataset.ciudad = dir.ciudad;\r\n                dirEntrega.appendChild(option);\r\n                dir.tarifa.idcliente = dir.idcliente;\r\n                if(!setTarifas.has(dir.tarifa.id)){\r\n                POS.tarifas = [...POS.tarifas, dir.tarifa];\r\n                setTarifas.add(dir.tarifa.id);\r\n                }\r\n            });\r\n            setTarifas.clear();\r\n            POS.printTarifaEnvio();\r\n            POS.valorCarritoTotal();\r\n            (document.querySelector('#departamento') as HTMLInputElement).value = addrs.direcciones[0]?.departamento??'No especificado';\r\n            (document.querySelector('#ciudad') as HTMLInputElement).value = addrs.direcciones[0]?.ciudad??'No especificado';\r\n        }\r\n\r\n        ///////// Evento al select de direcciones ////////////\r\n        dirEntrega?.addEventListener('change', (e)=>{\r\n            const select = (e.target as HTMLSelectElement);\r\n            const x:string = select.options[select.selectedIndex].dataset.ciudad||'';\r\n            (document.querySelector('#ciudadEntrega') as HTMLInputElement).value = x;\r\n            POS.printTarifaEnvio();\r\n            POS.valorCarritoTotal();\r\n        });\r\n\r\n        ////////////////// evento al btn submit del formulario add direccion //////////////////////\r\n        /*document.querySelector('#formAddDir')?.addEventListener('submit', e=>{\r\n            e.preventDefault();\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('idcliente', selectCliente.value);\r\n                datos.append('departamento', (document.querySelector('#adddepartamento') as HTMLInputElement).value);\r\n                datos.append('ciudad', (document.querySelector('#addciudad') as HTMLInputElement).value);\r\n                datos.append('direccion', (document.querySelector('#adddireccion') as HTMLInputElement).value);\r\n                datos.append('idtarifa', (document.querySelector('#tarifa') as HTMLSelectElement).value);\r\n                try {\r\n                    const url = \"/admin/api/addDireccionCliente\";  //direccionescontrolador\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    addDireccionSelect(resultado.direcciones);\r\n                    }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n            //miDialogoAddDir.close();\r\n            //document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });*/\r\n        \r\n    }\r\n    \r\n  };\r\n\r\n  (window as any).POS.gestionClientes = gestionClientes;\r\n\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas')&&!document.querySelector('.crearseparado'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const btndescuento = document.querySelector('#btndescuento') as HTMLButtonElement;\r\n    const miDialogoDescuento = document.querySelector('#miDialogoDescuento') as any;\r\n    const tipoDescts = document.querySelectorAll<HTMLInputElement>('input[name=\"tipodescuento\"]'); //radio buttom\r\n    const inputDescuento = document.querySelector('#inputDescuento') as HTMLInputElement;\r\n    const inputDescuentoClave = document.querySelector('#inputDescuentoClave') as HTMLInputElement;\r\n    let valorMax = 0;\r\n    \r\n    interface clavesApi {\r\n      clave:string,\r\n      valor_default:string|null,\r\n      valor_final:string|null,\r\n      valor_local:string|null\r\n    };\r\n\r\n    let clavedcto:clavesApi[];\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          clavedcto = resultado;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n    \r\n    btndescuento?.addEventListener('click', ()=>{\r\n      if(POS.carrito.length){\r\n        valorMax = POS.valorTotal.subtotal;\r\n        //validar que si al reducir los productos o aumentar recalcular el porcentaje\r\n        miDialogoDescuento.showModal();\r\n        document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n    /////////////////////  logica del descuento  //////////////////////////\r\n    tipoDescts.forEach(desc=>{ //evento a los radiobutton\r\n      desc.addEventListener('change', (e:Event)=>{\r\n        if((e.target as HTMLInputElement).value === \"porcentaje\"){\r\n          valorMax = 100;\r\n          inputDescuento.value = '';\r\n        }\r\n        if((e.target as HTMLInputElement).value === \"valor\"){\r\n          inputDescuento.value = '';\r\n          valorMax = POS.valorTotal.subtotal;\r\n        }\r\n      });\r\n    });\r\n\r\n    inputDescuento?.addEventListener('input', (e)=>{\r\n      var valorInput:number = Number((e.target as HTMLInputElement).value);\r\n      if(valorInput > valorMax){\r\n        inputDescuento.value = valorMax+'';\r\n        valorInput = valorMax; \r\n      }\r\n    });\r\n\r\n    document.querySelector('#formDescuento')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      const valorInput:number = Number(inputDescuento.value);\r\n      if(tipoDescts[0].checked){  //tipo valor\r\n        POS.valorTotal.dctox100 = Math.round((valorInput*100)/POS.valorTotal.subtotal);  // valor en porcentaje\r\n        POS.valorTotal.descuento = valorInput;  //valor del dcto\r\n      }\r\n      if(tipoDescts[1].checked){ //tipo porcentaje\r\n        POS.valorTotal.descuento = (POS.valorTotal.subtotal*valorInput)/100;  //valor descontado\r\n        POS.valorTotal.dctox100 = valorInput;  //valor en porcentaje\r\n      }\r\n      //validar en backend password\r\n      const v:number = validarPasswordDcto();\r\n      if(!v)return;\r\n      \r\n      POS.valorTotal.total = POS.valorTotal.subtotal - POS.valorTotal.descuento + POS.valorTotal.valortarifa;\r\n      document.querySelector('#total')!.textContent = '$ '+POS.valorTotal.total.toLocaleString();\r\n      (document.querySelector('#descuento') as HTMLElement).textContent = '$'+POS.valorTotal.descuento.toLocaleString();\r\n      miDialogoDescuento.close();\r\n      document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    });\r\n    \r\n    function validarPasswordDcto():number{\r\n      const clave = clavedcto.find(c => c.clave=='clave_para_agregar_descuento');\r\n      if(clave?.valor_final!==null && inputDescuentoClave.value !== clave?.valor_final){\r\n        msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalertaClaveDcto') as HTMLElement));\r\n        return 0;\r\n      }\r\n      return 1;\r\n    }\r\n    \r\n    const gestionarDescuentos = { miDialogoDescuento }\r\n\r\n    POS.gestionarDescuentos = gestionarDescuentos;\r\n    \r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas')&&!document.querySelector('.crearseparado'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const mediospago = document.querySelectorAll<HTMLInputElement>('.mediopago');\r\n    const interes = document.querySelector('#interes') as HTMLSelectElement;\r\n    const abonoinicial = (document.querySelector('#abonoinicial') as HTMLInputElement);\r\n    const cantidadcuotas = (document.querySelector('#cantidadcuotas') as HTMLInputElement);\r\n    //let tipoventa:string=\"Contado\";\r\n    let valoresCredito = {capital:0, abonoinicial:0, cantidadcuotas:1, montocuota:0, frecuenciapago:1, interes:0, interestotal:0, valorinterestotal:0, valorinteresxcuota:0, montototal:0};\r\n\r\n    //eventos a los inputs medios de pago\r\n    mediospago.forEach(m=>{m.addEventListener('input', (e)=>{ calcularmediospago(e);});});\r\n\r\n    /////////////////////  evento al input recibido  //////////////////////////\r\n    document.querySelector<HTMLInputElement>('#recibio')?.addEventListener('input', (e)=>{\r\n      calcularCambio((e.target as HTMLInputElement).value);\r\n    });\r\n    \r\n    const gestionSubirModalPagar = {\r\n        \r\n      subirModalPagar(){\r\n        //initvaloresCredito();\r\n        document.querySelector('#totalPagar')!.textContent = `${POS.valorTotal.total.toLocaleString()}`;\r\n        //como se puede cerrar el modal y aumentar los productos, hay calcular los inputs\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{\r\n            if(index>0)totalotrosmedios += parseInt(item.value.replace(/[,.]/g, ''));\r\n        });\r\n\r\n        if(POS.valorTotal.total<totalotrosmedios){\r\n            totalotrosmedios = 0;\r\n            POS.mapMediospago.clear();\r\n            $('.mediopago').val(0);\r\n        }\r\n        if(POS.tipoventa == \"Contado\"){\r\n            (document.querySelector('.Efectivo')! as HTMLInputElement).value =  `${(POS.valorTotal.total-totalotrosmedios).toLocaleString()}`;\r\n            POS.mapMediospago.set('1', POS.valorTotal.total-totalotrosmedios); //inicialmente el valor total se establece para efectivo\r\n        }\r\n        if(POS.valorTotal.total-totalotrosmedios == 0 && POS.mapMediospago.has('1'))POS.mapMediospago.delete('1');\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n        if(POS.tipoventa == \"Credito\")calculoTasaInteres();\r\n        if(POS.tipoventa == \"Contado\")initvaloresCredito();\r\n      },\r\n      calculoTasaInteres,\r\n      valoresCredito\r\n      \r\n    };\r\n\r\n\r\n    function initvaloresCredito(){\r\n      /*valoresCredito.capital = POS.valorTotal.total;  //inicializar el capital en el obj\r\n      valoresCredito.cantidadcuotas = Number(cantidadcuotas.value);\r\n      valoresCredito.montocuota = (valoresCredito.capital - valoresCredito.abonoinicial)/valoresCredito.cantidadcuotas;\r\n      valoresCredito.interes = 0;  //No aplicar interes\r\n      valoresCredito.interestotal = 0;  // 0% de interes\r\n      valoresCredito.valorinterestotal = 0; //0$ de interes total de la factura\r\n      valoresCredito.valorinteresxcuota = 0;  //0$ de interes de cada cuota\r\n      valoresCredito.montototal = valoresCredito.capital;\r\n      (document.querySelector('#montocuota') as HTMLInputElement).value = valoresCredito.montocuota+'';*/\r\n      valoresCredito.capital=0; \r\n      valoresCredito.abonoinicial=0;\r\n      valoresCredito.cantidadcuotas=1;\r\n      valoresCredito.montocuota=0;\r\n      valoresCredito.frecuenciapago=1,\r\n      valoresCredito.interes=0;\r\n      valoresCredito.interestotal=0;\r\n      valoresCredito.valorinterestotal=0;\r\n      valoresCredito.valorinteresxcuota=0;\r\n      valoresCredito.montototal=0;\r\n    }\r\n\r\n    \r\n    function calcularmediospago(e:Event){\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{ //sumar todos los medios de pago menos el efectivo\r\n          if(index>0&&POS.tipoventa==\"Contado\" || POS.tipoventa==\"Credito\")totalotrosmedios += parseInt(item.value.replace(/[,.]/g, ''));\r\n        });\r\n        if(totalotrosmedios<=POS.valorTotal.total&&POS.tipoventa == \"Contado\" || totalotrosmedios<=valoresCredito.abonoinicial&&POS.tipoventa == \"Credito\"){\r\n          if(POS.tipoventa == \"Contado\"){\r\n            POS.mapMediospago.set('1', POS.valorTotal.total-totalotrosmedios);\r\n            if(POS.valorTotal.total-totalotrosmedios == 0 && POS.mapMediospago.has('1'))POS.mapMediospago.delete('1'); //se elimina medio de pago efectivo\r\n          }\r\n          POS.mapMediospago.set((e.target as HTMLInputElement).id, parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, '')));\r\n          if((e.target as HTMLInputElement).value == '0' && POS.mapMediospago.has((e.target as HTMLInputElement).id))POS.mapMediospago.delete((e.target as HTMLInputElement).id);\r\n        }else{ //si la suma de los medios de pago superan el valor total, toma el ultimo input digitado y lo reestablece a su ultimo valor\r\n          if(POS.mapMediospago.has((e.target as HTMLInputElement).id)){\r\n            (e.target as HTMLInputElement).value = POS.mapMediospago.get((e.target as HTMLInputElement).id).toLocaleString();\r\n          }else{\r\n            (e.target as HTMLInputElement).value = '0';\r\n          }\r\n        }\r\n        if(POS.tipoventa == \"Contado\"){\r\n          mediospago[0].value = (POS.mapMediospago.get('1')??0).toLocaleString();  //medio de pago en efectivo\r\n        }\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n    }\r\n\r\n    function calcularCambio(recibido:string):void{\r\n      recibido = recibido.replace(/[,.]/g, '');\r\n      if(Number(recibido)>POS.mapMediospago.get('1')){\r\n        (document.querySelector('#cambio') as HTMLElement).textContent = (Number(recibido)-POS.mapMediospago.get('1')).toLocaleString()+'';\r\n        return;\r\n      }\r\n      (document.querySelector('#cambio') as HTMLElement).textContent = '0';\r\n    }\r\n\r\n\r\n    ////////////////////  CALCULO DE VALORES DEL CREDITO  //////////////////////\r\n\r\n    interes.addEventListener('change', e=>calculoTasaInteres());\r\n    cantidadcuotas.addEventListener('input', e=>calculoTasaInteres());\r\n    abonoinicial.addEventListener('input', e=>calculoTasaInteres());\r\n\r\n    function calculoTasaInteres(){\r\n      let creditofinal = recalcularCapitalXAbono(); //capital inicial - abono\r\n      initMediosPagos();\r\n      valoresCredito.cantidadcuotas = Number(cantidadcuotas.value);\r\n      if(cantidadcuotas.value == '1' || (interes.value == '0' || interes.value == '')){\r\n        (document.querySelector('#montocuota') as HTMLInputElement).value =  (Math.ceil((creditofinal/valoresCredito.cantidadcuotas)*100)/100)+'';\r\n        //(document.querySelector('#interestotal') as HTMLInputElement).value = '0';\r\n        //(document.querySelector('#valorinteresxcuota') as HTMLInputElement).value = '0';\r\n        //(document.querySelector('#valorinterestotal') as HTMLInputElement).value = '0';\r\n        //(document.querySelector('#montototal') as HTMLInputElement).value = creditofinal.toLocaleString();\r\n        valoresCredito.montocuota = (Math.ceil((creditofinal/valoresCredito.cantidadcuotas)*100)/100);\r\n        valoresCredito.interestotal = 0;\r\n        valoresCredito.valorinteresxcuota = 0;\r\n        valoresCredito.valorinterestotal = 0;\r\n        valoresCredito.montototal = creditofinal;\r\n      }\r\n      if(cantidadcuotas.value !== '1'&&interes.value === '1'){\r\n        const valorInteres = creditofinal*0.02*valoresCredito.cantidadcuotas;\r\n        const total = creditofinal + valorInteres;\r\n        const valorxcuota = Math.ceil((total/valoresCredito.cantidadcuotas)*100)/100;\r\n        (document.querySelector('#montocuota') as HTMLInputElement).value = valorxcuota+'';\r\n        //(document.querySelector('#interestotal') as HTMLInputElement).value = 2*valoresCredito.cantidadcuotas+''; //porcentaje de interes total\r\n        //(document.querySelector('#valorinteresxcuota') as HTMLInputElement).value = valorInteres/valoresCredito.cantidadcuotas+'';\r\n        //(document.querySelector('#valorinterestotal') as HTMLInputElement).value = valorInteres.toLocaleString();  //valor del interes total del credito\r\n        //(document.querySelector('#montototal') as HTMLInputElement).value = total.toLocaleString();  //valor total del credito\r\n        valoresCredito.interes = 1;\r\n        valoresCredito.montocuota = valorxcuota;\r\n        valoresCredito.interestotal = 2*valoresCredito.cantidadcuotas;\r\n        valoresCredito.valorinteresxcuota = valorInteres/valoresCredito.cantidadcuotas;\r\n        valoresCredito.valorinterestotal = valorInteres;\r\n        valoresCredito.montototal = total;\r\n      }\r\n      //(document.querySelector('#capitalinicial') as HTMLInputElement).value = capital.value.toLocaleString();\r\n      //(document.querySelector('#abono') as HTMLInputElement).value = Number(abonoinicial.value).toLocaleString();\r\n      //(document.querySelector('#capitalFinanciado') as HTMLInputElement).value = creditofinal+'';\r\n      \r\n    }\r\n\r\n    function recalcularCapitalXAbono():number{\r\n      const capital = POS.valorTotal.total;\r\n      let abono = Number(abonoinicial.value??0);\r\n      const capitalinicial:number = capital;\r\n      let creditofinal:number = capitalinicial;\r\n      if(capital>0){\r\n        if(abono < capitalinicial){\r\n          creditofinal = capitalinicial-abono;\r\n        }else{\r\n          abonoinicial.value = '0';\r\n        }\r\n      }\r\n      valoresCredito.capital = capital;\r\n      valoresCredito.abonoinicial = abono;\r\n      document.querySelector('#valorAbono')!.textContent = abono.toLocaleString();\r\n      return creditofinal;\r\n    }\r\n\r\n\r\n    function initMediosPagos(){\r\n      mediospago.forEach(z=>z.value = '0');\r\n      POS.mapMediospago.clear();\r\n    }\r\n\r\n    POS.gestionSubirModalPagar = gestionSubirModalPagar;\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const btnotros = document.querySelector('#btnotros') as HTMLButtonElement;  //btn de otros\r\n    const miDialogoOtrosProductos = document.querySelector('#miDialogoOtrosProductos') as any;\r\n    let otrosproductos:{id:number, nombre:string, cantidad:number, valorunidad:number, total:number}={\r\n      id: 0,\r\n      nombre: '',\r\n      cantidad: 0,\r\n      valorunidad: 0,\r\n      total: 0\r\n    }\r\n\r\n    ///////////////////// Evento al btn Otros /////////////////////////\r\n    btnotros.addEventListener('click', (e:Event)=>{\r\n      miDialogoOtrosProductos.showModal();\r\n      document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    });\r\n\r\n    const gestionOtrosProductos = {\r\n      miDialogoOtrosProductos,  \r\n      otrosproductos(){\r\n\r\n        /////////////////////Evento al formulario de agregar otros productos //////////////////////\r\n        document.querySelector('#formOtrosProductos')?.addEventListener('submit', (e:Event)=>{\r\n            e.preventDefault();\r\n            const formelements = (e.target as HTMLFormElement).elements;\r\n            const impuesto = (formelements.namedItem('porcentaje_de_impuesto') as HTMLSelectElement).value;\r\n            const cantidadotros = Number((formelements.namedItem('cantidadotros') as HTMLInputElement).value);\r\n            const preciootros = Number((formelements.namedItem('preciootros') as HTMLInputElement).value);\r\n            \r\n            otrosproductos!.id += -1 ;\r\n            otrosproductos!.nombre = (formelements.namedItem('nombreotros') as HTMLInputElement).value;\r\n            otrosproductos!.cantidad = cantidadotros;\r\n            otrosproductos!.valorunidad = preciootros/cantidadotros;\r\n            otrosproductos!.total = preciootros;\r\n            \r\n            POS.products.push({\r\n                ID: otrosproductos!.id+'',\r\n                id: otrosproductos!.id+'', \r\n                idcategoria: '-1',\r\n                idunidadmedida: '1',\r\n                nombre: otrosproductos!.nombre,\r\n                foto: 'na',\r\n                impuesto: impuesto==''?null:impuesto, //impuesto en %\r\n                marca: 'na',\r\n                tipoproducto: '-1', // 0 = simple,  1 = compuesto\r\n                tipoproduccion: '-1', //0 = inmediato, 1 = construccion\r\n                codigo: '-1',\r\n                unidadmedida: 'Unidad',\r\n                descripcion: 'na',\r\n                peso: 'na',\r\n                medidas: 'na',\r\n                color: 'na',\r\n                funcion: 'na',\r\n                uso: 'na',\r\n                fabricante: 'na',\r\n                garantia: 'na',\r\n                stock: '0',\r\n                stockminimo: '1',\r\n                categoria: 'na',\r\n                rendimientoestandar: '1',\r\n                precio_compra: '0',\r\n                precio_venta: otrosproductos!.valorunidad+'',\r\n                fecha_ingreso: '',\r\n                estado: '1',\r\n                visible: '1'\r\n            });\r\n\r\n            POS.actualizarCarrito(otrosproductos.id+'', cantidadotros, false, false, otrosproductos!.valorunidad+'');\r\n            miDialogoOtrosProductos.close();\r\n            document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n            (e.target as HTMLFormElement).reset();\r\n        });\r\n\r\n      }\r\n    };\r\n\r\n    (window as any).POS.gestionOtrosProductos = gestionOtrosProductos;\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n  const POS = (window as any).POS;\r\n\r\n  const miDialogoPreciosAdicionales = document.querySelector('#miDialogoPreciosAdicionales') as any;\r\n  const aplicarprecioadicional = document.querySelector('#aplicarprecioadicional') as HTMLButtonElement;\r\n\r\n  function cargarPreciosAdicionales(id:string) {\r\n    const listaPrecios = document.querySelector('#listaPrecios') as HTMLElement;\r\n    const products = POS.products as productsapi[];\r\n    const producto = products.find(x=>x.id==id);\r\n\r\n    while(listaPrecios.firstChild)listaPrecios.removeChild(listaPrecios.firstChild);\r\n\r\n    producto?.preciosadicionales.forEach(precio=>{\r\n      const preciohtml = `<label class=\"flex justify-between items-center p-4 rounded-xl bg-indigo-50 dark:bg-indigo-950/30 border border-indigo-200 dark:border-indigo-800 cursor-pointer hover:bg-indigo-100 dark:hover:bg-indigo-900/40 transition\">\r\n                          <div class=\"flex items-center gap-3\">\r\n                              <input type=\"radio\" class=\"w-5 h-5 text-indigo-600 focus:ring-indigo-500 inputprecioadicional\" data-precio=\"${id}\"  name=\"precioSeleccionado\" value=\"${precio.precio}\">\r\n                              <span class=\"text-gray-900 dark:text-gray-100 text-lg font-medium\">Precio adicional</span>\r\n                          </div>\r\n                          <span class=\"text-gray-800 dark:text-gray-200 text-lg font-semibold\">${precio.precio}</span>\r\n                      </label>`;\r\n      listaPrecios.insertAdjacentHTML('beforeend', preciohtml);\r\n    });\r\n  }\r\n\r\n  aplicarprecioadicional.addEventListener('click', ()=>{\r\n    if(document.querySelector('.inputprecioadicional')){  //si existe uno de los input de precios adicionales\r\n      const seleccionado = document.querySelector('.inputprecioadicional:checked') as HTMLInputElement;\r\n      POS.actualizarCarrito(seleccionado.dataset.precio, 1, true, true, seleccionado.value);\r\n    }\r\n  });\r\n\r\n\r\n  const gestionarPreciosAdicionales = {\r\n    miDialogoPreciosAdicionales,\r\n    abrirDialogo(elementProduct: HTMLElement) {\r\n      miDialogoPreciosAdicionales.showModal();\r\n      cargarPreciosAdicionales(elementProduct.dataset.id!);\r\n      document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    },\r\n  };\r\n\r\n  POS.gestionarPreciosAdicionales = gestionarPreciosAdicionales;\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.ventas') || document.querySelector('.ordenresumen') || document.querySelector('.detalleinvoice')){\r\n\r\n    const sendInvoiceAPI = {\r\n\r\n      async sendInvoice(x:number){\r\n        console.log(x);\r\n        try {\r\n            const url = \"/admin/api/sendInvoice\"; //llamado a la API REST apidiancontrolador.php\r\n            const respuesta = await fetch(url, {\r\n              method: 'POST', \r\n              headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n              body: JSON.stringify({id: x}) \r\n            });\r\n            \r\n            const responseDian = await respuesta.json();\r\n            /*return new Promise(resolve => {\r\n              setTimeout(() => {\r\n                  resolve('ok');\r\n              }, 4000);\r\n            }); */\r\n            return responseDian;\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      }\r\n    };\r\n  \r\n\r\n    (window as any).POS.sendInvoiceAPI = sendInvoiceAPI;\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.ventas')){\r\n\r\n    const POS = (window as any).POS;\r\n     \r\n    const selectCliente = POS.gestionClientes.selectCliente;\r\n    const dirEntrega = POS.gestionClientes.dirEntrega;\r\n    const productos = document.querySelectorAll<HTMLElement>('#producto')!;\r\n    const contentproducts = document.querySelector('#productos');\r\n    const btnEntrega = document.querySelector('#btnEntrega');\r\n    const modalidadEntrega = document.querySelector('#modalidadEntrega') as HTMLElement;\r\n    const totalunidades = document.querySelector('#totalunidades') as HTMLElement;\r\n    const tablaventa = document.querySelector('#tablaventa tbody');\r\n    const btnguardar = document.querySelector('#btnguardar');\r\n    const btnfacturar = document.querySelector('#btnfacturar');\r\n    const btnaplicarcredito = document.querySelector('#btnaplicarcredito');\r\n    const miDialogoAddCliente = POS.gestionClientes.miDialogoAddCliente;\r\n    //const miDialogoAddDir = POS.gestionClientes.miDialogoAddDir;\r\n    const miDialogoOtrosProductos = POS.gestionOtrosProductos.miDialogoOtrosProductos;\r\n    const miDialogoPreciosAdicionales = POS.gestionarPreciosAdicionales.miDialogoPreciosAdicionales;\r\n    const miDialogoFacturarA = POS.gestionarAdquiriente.miDialogoFacturarA;\r\n    const miDialogoDescuento = POS.gestionarDescuentos.miDialogoDescuento;\r\n    const miDialogoCredito = document.querySelector('#miDialogoCredito') as any;\r\n    const miDialogoGuardar = document.querySelector('#miDialogoGuardar') as any;\r\n    const miDialogoFacturar = document.querySelector('#miDialogoFacturar') as any;\r\n    const btnCaja = document.querySelector('#caja') as HTMLSelectElement; //select de la caja en el modal pagar\r\n    const btnTipoFacturador = document.querySelector('#facturador') as HTMLSelectElement; //select del consecutivo o facturador en el modal de pago\r\n    const btnPagar = document.getElementById('btnPagar') as HTMLInputElement;\r\n    \r\n    let carrito:{id:string, idproducto:string, tipoproducto:string, tipoproduccion:string, idcategoria: string, foto:string, nombreproducto: string, rendimientoestandar:string, costo:string, valorunidad: string, cantidad: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total: number}[]=[];\r\n    const valorTotal = {subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, idtarifa: 0, valortarifa: 0, total: 0}; //datos global de la venta\r\n    let tarifas:{id:string, idcliente:string, nombre:string, valor:string}[] = [];\r\n    let nombretarifa:string|undefined='', tipoventa:string=\"Contado\";\r\n    const promesas: Promise<any>[] = [];\r\n    \r\n    const constImp: {[key:string]: number} = {};\r\n    constImp['excluido'] = 0;\r\n    constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n    constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n    constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n    constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n    constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n    interface Item {\r\n      id_impuesto: number,\r\n      facturaid: number,\r\n      basegravable: number,\r\n      valorimpuesto: number\r\n    }\r\n    let factimpuestos:Item[] = [];\r\n\r\n    let products:productsapi[]=[], unproducto:productsapi;\r\n    const mapMediospago = new Map();\r\n\r\n    const mediosPagoDBMAP = new Map<string, string>( \r\n      mediosPagoDB.map(m => [m.id, m.mediopago]) //mediosPagoDB se declara en app.ts el cual viene del <script> en index.php que convierte el array de medios de pago de php a js.\r\n    );\r\n\r\n    (async ()=>{\r\n      products = await POS.productosAPI.getProductosAPI();\r\n      POS.products = products;  //Se expone globalmente\r\n      POS.gestionOtrosProductos.otrosproductos();\r\n    })();\r\n\r\n    /*productos.forEach(producto=>{\r\n      producto.addEventListener('click', (e)=>{\r\n        console.log(producto.dataset.id);\r\n      });\r\n    });*/\r\n    \r\n\r\n\r\n                       /******** *********/\r\n\r\n    selectFacturadorSegunCaja(btnCaja);\r\n    btnCaja.addEventListener('change', (e:Event)=>selectFacturadorSegunCaja(e.target as HTMLSelectElement));\r\n    function selectFacturadorSegunCaja(z:HTMLSelectElement){\r\n      $('#facturador').val(z.options[z.selectedIndex].dataset.idfacturador??'1');\r\n    }\r\n\r\n    POS.gestionClientes.clientes();  //inicializa modulo de clientes\r\n\r\n    //////////// evento al boton modalidad de entrega //////////////\r\n    btnEntrega?.addEventListener('click', (e:Event)=>{\r\n      modalidadEntrega.textContent == \": Presencial\"?modalidadEntrega.textContent = \": Domicilio\":modalidadEntrega.textContent=\": Presencial\";\r\n      printTarifaEnvio();\r\n      valorCarritoTotal();\r\n    });\r\n\r\n    ///////// funcion que imprime el valor de la tarifa segun direccion ///////////\r\n    function printTarifaEnvio():void{\r\n      tarifas = POS.tarifas;\r\n      const selectDir = dirEntrega.options[dirEntrega.selectedIndex];\r\n      if(modalidadEntrega.textContent == \": Presencial\" || dirEntrega.selectedIndex == -1){\r\n        valorTotal.valortarifa = 0;\r\n        nombretarifa = '';\r\n        return;\r\n      }\r\n      if(selectDir?.dataset.idtarifa && modalidadEntrega.textContent == \": Domicilio\"){\r\n        const objtarifa = tarifas.find(tarifa =>{\r\n          if(tarifa.idcliente == selectDir.dataset.idcliente && tarifa.id == selectDir.dataset.idtarifa)return true;\r\n        });\r\n        valorTotal.valortarifa = Number(objtarifa?.valor);\r\n        valorTotal.idtarifa = Number(objtarifa?.id);\r\n        nombretarifa = objtarifa?.nombre;\r\n      }\r\n    }\r\n\r\n\r\n    //////////// evento a toda el area de los productos a seleccionar //////////////\r\n    contentproducts?.addEventListener('click', (e:Event)=>{\r\n      const elementProduct = (e.target as HTMLElement)?.closest('.producto');\r\n      const count = carrito.find(x=>x.idproducto == (elementProduct as HTMLElement).dataset.id);\r\n\r\n      if((e.target as HTMLElement).parentElement?.id === 'precioadicional'){\r\n        POS.gestionarPreciosAdicionales.abrirDialogo(elementProduct);  //ejecuta los precios adicionales\r\n        return;\r\n      }\r\n\r\n      if(window.innerWidth < 992){\r\n        // Crear popup\r\n        const popup = document.createElement('div');\r\n        popup.className = `popup absolute z-40 right-8 top-1/3 opacity-0 translate-x-0 translate-y-0 transition-all duration-500 w-10 h-10 rounded-full text-center grid place-items-center bg-teal-400 text-white font-semibold text-lg`;\r\n        popup.innerHTML = `${(count?.cantidad??0)+1}`;\r\n        elementProduct!.appendChild(popup);\r\n        // Forzar reflow para activar transición\r\n        requestAnimationFrame(() => {\r\n          popup.classList.remove(\"opacity-0\", \"translate-y-0\", \"translate-x-0\");\r\n          popup.classList.add(\"opacity-100\", \"-translate-y-14\", \"translate-x-10\");\r\n        });\r\n        const popupx = document.querySelectorAll('.popup');\r\n        setTimeout(() => {popupx.forEach(t=>{t.remove();});}, 2500);\r\n      }\r\n\r\n      const precio = products.find(x=>x.id == (elementProduct as HTMLElement).dataset.id)?.precio_venta;\r\n      if(elementProduct)actualizarCarrito((elementProduct as HTMLElement).dataset.id!, 1, true, true, precio);\r\n    });\r\n\r\n    function printProduct(id:string, precio:string){ //recibe el id del producto\r\n      const uncarrito = carrito.find(x=>x.idproducto==id&&x.valorunidad==precio)!;\r\n      const tr = document.createElement('TR');\r\n      tr.classList.add('productselect');\r\n      tr.dataset.id = `${id}`;\r\n      tr.dataset.precio = precio;\r\n      tr.insertAdjacentHTML('afterbegin', `<td class=\"!px-0 !py-2 text-xl text-gray-500 leading-5\">${uncarrito?.nombreproducto}</td> \r\n\r\n      <td class=\"!px-0 !py-2\">\r\n        <div class=\"flex items-center gap-2 px-4\">\r\n          <button type=\"button\" class=\"w-8 h-8 bg-indigo-700 text-white rounded-full flex items-center justify-center\">\r\n            <span class=\"menos material-symbols-outlined text-base\">remove</span>\r\n          </button>\r\n\r\n          <input type=\"text\" class=\"inputcantidad w-20 px-2 text-center\" value=\"${uncarrito.cantidad}\">\r\n\r\n          <button type=\"button\" class=\"w-8 h-8 bg-indigo-700 text-white rounded-full flex items-center justify-center\">\r\n            <span class=\"mas material-symbols-outlined text-base\">add</span>\r\n          </button>\r\n        </div>\r\n      </td>\r\n\r\n      <td class=\"!p-2 text-xl text-gray-500 leading-5\">$${Number(uncarrito?.valorunidad).toLocaleString()}</td>\r\n      <td class=\"!p-2 text-xl text-gray-500 leading-5\">$${Number(uncarrito?.total).toLocaleString()}</td>\r\n      <td class=\"accionestd\"><div class=\"acciones-btns\"><button class=\"btn-md btn-red eliminarProducto\"><i class=\"fa-solid fa-trash-can\"></i></button></div></td>`);\r\n      tablaventa?.appendChild(tr);\r\n    } //oninput=\"this.value = parseInt(this.value.replace(/[,.]/g, '')||1)\"\r\n\r\n\r\n    function actualizarCarrito(id:string, cantidad:number, control:boolean, stateinput:boolean, precio:string = '0'){\r\n      ///limpiar el campo de buscar producto\r\n      (document.querySelector('#buscarproducto') as HTMLInputElement).value = '';\r\n      //const hackerList = POS.hackerList;\r\n      //hackerList.search('');\r\n      const index = carrito.findIndex(x=>x.idproducto==id && x.valorunidad == precio); //devuelve el index si el producto existe\r\n      \r\n      if(index>-1){\r\n        if(cantidad <= 0){\r\n          cantidad = 0;\r\n          carrito[index].total = 0;\r\n        }\r\n        if(control){ //cuando el producto se agrega desde la lista de productos\r\n          carrito[index].cantidad += cantidad;\r\n        }else{ //cuando el producto se agrega por cantidad\r\n          carrito[index].cantidad = cantidad;\r\n        }\r\n       \r\n        \r\n        carrito[index].subtotal = parseInt(carrito[index].valorunidad)*carrito[index].cantidad;\r\n        carrito[index].total = carrito[index].subtotal;\r\n        //calculo del impuesto y base por producto en el carrito deventas\r\n        carrito[index].valorimp = parseFloat((carrito[index].total*constImp[carrito[index].impuesto??0]).toFixed(3));\r\n        carrito[index].base = parseFloat((carrito[index].total-carrito[index].valorimp).toFixed(3));\r\n\r\n        valorCarritoTotal();\r\n        if(stateinput)\r\n        (tablaventa?.querySelector(`TR[data-id=\"${id}\"][data-precio=\"${precio}\"] .inputcantidad`) as HTMLInputElement).value = carrito[index].cantidad+'';\r\n        (tablaventa?.querySelector(`TR[data-id=\"${id}\"][data-precio=\"${precio}\"]`)?.children?.[3] as HTMLElement).textContent = \"$\"+carrito[index].total.toLocaleString();\r\n      }else{  //agregar a carrito si el producto no esta agregado en carrito, cuando se agrega por primera vez\r\n        const producto = products.find(x=>x.id==id)!; //products es el arreglo de todos los productos traido por api\r\n        \r\n        const productovalorimp = (Number(precio)*cantidad)*constImp[producto.impuesto??'0']; //si producto.impuesto es null toma el valor de cero\r\n        const productototal = Number(precio)*cantidad;\r\n        \r\n        var a:{id:string, idproducto:string, tipoproducto:string, tipoproduccion:string, idcategoria: string, nombreproducto: string, rendimientoestandar:string, foto:string, costo:string, valorunidad: string, cantidad: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total:number} = {\r\n          id: '',\r\n          idproducto: producto?.id!,\r\n          tipoproducto: producto.tipoproducto,\r\n          tipoproduccion: producto.tipoproduccion,\r\n          idcategoria: producto.idcategoria,\r\n          nombreproducto: producto.nombre,\r\n          rendimientoestandar: producto.rendimientoestandar,\r\n          foto: producto.foto,\r\n          costo: producto.precio_compra,\r\n          valorunidad: precio,\r\n          cantidad: cantidad,\r\n          subtotal: productototal, //este es el subtotal del producto\r\n          base: productototal-productovalorimp,\r\n          impuesto: producto.impuesto, //porcentaje de impuesto, es null si es excluido de iva\r\n          valorimp: productovalorimp,\r\n          descuento: 0,\r\n          total: productototal //valorunidad x cantidad\r\n        }\r\n        \r\n        carrito = [...carrito, a];\r\n        valorCarritoTotal();\r\n        printProduct(id, precio);\r\n        POS.carrito = carrito;\r\n      }\r\n    }\r\n\r\n    ////////////////////// valores finales subtotal y total ////////////////////////\r\n    function valorCarritoTotal(){\r\n      //calcular el impuesto discriminado por tarifa\r\n      const idimpuesto: Record<string, number> = {'0': 1, '5': 2, '16': 3, '19': 4, 'excluido': 5, '8': 6 };\r\n      const objbase:{'0':number, '5':number, '16':number, '19':number, 'excluido':number, '8':number} = {'0': 0, '5': 0, '16': 0, '19': 0, 'excluido':0, '8': 0};\r\n\r\n      const mapImpuesto = new Map();\r\n      carrito.forEach(x=>{\r\n        if(x.impuesto){\r\n          if(mapImpuesto.has(x.impuesto)){\r\n            const valor = mapImpuesto.get(x.impuesto) + x.total*constImp[x.impuesto];\r\n            mapImpuesto.set(x.impuesto, valor);\r\n          }else{\r\n            mapImpuesto.set(x.impuesto, x.total*constImp[x.impuesto]);\r\n          }\r\n        }\r\n        if(x.impuesto == null)x.impuesto = \"excluido\";\r\n          objbase[x.impuesto as keyof typeof objbase] += x.base;\r\n          const impValor = mapImpuesto.get(x.impuesto)??0;\r\n          const index = factimpuestos.findIndex(Obj=>Obj.id_impuesto == idimpuesto[x.impuesto]);\r\n          if(index!=-1){ //si existe remplazar obj\r\n            factimpuestos[index] = {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor};\r\n          }else{\r\n            factimpuestos = [...factimpuestos, {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor}];\r\n          }\r\n      });\r\n\r\n     \r\n      //Valor del impuesto total de todos los productos, es decir de la factura;\r\n      let valorTotalImp:number = 0;\r\n      for(let valorImp of mapImpuesto.values())valorTotalImp += valorImp;\r\n      \r\n      valorTotal.valorimpuestototal = parseFloat(valorTotalImp.toFixed(3));  //valor del impuesto total factura de todos los productos\r\n\r\n      valorTotal.subtotal = carrito.reduce((total, x)=>x.total+total, 0);\r\n      valorTotal.base = valorTotal.subtotal - valorTotal.valorimpuestototal;  //valor de la base total factura de todos los productos\r\n      valorTotal.total = valorTotal.subtotal + valorTotal.valortarifa - valorTotal.descuento;\r\n      document.querySelector('#subTotal')!.textContent = '$'+valorTotal.subtotal.toLocaleString();\r\n      (document.querySelector('#impuesto') as HTMLElement).textContent = '$'+valorTotalImp.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n      (document.querySelector('#valorTarifa') as HTMLElement).textContent = '$'+valorTotal.valortarifa.toLocaleString();\r\n      document.querySelector('#total')!.textContent = '$ '+valorTotal.total.toLocaleString();\r\n      // cantidad total de productos\r\n      totalunidades.textContent = carrito.reduce((total, producto)=>producto.cantidad+total, 0)+'';\r\n    }\r\n\r\n    /////////////////////// evento a la tabla de productos de venta (carrito) //////////////////////////\r\n    tablaventa?.addEventListener('click', (e:Event)=>{\r\n      const elementProduct = (e.target as HTMLElement)?.closest('.productselect');\r\n      const idProduct = (elementProduct as HTMLElement).dataset.id!;\r\n      const precio = (elementProduct as HTMLElement).dataset.precio!;\r\n      const productoCarrito = carrito.find(x=>x.idproducto==idProduct && x.valorunidad==precio);\r\n      if((e.target as HTMLElement).classList.contains('menos')){\r\n        actualizarCarrito(idProduct, productoCarrito!.cantidad-1, false, true, productoCarrito?.valorunidad);\r\n      }\r\n      if((e.target as HTMLElement).classList.contains('mas')){\r\n        actualizarCarrito(idProduct, productoCarrito!.cantidad+1, false, true, productoCarrito?.valorunidad);\r\n      }\r\n      if((e.target as HTMLElement).classList.contains('eliminarProducto') || (e.target as HTMLElement).tagName == \"I\"){\r\n        carrito = carrito.filter(x=>x.idproducto != idProduct || x.valorunidad != precio);\r\n        valorCarritoTotal();\r\n        tablaventa?.querySelector(`TR[data-id=\"${idProduct}\"][data-precio=\"${precio}\"]`)?.remove();\r\n      }\r\n    });\r\n\r\n\r\n    tablaventa?.addEventListener('input', e=>{\r\n      const input = e.target as HTMLInputElement;\r\n      if (!input.classList.contains('inputcantidad')) return;\r\n      const fila = input?.closest('.productselect') as HTMLTableRowElement;\r\n      const idProduct = fila.dataset.id!;\r\n      const precio = fila.dataset.precio!;\r\n      const productoCarrito = carrito.find(x=>x.idproducto==idProduct && x.valorunidad==precio);\r\n      \r\n      \r\n        //if((e.target as HTMLElement).dataset.event != \"eventInput\"){\r\n          \r\n           \r\n            let val = input.value;\r\n            val = val.replace(/[^0-9.]/g, '');\r\n            const partes = val.split('.');\r\n            if(partes.length > 2)val = partes[0]+'.'+partes.slice(1).join('');\r\n            if (val.startsWith('.'))val = '1';\r\n            if (val === '' || isNaN(parseFloat(val))) val = '0';\r\n\r\n            input.value = val;\r\n            actualizarCarrito(idProduct, Number(input.value), false, false,  productoCarrito?.valorunidad);\r\n          \r\n          //(e.target as HTMLElement).dataset.event = \"eventInput\"; //se marca al input que ya tiene evento añadido\r\n        //}\r\n      \r\n\r\n    });\r\n\r\n\r\n    /*btnvaciar?.addEventListener('click', ()=>{\r\n      if(carrito.length){\r\n        miDialogoVaciar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });*/\r\n\r\n    btnguardar?.addEventListener('click', ()=>{\r\n      if(carrito.length){\r\n        miDialogoGuardar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n    btnaplicarcredito?.addEventListener('click', ()=>{\r\n      if(modalidadEntrega.textContent === \": Domicilio\" && (selectCliente.value =='' || !dirEntrega.value) || selectCliente.value ==''){\r\n        msjAlert('error', 'Cliente o direccion no seleccionado', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n        return;\r\n      }\r\n      if(carrito.length){\r\n        document.querySelector('.Efectivo')?.removeAttribute('readonly');\r\n        document.querySelector('#inputscreditos')?.classList.add('flex');\r\n        document.querySelector('#inputscreditos')?.classList.remove('hidden');\r\n        if(tipoventa == \"Contado\"){\r\n          mapMediospago.clear();\r\n          $('.mediopago').val(0);\r\n        }\r\n        tipoventa = \"Credito\";\r\n        POS.tipoventa = tipoventa;\r\n        POS.gestionSubirModalPagar.subirModalPagar();\r\n        //miDialogoCredito.showModal();\r\n        miDialogoFacturar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n    btnfacturar?.addEventListener('click', ()=>{\r\n      if(modalidadEntrega.textContent === \": Domicilio\" && (selectCliente.value =='' || !dirEntrega.value)){\r\n        msjAlert('error', 'Cliente o direccion no seleccionado', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n        return;\r\n      }\r\n      if(carrito.length){\r\n        document.querySelector('.Efectivo')?.setAttribute('readonly', 'true');\r\n        document.querySelector('#inputscreditos')?.classList.add('hidden');\r\n        document.querySelector('#inputscreditos')?.classList.remove('flex');\r\n        tipoventa = \"Contado\";\r\n        POS.tipoventa = tipoventa;\r\n        POS.gestionSubirModalPagar.subirModalPagar();\r\n        miDialogoFacturar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if (f === miDialogoDescuento || f === miDialogoCredito || f === miDialogoGuardar || f === miDialogoFacturar || f === miDialogoAddCliente || f === miDialogoOtrosProductos || f === miDialogoFacturarA || /*f === miDialogoAddDir ||*/ f=== miDialogoPreciosAdicionales || (f as HTMLInputElement).closest('.salir') || (f as HTMLInputElement).closest('.novaciar') || (f as HTMLInputElement).closest('.sivaciar') || (f as HTMLInputElement).closest('.noguardar') || (f as HTMLInputElement).closest('.siguardar') || (f as HTMLButtonElement).value == \"Cancelar\" || /*(f as HTMLButtonElement).value == \"Seleccionar\" ||*/ (f as HTMLButtonElement).classList.contains('btnCerrarPreciosAdicionales') ) {\r\n        miDialogoDescuento.close();\r\n        //miDialogoCredito.close();\r\n        miDialogoGuardar.close();\r\n        miDialogoFacturar.close();\r\n        miDialogoAddCliente.close();\r\n        //miDialogoAddDir.close();\r\n        miDialogoFacturarA.close();\r\n        miDialogoOtrosProductos.close();\r\n        miDialogoPreciosAdicionales.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        if((f as HTMLInputElement).closest('.siguardar')){\r\n          tipoventa = \"\";\r\n          procesarpedido('Guardado', '1');\r\n        }\r\n        //if((f as HTMLInputElement).closest('.sivaciar'))vaciarventa();\r\n      }\r\n    }\r\n\r\n    function vaciarventa():void\r\n    {\r\n      if(datosfactura?.id)datosfactura.id = '';\r\n      (document.querySelector('#formFacturarA') as HTMLFormElement)?.reset();\r\n      (document.querySelector('#formfacturar') as HTMLFormElement)?.reset();\r\n      mapMediospago.clear();\r\n      $('.mediopago').val(0);\r\n      carrito.length = 0;\r\n      factimpuestos.length = 0;\r\n\r\n      history.replaceState({}, \"\", \"/admin/ventas\");\r\n      while(tablaventa?.firstChild)tablaventa.removeChild(tablaventa?.firstChild);\r\n      (document.querySelector('#npedido') as HTMLInputElement).value = '';\r\n      document.querySelector('#subTotal')!.textContent = '$'+0;\r\n      document.querySelector('#impuesto')!.textContent = '$'+0;\r\n      (document.querySelector('#descuento') as HTMLElement).textContent = '$'+0;\r\n      document.querySelector('#total')!.textContent = '$'+0;\r\n      $('#selectCliente').val('').trigger('change');   //aqui tambien se reinicia la elemento del valor de la tarifa\r\n      for(const key in valorTotal)valorTotal[key as keyof typeof valorTotal] = 0; //reiniciar objeto\r\n    }\r\n\r\n\r\n    ////////////////// evento al bton pagar del modal facturar //////////////////////\r\n    document.querySelector('#formfacturar')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      if(valorTotal.total <0 || valorTotal.subtotal <0){\r\n        msjAlert('error', 'No se puede procesar pago con $0', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n\r\n      //calcular si el totoal de los medios de pago es menor al abono inicial, abortar pago...\r\n      let totalMediosPago:number = 0;\r\n      for(let value of mapMediospago.values())totalMediosPago+=value;\r\n      if(totalMediosPago<POS.gestionSubirModalPagar.valoresCredito.abonoinicial){\r\n        msjAlert('error', 'Medio de pago no indicado', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n  \r\n      btnPagar.disabled = true;\r\n      btnPagar.value = 'Procesando...';\r\n      procesarpedido('Paga', '0');\r\n    });\r\n\r\n    async function procesarpedido(estado:string, ctz:string){\r\n      const imprimir = document.querySelector('input[name=\"imprimir\"]:checked') as HTMLInputElement;\r\n      const valoresCredito = POS.gestionSubirModalPagar.valoresCredito;\r\n      const datos = new FormData();\r\n      datos.append('id', datosfactura?.id??'');\r\n      datos.append('idcliente', (document.querySelector('#selectCliente') as HTMLSelectElement).value || '1');\r\n      datos.append('idvendedor', (document.querySelector('#vendedor') as HTMLInputElement).dataset.idvendedor!);\r\n      datos.append('idcaja', btnCaja.value);\r\n      datos.append('idconsecutivo', btnTipoFacturador.value);\r\n      datos.append('iddireccion', dirEntrega.value);\r\n      datos.append('idtarifazona', valorTotal.idtarifa+'');\r\n      datos.append('idcanaldeventa', (document.querySelector('#canalVenta') as HTMLSelectElement)?.value??'1');\r\n      datos.append('cliente', selectCliente.value==''?'N/A':selectCliente.options[selectCliente.selectedIndex].textContent!);\r\n      datos.append('vendedor', (document.querySelector('#vendedor') as HTMLInputElement).value);\r\n      datos.append('caja', (document.querySelector('#caja option:checked') as HTMLSelectElement).textContent!);\r\n      datos.append('tipofacturador', btnTipoFacturador.options[btnTipoFacturador.selectedIndex].textContent!);\r\n      datos.append('direccion', dirEntrega.options[dirEntrega.selectedIndex]?.text??'');\r\n      datos.append('tarifazona', nombretarifa||'');\r\n      datos.append('carrito', JSON.stringify(carrito.filter(x=>x.cantidad>0)));  //envio de todos los productos con sus cantidades\r\n      datos.append('totalunidades', totalunidades.textContent!);\r\n      //datos.append('mediosPago', JSON.stringify(Object.fromEntries(mapMediospago)));\r\n      datos.append('mediosPago', JSON.stringify(Array.from(mapMediospago, ([idmediopago, valor])=>({idmediopago, id_factura:0, valor}))));\r\n      datos.append('factimpuestos', JSON.stringify(factimpuestos));\r\n      datos.append('recibido', document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n      datos.append('transaccion', '');\r\n      datos.append('tipoventa', tipoventa);\r\n      datos.append('valoresCredito', JSON.stringify(valoresCredito));\r\n      datos.append('cotizacion', ctz);  //1= cotizacion, 0 = no cotizacion pagada.\r\n      datos.append('estado', estado);\r\n      datos.append('subtotal', valorTotal.subtotal+'');\r\n      datos.append('base', valorTotal.base.toFixed(3));\r\n      datos.append('valorimpuestototal', valorTotal.valorimpuestototal+''); //valor total del impuesto. \r\n      datos.append('dctox100',valorTotal.dctox100+'');\r\n      datos.append('descuento',valorTotal.descuento+'');\r\n      datos.append('total', valorTotal.total.toString());\r\n      datos.append('observacion', document.querySelector<HTMLTextAreaElement>('#observacion')!.value);\r\n      datos.append('departamento', '');\r\n      datos.append('ciudad', (document.querySelector('#ciudad') as HTMLInputElement).value);\r\n      datos.append('entrega', modalidadEntrega.textContent!.replace(': ', ''));\r\n      datos.append('valortarifa', valorTotal.valortarifa+'');\r\n      datos.append('datosAdquiriente', JSON.stringify(POS.gestionarAdquiriente.datosAdquiriente));\r\n      datos.append('opc1', '');\r\n      datos.append('opc2', '');\r\n      try {\r\n          const url = \"/admin/api/facturar\";  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n\r\n          if(estado == \"Paga\"){\r\n            resultado.dataInvoice.items = carrito.filter(x=>x.cantidad>0);\r\n            resultado.dataInvoice.mediospago = Array.from(mapMediospago, ([idmediopago, valor])=>({\r\n              idmediopago,\r\n              mediopago: mediosPagoDBMAP.get(idmediopago),\r\n              valor,\r\n            }));\r\n          }\r\n\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            btnPagar.disabled = false;\r\n            btnPagar.value = 'Pagar';\r\n            miDialogoFacturar.close();\r\n            (document.getElementById('miDialogoCarritoMovil') as HTMLDialogElement).close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          \r\n            //ENVIAR FACTURA A DIAN SI ES FACTURACION ELECTRONICA\r\n            if(btnTipoFacturador.options[btnTipoFacturador.selectedIndex].dataset.idtipofacturador == '1'){\r\n              const resDian = await POS.sendInvoiceAPI.sendInvoice(resultado.idfactura);\r\n              POS.gestionarAdquiriente.datosAdquiriente = {}; //reiniciar datos de adquiriente cada vez que se facture electronicamente\r\n              resultado.dataInvoice.cufe = resDian.cufe;\r\n              resultado.dataInvoice.link = resDian.link;\r\n              console.log(resDian);\r\n            }\r\n            //IMPRIMIR TICKET POS\r\n            if(resultado.idfactura && imprimir.value === '1')printTicketPOS(resultado.idfactura, resultado.dataInvoice);\r\n            vaciarventa();\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n\r\n    async function printTicketPOS(idfactura:string, datainvoice:DataInvoice){\r\n      try {\r\n        const url = \"http://localhost:3100/api/printPOS/ticket1/CAJA\"; //llamado a la API REST apidiancontrolador.php\r\n        const respuesta = await fetch(url, {\r\n          method: 'POST',\r\n          headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n          body: JSON.stringify(datainvoice)\r\n        });\r\n        const resultado = await respuesta.json();\r\n        console.log(resultado);\r\n      } catch (error) {\r\n        console.log(error);\r\n      }\r\n\r\n      setTimeout(() => {\r\n        window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");\r\n      }, 1100);\r\n    }\r\n\r\n    \r\n    /////////////////////////obtener datos de cotizacion /////////////////////\r\n    const parametrosURL = new URLSearchParams(window.location.search);\r\n    const id = parametrosURL.get('id');\r\n    let datosfactura:{id:string, idcliente: string, idvendedor:string, idcaja:string, idconsecutivo:string, iddireccion:string, idtarifazona:string, idcierrecaja:string, num_orden:string, cliente:string, vendedor:string, caja:string, tipofacturador:string, direccion:string, tarifazona:string, totalunidades:string, recibido:string, transaccion:string, tipoventa:string,\r\n                      cotizacion:string, estado:string, cambioaventa:string, referencia:string, subtotal:string, base:string, valorimpuestototal:string, dctox100:string, descuento:string, total:string, observacion:string, departamento:string, ciudad:string, entrega:string, valortarifa:string, fechacreacion:string, fechapago:string, opc1:string, opc2:string};\r\n    if(id){\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/getcotizacion_venta?id=\"+id; //llamado a la API REST\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json();\r\n            datosfactura = resultado.factura;\r\n            carrito = resultado.productos;\r\n            carrito.forEach(item =>printProduct(item.idproducto, item.valorunidad));\r\n            valorCarritoTotal(); //recalcula impuestos de la cotizacion y valores totales\r\n            (document.querySelector('#npedido') as HTMLInputElement).value = datosfactura.num_orden;\r\n            $('#selectCliente').val(datosfactura.idcliente).trigger('change');\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formAddCliente') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n    //exponer variables y funciones globalmente\r\n    POS.limpiarformdialog = limpiarformdialog;\r\n    POS.printTarifaEnvio = printTarifaEnvio;\r\n    POS.valorCarritoTotal = valorCarritoTotal;\r\n    POS.actualizarCarrito = actualizarCarrito;\r\n    //POS.calcularCambio = calcularCambio;\r\n    POS.cerrarDialogoExterno = cerrarDialogoExterno;\r\n    POS.tarifas = tarifas;\r\n    POS.valorTotal = valorTotal;\r\n    POS.mapMediospago = mapMediospago;\r\n    POS.tipoventa = tipoventa;\r\n    //POS.carrito = carrito;\r\n    //POS.products = products;\r\n  }\r\n\r\n\r\n})();","(()=>{\r\n\r\n    if(!document.querySelector('.ventasgenerales') && !document.querySelector('.cuotasCreditos') && !document.querySelector('.movimientosinventarios') && !document.querySelector('.estadosfinancierosCreditos'))return;\r\n\r\n     const POS = (window as any).POS;\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\";\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      POS.callApiReporte(fechainicio, fechafin);\r\n    });\r\n})();","(function(){\r\n  if(document.querySelector('.reportes')){\r\n    const graficaventa = document.querySelectorAll<HTMLButtonElement>('.graficaventa');\r\n    const chartventas = (document.getElementById('chartventas') as HTMLCanvasElement)?.getContext('2d');\r\n    const chartutilidad = (document.getElementById('chartutilidad') as HTMLCanvasElement)?.getContext('2d');\r\n\r\n    let chartVentasInstance: any | null = null;\r\n\r\n    /*(async ()=>{\r\n        try {\r\n          const url = \"https://apidianj2.com/api/getconfigcompanies\"; //llamado a la API REST Dianlaravel\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          console.log(resultado);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n\r\n    /*new Chart(ctx, {\r\n      type: 'line',\r\n      data: {\r\n          labels: [1,2,3,4,5,6,7,8,9],//resultado.map(programa=>programa.nombre),\r\n          datasets: [{\r\n          label: '# of Votes',\r\n          data: [1,2,3,4,10,3,11,4,17],//resultado.map(programa=>programa.total),\r\n          borderColor: '#00c8c2',\r\n          //backgroundColor: ['#ea580c', '#84cc16', '#22d3ee', '#a855f7'],\r\n          backgroundColor: '#ea580c',\r\n          //tension: 0.3,\r\n          //stepped: 'middle',\r\n          }]\r\n      },\r\n      options: {\r\n          scales: {\r\n              y: {\r\n                  beginAtZero: true\r\n              }\r\n          },\r\n          plugins: {legend: {display: false } } //elimina el label del dataset\r\n      }\r\n    });*/\r\n\r\n\r\n    //graficaVentaMensual.addEventListener('click', ()=>{\r\n      //console.log(777);\r\n      /*(async ()=>{\r\n        try {\r\n          const url = \"https://apidianj2.com/api/getconfigcompanies\"; //llamado a la API REST Dianlaravel\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          console.log(resultado);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n      /*const idcli = 1;\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/ventasGraficaMensual?id=\"+idcli; //llamado a la API REST en reportescontrolador.php\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          console.log(resultado);\r\n          graficaVentas(resultado);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n    //});\r\n\r\n    callapiventasgrafica(\"/admin/api/ventasGraficaMensual\");\r\n\r\n    graficaventa.forEach((btngrafica, index) =>{\r\n      btngrafica.addEventListener('click', (e:Event)=>{\r\n        let url:string = \"/admin/api/ventasGraficaMensual\"; //llamado a la API REST en reportescontrolador.php\r\n        if(index == 1){  //grafico diario\r\n          url = \"/admin/api/ventasGraficaDiario\"; //llamado a la API REST en reportescontrolador.php\r\n        }\r\n        callapiventasgrafica(url);\r\n      })\r\n    });\r\n\r\n    async function callapiventasgrafica(url:string){\r\n      try {\r\n        const respuesta = await fetch(url); \r\n        const resultado = await respuesta.json(); \r\n        graficaVentas(resultado);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n    function graficaVentas(resultado:{label:String[], datos:string[]}){\r\n      if (chartVentasInstance)chartVentasInstance.destroy();\r\n      chartVentasInstance = new Chart(chartventas, {\r\n        type: 'bar',\r\n        data: {\r\n          labels: resultado.label,\r\n          datasets: [{\r\n            label: 'Total Ventas',\r\n            data: resultado.datos,\r\n            borderWidth: 1\r\n          }]\r\n        },\r\n        options: {\r\n          scales: {\r\n            y: {\r\n              beginAtZero: true,\r\n              grid: {display: false} //ocultar regilla horizontal\r\n            },\r\n            x: {\r\n                grid: {display: false}, ////ocultar regilla vertical\r\n            }\r\n          },\r\n          responsive: true,\r\n        }\r\n      });\r\n    }\r\n\r\n\r\n\r\n    ////////////////////////////  chartutilidad - grafica costo/utlidad //////////////////////////////////\r\n    (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/graficaValorInventario\"; //llamado a la API REST en reportescontrolador.php\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          new Chart(chartutilidad, {\r\n            type: 'doughnut',\r\n            data: {\r\n              labels: ['Ventas total:', 'Costo:', 'Utilidad:'],\r\n              datasets: [{\r\n                label: 'Total Ventas',\r\n                data: [Number(resultado.valorventa), Number(resultado.costoinv), (Number(resultado.valorventa) - Number(resultado.costoinv))],\r\n                backgroundColor: ['rgb(54, 162, 235)','rgb(255, 99, 132)', 'rgb(255, 205, 86)'],\r\n                //borderWidth: 1\r\n                hoverOffset: 4\r\n              }]\r\n            },\r\n            options: {\r\n              responsive: true,\r\n              plugins: {\r\n                legend: {\r\n                    labels: {\r\n                        generateLabels: (chart:any) => {\r\n                            const data = chart.data.datasets[0].data;\r\n                            const labels = chart.data.labels;\r\n                            return labels.map((label:any, i:any) => ({\r\n                                text: `${label}: ${data[i]}`,\r\n                                fillStyle: chart.data.datasets[0].backgroundColor[i],\r\n                                index: i\r\n                            }));\r\n                        }\r\n                    }\r\n                }\r\n              }\r\n            }\r\n          });\r\n\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    })();\r\n\r\n\r\n\r\n\r\n    ////////////////////////////////////////////////////////////////////    \r\n    \r\n\r\n    /* cerrarDialogoExterno(event:Event) {\r\n      if (event.target === modalFecha || (event.target as HTMLInputElement).value === 'cancelar' || (event.target as HTMLElement).closest('.finCerrarcaja')) {\r\n          modalFecha.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          if((event.target as HTMLElement).closest('.finCerrarcaja'))console.log(45);//eliminarCita(event.target.closest('.terminarcita').id);\r\n      }\r\n    }*/\r\n\r\n  }\r\n})();","(():void=>{\r\n  if(document.querySelector('.caja')){\r\n    const modalGastosIngresos:any = document.querySelector(\"#gastosIngresos\");\r\n    const modalcambioMedioPago:any = document.querySelector(\"#cambioMedioPago\");\r\n    const miDialogoAbrirCaja:any = document.querySelector(\"#miDialogoAbrirCaja\");\r\n    const btnGastosingresos = document.querySelector<HTMLButtonElement>(\"#btnGastosingresos\");\r\n    const btnAbrirCajon = document.querySelector<HTMLButtonElement>(\"#btnAbrirCajon\");\r\n    const operacion = document.querySelector('#operacion') as HTMLSelectElement;\r\n    const origengasto = document.querySelectorAll<HTMLInputElement>('input[name=\"origengasto\"]');\r\n    const mediosPago = document.querySelectorAll<HTMLInputElement>('.mediopago'); //todos los medios de pago del modal\r\n    const totalPagado = document.querySelector('#totalPagado') as HTMLSpanElement;\r\n    const numfactura = document.querySelector('#numfactura') as HTMLLabelElement;\r\n    const inputAbrirCaja = document.querySelector('#inputAbrirCaja') as HTMLInputElement;\r\n\r\n    let tablaListaPedidos:HTMLElement;\r\n    let estadofactura:string, contentMP:HTMLElement, idfactura:string = '0';\r\n    let mediospagoDB:{id:string, idmediopago:string, id_factura:string, valor:string}[];\r\n    let nuevosMediosPago:{idmediopago:string, valor: string}[]=[];  // guardar los medios de pago a enviar a backend\r\n    const setMediosPagoDB = new Set();\r\n    const mapMediospago = new Map();\r\n    let totalpagadointerno = 0;\r\n\r\n    tablaListaPedidos = ($('#tablaListaPedidos') as any).DataTable(configdatatablescaja);\r\n\r\n\r\n    interface clavesApi {\r\n      clave:string,\r\n      valor_default:string|null,\r\n      valor_final:string|null,\r\n      valor_local:string|null\r\n    };\r\n\r\n    let claveAbrirCajon:clavesApi[];\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          claveAbrirCajon = resultado;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n\r\n    //////// clic al btn gastos/ingresos\r\n    btnGastosingresos?.addEventListener('click', ():void=>{\r\n      modalGastosIngresos.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    ///////// cambio de tipo de operacion si ingreso o gasto, si es gasto habilita el select de los tipos de gastos\r\n    operacion?.addEventListener('change', (e:Event)=>{\r\n      const targetDom = e.target as HTMLSelectElement;\r\n      const tipodegasto = document.querySelector('.tipodegasto') as HTMLElement;\r\n\r\n      if(targetDom.value == 'gasto'){\r\n        tipodegasto.style.display = 'flex';\r\n        document.querySelector('#tipodegasto')?.setAttribute(\"required\", \"\"); //categoria de los gastos\r\n        document.querySelector('#origengasto')?.classList.remove('hidden');  //origen del gasto ya sea por caja o banco\r\n        document.querySelector('#origengasto')?.classList.add('flex');\r\n        showCajasBancos();\r\n      }\r\n      else{ // ingreso a caja\r\n        tipodegasto.style.display = 'none';\r\n        document.querySelector('#tipodegasto')?.removeAttribute(\"required\");\r\n        document.querySelector('#origengasto')?.classList.add('hidden');\r\n        document.querySelector('#origengasto')?.classList.remove('flex');\r\n        document.querySelector('#showcajas')?.classList.remove('hidden'); //mostar caja\r\n        document.querySelector('#showbancos')?.classList.add('hidden'); //oculta banco\r\n        document.querySelector('#banco')?.removeAttribute(\"required\");\r\n      }\r\n    });\r\n\r\n    /// evento a los inputs type radio para elegir origne del gasto = caja o bancos\r\n    origengasto.forEach(element =>element.addEventListener('click', showCajasBancos));\r\n\r\n\r\n    function showCajasBancos(){\r\n      const selectorigen = document.querySelector('input[name=\"origengasto\"]:checked');\r\n      if(selectorigen?.id == 'gastocaja'){\r\n        document.querySelector('#showcajas')?.classList.remove('hidden');\r\n        document.querySelector('#showcajas')?.setAttribute(\"required\", \"\");\r\n        document.querySelector('#showbancos')?.classList.add('hidden');\r\n        document.querySelector('#showbancos')?.removeAttribute(\"required\");\r\n        document.querySelector('#banco')?.removeAttribute(\"required\");\r\n      }else{\r\n        //document.querySelector('#showcajas')?.classList.add('hidden');\r\n        //document.querySelector('#showcajas')?.removeAttribute(\"required\");\r\n        document.querySelector('#showbancos')?.classList.remove('hidden');\r\n        document.querySelector('#showbancos')?.setAttribute(\"required\", \"\");\r\n        document.querySelector('#banco')?.setAttribute(\"required\", \"\");\r\n      }\r\n    }\r\n\r\n\r\n    //////// clic al btn abrir cajon monedero\r\n    btnAbrirCajon?.addEventListener('click', ():void=>{\r\n      miDialogoAbrirCaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    //evento al boton confirmar para eliminar orden\r\n    document.querySelector('.siAbrirCajon')?.addEventListener('click', (event:Event)=>{\r\n      const v:number = validarPasswordDcto();\r\n      if(!v)return;\r\n      if((event.target as HTMLInputElement).closest('.siAbrirCajon'))abrirCajonMonedero();\r\n    });\r\n\r\n    const abrirCajonMonedero = async():Promise<void>=>{\r\n        try {\r\n            const url = \"http://localhost:3100/api/printPOS/openCashDrawer/CAJA\";  //api llama servidor de impresion local.\r\n            const respuesta = await fetch(url);\r\n            const resultado = await respuesta.json();\r\n            console.log(resultado);\r\n            if(resultado){\r\n              msjalertToast('success', '¡Éxito!', 'Apertura de cajon enviada');\r\n              miDialogoAbrirCaja.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', 'Error en el cajon monedero');\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    ////////////// Evento a la tabla lista de pedidos ///////////////\r\n    document.querySelector('#tablaListaPedidos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"mediosdepago\")||target.parentElement?.classList.contains(\"mediosdepago\"))cambiomediopago(target);\r\n      if(target?.classList.contains(\"printPOS\")||target.parentElement?.classList.contains(\"printPOS\"))printPOS(target);\r\n      if(target?.classList.contains(\"printPDF\")||target.parentElement?.classList.contains(\"printPDF\"))printPDF(target);\r\n    });\r\n\r\n\r\n    //////////// Modal para el cambio de medio de pago ////////////\r\n    function cambiomediopago(target:HTMLElement){\r\n      idfactura = target.id;\r\n      contentMP = target;\r\n      estadofactura = target.dataset.estado??'';\r\n      totalPagado.textContent = Number(target.dataset.totalpagado??'0').toLocaleString();\r\n      if(target.tagName == \"BUTTON\"){\r\n        idfactura = target.parentElement!.id;\r\n        contentMP = target.parentElement!;\r\n        estadofactura = target.parentElement?.dataset.estado??'';\r\n        totalPagado.textContent = Number(target.parentElement!.dataset.totalpagado??'0').toLocaleString();\r\n      }\r\n      facturamediospago();     //muestra los valores de los medios de pago de cada factura\r\n      if(estadofactura == \"Eliminada\")document.querySelector('#btnEnviarCambioMedioPago')?.classList.add('!hidden');\r\n      if(estadofactura == \"Paga\")document.querySelector('#btnEnviarCambioMedioPago')?.classList.remove('!hidden');\r\n      modalcambioMedioPago.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function facturamediospago(){  //muestra los valores de los medios de pago de cada factura\r\n      numfactura.textContent = 'Factura N° : '+idfactura;\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/mediospagoXfactura?id=\"+idfactura; //llamado a la API REST y se trae los medios de pago segun factura\r\n          const respuesta = await fetch(url); \r\n          mediospagoDB = await respuesta.json(); \r\n          //console.log(mediospagoDB);\r\n          //const setMediosPagoDB = new Set(mediospagoDB.map(x=>x.idmediopago));\r\n          //console.log(setMediosPagoDB);\r\n\r\n          //agrupar por idmediopago y sumar su valor\r\n          totalpagadointerno = 0;\r\n          mediospagoDB = Object.values(mediospagoDB.reduce<Record<string, {id:string, idmediopago:string, id_factura:string, valor:string}>>((obj, x)=>{\r\n            totalpagadointerno+=Number(x.valor);\r\n            const k = x.idmediopago;\r\n            if(!obj[k])obj[k] = {...x, valor: '0'}\r\n            obj[k].valor = (Number(obj[k].valor) + Number(x.valor))+'';\r\n            return obj;\r\n          }, {}));\r\n          console.log(totalpagadointerno);\r\n\r\n          mediospagoDB.forEach(x => setMediosPagoDB.add(x.idmediopago));//se llena el set con los medios de pago de la DB\r\n          mediosPago.forEach(mediopago =>{  //se llena los inputs medios de pago con los medios de pago de la DB\r\n            mediopago.value = '0';\r\n            for(let i=0; i<mediospagoDB.length; i++)\r\n              if(mediopago.id == mediospagoDB[i].idmediopago){\r\n                mediopago.value =  Number(mediospagoDB[i].valor).toLocaleString();\r\n                mapMediospago.set(mediopago.id, Number(mediospagoDB[i].valor));\r\n                break;\r\n              }\r\n          });\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n\r\n    mediosPago.forEach(mp =>{\r\n      mp.addEventListener('input', (e)=>{\r\n        let totalmediospago = 0;\r\n        mediosPago.forEach((item, index)=>{ //sumar todos los medios de pago\r\n          totalmediospago += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        });\r\n\r\n        if(totalmediospago<=parseInt(totalPagado.textContent!.replace(/[,.]/g, ''))){\r\n          mapMediospago.set((e.target as HTMLInputElement).id, parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, '')));\r\n          document.querySelector('#diferencia')!.textContent = (parseInt(totalPagado.textContent!.replace(/[,.]/g, ''))-totalmediospago).toLocaleString();\r\n        }else{\r\n          if(mapMediospago.has((e.target as HTMLInputElement).id)){\r\n            (e.target as HTMLInputElement).value = mapMediospago.get((e.target as HTMLInputElement).id).toLocaleString();\r\n          }else{ (e.target as HTMLInputElement).value = '0'; }\r\n        }\r\n      });\r\n    });\r\n\r\n\r\n    function printPOS(target: HTMLElement){\r\n      let idfactura = target.parentElement!.id;\r\n      if(target.tagName === 'I')idfactura = target.parentElement!.parentElement!.id;\r\n      window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");  //controlador printcontrolador\r\n    }\r\n\r\n    function printPDF(target: HTMLElement){\r\n      let idfactura = target.parentElement!.id;\r\n      let cotizacion:string = target.parentElement?.dataset.cotizacion!;\r\n      let urlprintPDF:string = \"/printfacturacarta?id=\";\r\n      if(target.tagName === 'I'){\r\n        idfactura = target.parentElement!.parentElement!.id;\r\n        cotizacion = target.parentElement!.parentElement?.dataset.cotizacion!;\r\n      }\r\n      if(cotizacion === '1')urlprintPDF = \"/printcotizacion?id=\";\r\n      const ventana = window.open(urlprintPDF + idfactura, \"_blank\");  //cajacontrolador\r\n      if(ventana){\r\n        ventana.onload = ()=>{\r\n          ventana?.focus();\r\n          ventana?.print();\r\n          setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n        };\r\n      }\r\n    }\r\n\r\n    ////////////////// evento al bton para cambiar medios de pago //////////////////////\r\n    document.querySelector('#formCambioMedioPago')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      let totalotrosmedios = 0;\r\n      nuevosMediosPago.length = 0;\r\n      mediosPago.forEach((item, index)=>{ \r\n        totalotrosmedios += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, '')); //sumar todos los medios de pago de los inputs\r\n        if(item.value != '0')\r\n          nuevosMediosPago = [...nuevosMediosPago, {idmediopago: item.id, valor: item.value.replace(/[,.]/g, '')}];  //obtengo los nuevos medios de pago difente a cero\r\n      });\r\n\r\n      if(totalotrosmedios != parseInt(totalPagado.textContent!.replace(/[,.]/g, '')) && totalotrosmedios!=totalpagadointerno){\r\n        msjAlert('error', 'Valor diferente al pagado', (document.querySelector('#divmsjalerta2') as HTMLElement));\r\n        return;\r\n      }\r\n      actualizarMediosPago();\r\n    });\r\n\r\n\r\n    async function actualizarMediosPago(){\r\n      const setNuevosMediosPago = new Set(nuevosMediosPago.map(x=>x.idmediopago));\r\n      ////cruzar los datos de los medios de pago de la DB y de los nuevos medios de pago////\r\n      //////// medios de pago iguales o compartidos ///////////\r\n      const mediospagocompartidos = mediospagoDB.filter(x=>setNuevosMediosPago.has(x.idmediopago));\r\n      //////// nuevos medios de pago que no estan en DB, crear o agregar\r\n      const nuevosMediosPagoNoEnDB = nuevosMediosPago.filter(x=>!setMediosPagoDB.has(x.idmediopago));\r\n      //////// medios de pago de la DB que no estan en los nuevos medios de pago, eliminar\r\n      const mediosPagoDBNoEnNuevos = mediospagoDB.filter(x=>!setNuevosMediosPago.has(x.idmediopago));\r\n\r\n      const datos = new FormData();\r\n      datos.append('id_factura', idfactura);\r\n      datos.append('efectivoDB', mediospagoDB.find(x=>x.idmediopago=='1')?.valor??'0'+'');\r\n      datos.append('nuevoEfectivo', nuevosMediosPago.find(x=>x.idmediopago=='1')?.valor??'0'+'');\r\n      datos.append('mediospagocompartidos', JSON.stringify(mediospagocompartidos));\r\n      datos.append('nuevosMediosPagoNoEnDB', JSON.stringify(nuevosMediosPagoNoEnDB));\r\n      datos.append('mediosPagoDBNoEnNuevos', JSON.stringify(mediosPagoDBNoEnNuevos));\r\n      datos.append('nuevosMediosPago', JSON.stringify(nuevosMediosPago));  \r\n      try {\r\n          const url = \"/admin/api/cambioMedioPago\";  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            updateMP(resultado.mediosPagoUpdate);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n      modalcambioMedioPago.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function updateMP(mediosPagoUpdate:{id:string, idmediopago:string, id_factura:string, valor:string, mediopago:string}[]){\r\n      while(contentMP.firstChild)contentMP.removeChild(contentMP.firstChild);\r\n      mediosPagoUpdate.forEach(btnMP=>{\r\n        const button = document.createElement('button');\r\n        button.classList.add('btn-xs', 'btn-light', 'mr-2');\r\n        button.textContent = btnMP.mediopago;\r\n        contentMP.appendChild(button);\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if (f === modalGastosIngresos || f === modalcambioMedioPago || f === miDialogoAbrirCaja || (f as HTMLInputElement).closest('.noAbrirCajon') || (f as HTMLInputElement).value === 'cancelar') {\r\n          modalGastosIngresos.close();\r\n          modalcambioMedioPago.close();\r\n          miDialogoAbrirCaja.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n    \r\n    function validarPasswordDcto():number{\r\n      const clave = claveAbrirCajon.find(c => c.clave=='clave_para_abrir_cajón_monedero');\r\n      if(clave?.valor_final!==null && inputAbrirCaja.value !== clave?.valor_final){\r\n        msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalerta3') as HTMLElement));\r\n        return 0;\r\n      }\r\n      return 1;\r\n    }\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.categoriasgastos')){\r\n        const btnCrearCategoriaGasto = document.querySelector('#btnCrearCategoriaGasto');\r\n        const miDialogoCategoriaGasto = document.querySelector('#miDialogoCategoriaGasto') as any;\r\n        let tablaCategoriasGastos:HTMLElement;\r\n\r\n        tablaCategoriasGastos = ($('#tablaCategoriasGastos') as any).DataTable(configdatatables25reg);\r\n\r\n        ///////////////BTN PARA CREAR CATEGORIA DE GASTO////////////////\r\n        btnCrearCategoriaGasto?.addEventListener('click', (e):void=>{\r\n            limpiarformdialog();\r\n            document.querySelector('#modalCategoriaGasto')!.textContent = \"Crear categoria de gasto\";\r\n            (document.querySelector('#btnEditarCrearCategoriaGasto') as HTMLInputElement).value = \"Crear\";\r\n            miDialogoCategoriaGasto.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n        document.querySelector('#tablaCategoriasGastos')?.addEventListener('click', (e:Event)=>{\r\n            var btn = e.target as HTMLElement;\r\n            if(btn?.classList.contains('editarCategoriaGasto')||btn.parentElement?.classList.contains(\"editarCategoriaGasto\"))editarCategoriaGasto(e);\r\n            if(btn?.classList.contains('eliminarCategoriaGasto')||btn.parentElement?.classList.contains(\"eliminarCategoriaGasto\"))eliminarCategoriaGasto(e);   \r\n        });\r\n\r\n\r\n        ///////////////EDITAR CATEGORIA DE GASTO////////////////\r\n        function editarCategoriaGasto(e:Event){\r\n            let idcategoriagasto = (e.target as HTMLElement).parentElement?.id!;\r\n            if((e.target as HTMLElement)?.tagName === 'I')idcategoriagasto = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n            (document.querySelector('#formCrearUpdateCategoriaGasto') as HTMLFormElement).action = \"/admin/caja/editarcategoriagasto\";\r\n            document.querySelector('#modalCategoriaGasto')!.textContent = \"Actualizar categoria de gasto\";\r\n            (document.querySelector('#btnEditarCrearCategoriaGasto') as HTMLInputElement)!.value = \"Actualizar\";\r\n            (document.querySelector('#idCategoriaGasto') as HTMLInputElement).value = idcategoriagasto;\r\n            (document.querySelector('#nombre') as HTMLInputElement).value = ((e.target as HTMLElement).closest('.acciones-btns') as HTMLElement)?.dataset.categoriagasto!; \r\n            miDialogoCategoriaGasto.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n\r\n        function eliminarCategoriaGasto(e:Event):void{\r\n            let form = (e.target as HTMLElement).parentElement!;\r\n            if((e.target as HTMLElement).tagName === 'I')form = form.parentElement!;\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar la categoria de gasto?',\r\n                text: \"La categoria de gasto sera eliminado definitivamente.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed)(form as HTMLFormElement).submit();\r\n            });\r\n        }\r\n        \r\n        function limpiarformdialog(){\r\n            (document.querySelector('#formCrearUpdateCategoriaGasto') as HTMLFormElement)?.reset();\r\n            (document.querySelector('#formCrearUpdateCategoriaGasto') as HTMLFormElement).action = \"/admin/caja/crear_categoriaGasto\";\r\n        }\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n        if (f === miDialogoCategoriaGasto || (f as HTMLInputElement).value === 'Salir' || (f as HTMLInputElement).value === 'Actualizar') {\r\n            miDialogoCategoriaGasto.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n        }\r\n    }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.cerrarcaja')){\r\n    const modalArqueocaja:any = document.querySelector(\"#modalArqueocaja\");\r\n    const Modalcerrarcaja:any = document.querySelector(\"#Modalcerrarcaja\");\r\n    const modalCambiarCaja:any = document.querySelector(\"#modalCambiarCaja\");\r\n    const btnArqueocaja = document.querySelector<HTMLButtonElement>(\"#btnArqueocaja\");\r\n    const btnCerrarcaja = document.querySelector<HTMLButtonElement>(\"#btnCerrarcaja\");\r\n    const btnImprimirDetalleCaja = document.querySelector('#btnImprimirDetalleCaja') as HTMLButtonElement;\r\n    const btnCambiarCaja = document.querySelector<HTMLButtonElement>(\"#btnCambiarCaja\");\r\n    const btnVerCierreWeb = document.querySelector('#btnVerCierreWeb') as HTMLButtonElement;\r\n    const inputsmediospago = document.querySelectorAll<HTMLInputElement>('.inputmediopago');\r\n    const formArqueocaja = document.querySelector('#formArqueocaja') as HTMLFormElement;\r\n    const formCambiarCaja = document.querySelector('#formCambiarCaja') as HTMLFormElement;\r\n\r\n    btnArqueocaja?.addEventListener('click', ():void=>{\r\n      modalArqueocaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    btnCerrarcaja?.addEventListener('click', ():void=>{\r\n      Modalcerrarcaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    btnCambiarCaja?.addEventListener('click', ():void=>{\r\n      modalCambiarCaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n    \r\n\r\n    //////////////////     Arqueo de caja      //////////////////////\r\n    formArqueocaja?.addEventListener('submit', (e:Event)=>{\r\n      e.preventDefault();\r\n      sumatoriaDenominaciones();\r\n      const datos = new FormData(formArqueocaja);\r\n      datos.append('idcierrecaja', document.querySelector('#idCierrecaja')?.textContent!);\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/arqueocaja\";  //api llamada en cajacontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              modalArqueocaja.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n      \r\n    });\r\n\r\n    function sumatoriaDenominaciones():void{\r\n      const ef = document.querySelector('#Efectivo') as HTMLInputElement;\r\n      const inputsDenominaciones = Array.from( document.querySelectorAll<HTMLInputElement>('.denominacion'));\r\n      const sum = inputsDenominaciones.reduce((total, denominaicon)=>(Number(denominaicon.dataset.moneda)*Number(denominaicon.value))+total, 0);\r\n      ef.value = sum+'';\r\n      const eventInput = new Event('input');  //crea un evento\r\n      ef.dispatchEvent(eventInput); // se dispara el evento de manera manual, --->abajo<--, es decir cuando se introduce un valor en el campo efectivo se dispara el evento.\r\n    }\r\n\r\n    ///////////  eventos a los inputs medios de pago de declarar valores /////////////\r\n    inputsmediospago.forEach(m=>{\r\n      m.addEventListener('input', (e)=>{  \r\n        const inputmediopago = (e.target as HTMLInputElement);\r\n        const valormediopagodeclarado:number =  parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        (async ()=>{\r\n          const datos = new FormData();\r\n          datos.append('id_mediopago', inputmediopago.dataset.idmediopago+'');\r\n          datos.append('nombremediopago', inputmediopago.name);\r\n          datos.append('valordeclarado', valormediopagodeclarado+'');\r\n          datos.append('idcierrecaja', document.querySelector('#idCierrecaja')?.textContent!);\r\n          try {\r\n              const url = \"/admin/api/declaracionDinero\";  //api llamada en cajacontrolador.php\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito !== undefined){\r\n                inputmediopago.style.color = \"#02db02\";\r\n                inputmediopago.style.fontWeight = \"500\";\r\n                actualizarAnalisis(inputmediopago.dataset.idmediopago!, valormediopagodeclarado+'', inputmediopago.name);\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();\r\n      });\r\n    }); \r\n\r\n\r\n    function actualizarAnalisis(id: string, valordeclarado: string, mediopago:string):void{\r\n      const coldeclarado = document.querySelector(`.coldeclarado[data-mediopagoid=\"${id}\"]`);\r\n      if(coldeclarado){\r\n        const coldif = coldeclarado.nextElementSibling;\r\n        coldeclarado.textContent = Number(valordeclarado).toLocaleString('es-ES', { useGrouping: true });\r\n        const colsistem = coldeclarado.previousElementSibling?.textContent?.replace(/[.,]/g, '');\r\n        coldif!.textContent = ((Number(valordeclarado) - Number(colsistem))).toLocaleString('es-ES', { useGrouping: true }); \r\n      }else{\r\n        const cuerpoanalisis = document.querySelector('.cuerpoanalisis');\r\n        cuerpoanalisis?.insertAdjacentHTML('beforeend', `\r\n          <tr class=\"${mediopago=='Efectivo'?'!border-2 !border-indigo-600':''}\">\r\n            <td class=\"\">${mediopago}</td> \r\n            <td class=\"colsistem\">0</td>\r\n            <td class=\"coldeclarado\" data-mediopagoid=\"${id}\">${Number(valordeclarado).toLocaleString('es-ES', { useGrouping: true })}</td>\r\n            <td class=\"coldif\">${Number(valordeclarado).toLocaleString('es-ES', { useGrouping: true })}</td>\r\n          </tr>`\r\n        );\r\n      }\r\n    }\r\n\r\n    function confirmarcierre(){\r\n      const datos = new FormData();\r\n      \r\n      datos.append('idcierrecaja', document.querySelector('#idCierrecaja')?.textContent!);\r\n      \r\n      (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n      Modalcerrarcaja.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      (async ()=>{\r\n        try {\r\n\r\n            const url = \"/admin/api/cierrecajaconfirmado\";  //api llamada en cajacontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              setTimeout(() => {\r\n                (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n                window.location.href = `/admin/caja/detallecierrecaja?id=${resultado.ultimocierre[0]}`;\r\n              }, 1600);\r\n            }else{\r\n              (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n\r\n    const idimprimircierrecaja = document.querySelector('#idCierrecaja')?.textContent;\r\n    ///////// imprimir detalle cierre\r\n    btnImprimirDetalleCaja?.addEventListener('click', ()=>{\r\n        const ventana = window.open('/printdetallecierre?id='+idimprimircierrecaja, '_blank');\r\n        if(ventana){\r\n          ventana.onload = ()=>{\r\n            ventana?.focus();\r\n            ventana?.print();\r\n            setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n          };\r\n        }\r\n    });\r\n    ///////// ver detalle cierre en web\r\n    btnVerCierreWeb?.addEventListener('click', ()=>{\r\n        const ventana = window.open('/printdetallecierre?id='+idimprimircierrecaja, '_blank');\r\n        if(ventana)ventana.onload = ()=>ventana?.focus();\r\n    });\r\n\r\n    //////////////////     Cambio de caja      //////////////////////\r\n    formCambiarCaja?.addEventListener('submit', (e:Event)=>{\r\n      e.preventDefault();\r\n      const datos = new FormData();\r\n      datos.append('idcaja', $('#CambiarCaja').val()as string); //select del modal de cambio de caja\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/datoscajaseleccionada\";  //api llamada en cajacontrolador.php para traer datos de venta de la caja seleccionada \r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              modalCambiarCaja.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              console.log(resultado);\r\n              //cambiar el id del cierre de caja en id=\"#idCierrecaja\"\r\n              document.querySelector('#nombreCaja')!.textContent = $('#CambiarCaja option:selected').text();\r\n              document.querySelector('#idCierrecaja')!.textContent = resultado.ultimocierre.id;\r\n              //mostar datos de la caja seleccionada\r\n              printdiscriminarmediospago(resultado.discriminarmediospagos);\r\n              printindicadores(resultado.ultimocierre);\r\n              //printdetalleimpuesto();\r\n              //printgastosdelacaja();\r\n              //printdiscriminadoabonos();\r\n              printsobrantesfaltantes(resultado.sobrantefaltante);\r\n              printventasxusuarios(resultado.ventasxusuarios);\r\n              printventas(resultado.facturas);\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n      \r\n    });\r\n\r\n    function printdiscriminarmediospago(array: {idmediopago:string, mediopago:string, valor:string}[]){\r\n      const tbodyMediosPago = document.querySelector('#tablaMediosPago tbody') as HTMLTableElement;\r\n      while(tbodyMediosPago.firstChild)tbodyMediosPago.removeChild(tbodyMediosPago.firstChild);\r\n      array.forEach(row=>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${row.mediopago}</td> \r\n                        <td class=\"\"><strong>$ </strong>${Number(row.valor).toLocaleString()}</td>\r\n                      `;\r\n        tbodyMediosPago.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function printindicadores(obj:{id:string, idcaja:string, id_usuario:string, nombrecaja:string, nombreusuario:string, fechainicio:string, fechacierre:string, ncambiosaventa:string, totalcotizaciones:string, totalfacturas:string, facturaselectronicas:string, facturaspos:string, valorfe:string, descuentofe:string, valorpos:string, descuentopos:string, basecaja:string, ventasenefectivo:string, creditocapital:string, creditos:string, abonostotales:string, abonosenefectivo:string, abonoscreditos:string, abonosseparados:string, gastoscaja:string, gastosbanco:string, dineroencaja:string, domicilios:string, ndomicilios:string, realencaja:string, ingresoventas:string, totaldescuentos:string, realventas:string, valorimpuestototal:string, basegravable:string, estado:string}){\r\n      const basecaja = Number(obj.basecaja);\r\n      const ventasenefectivo = Number(obj.ventasenefectivo);\r\n      const gastoscaja = Number(obj.gastoscaja);\r\n      const domicilios = Number(obj.domicilios);\r\n      const ingresoventas = Number(obj.ingresoventas);\r\n      const totaldescuentos = Number(obj.totaldescuentos);\r\n      const abonosenefectivo = Number(obj.abonosenefectivo);\r\n      const abonostotales = Number(obj.abonostotales);\r\n\r\n      document.querySelector('#basecajaResumen')!.textContent = '$'+basecaja.toLocaleString();\r\n      document.querySelector('#gastoscajaResumen')!.textContent = '$'+gastoscaja.toLocaleString();\r\n      document.querySelector('#domiciliosResumen')!.textContent = '$'+domicilios.toLocaleString();\r\n      document.querySelector('#ingresoventasResumen')!.textContent = '$'+(ingresoventas).toLocaleString();\r\n      document.querySelector('#totalfacturasResumen')!.textContent = obj.totalfacturas;\r\n      document.querySelector('#totalcotizacionesResumen')!.textContent = obj.totalcotizaciones;\r\n\r\n      document.querySelector('#baseIngresoCaja')!.textContent = '+ $'+basecaja.toLocaleString();\r\n      document.querySelector('#ventasEfectivo')!.textContent = '+ $'+ventasenefectivo.toLocaleString();\r\n      document.querySelector('#abonosEfectivo')!.textContent = '+ $'+abonosenefectivo.toLocaleString();\r\n      document.querySelector('#gastosCaja')!.textContent = '- $'+gastoscaja.toLocaleString();\r\n      document.querySelector('#dineroCaja')!.textContent = '= $'+(basecaja+ventasenefectivo-gastoscaja).toLocaleString();\r\n      document.querySelector('#domicilios')!.textContent = '- $'+domicilios.toLocaleString();\r\n      document.querySelector('#realCaja')!.textContent = '= $'+(basecaja+ventasenefectivo-gastoscaja-domicilios).toLocaleString();\r\n      document.querySelector('#ingresoVentasTotal')!.textContent = '+ $'+ingresoventas.toLocaleString();\r\n      document.querySelector('#abonosTotales')!.textContent = '+ $'+abonostotales.toLocaleString();\r\n      document.querySelector('#totalGastosCaja')!.textContent = '- $'+gastoscaja.toLocaleString();\r\n      document.querySelector('#totalDescuentos')!.textContent = '- $'+totaldescuentos.toLocaleString();\r\n      document.querySelector('#totalDomicilios')!.textContent = '= $'+(domicilios).toLocaleString();\r\n      document.querySelector('#realVentas')!.textContent = '= $'+(ingresoventas-totaldescuentos-domicilios-gastoscaja).toLocaleString();\r\n      document.querySelector('#totalBaseGravable')!.textContent = '+ $'+Number(obj.basegravable).toLocaleString();\r\n      document.querySelector('#impuestoTotal')!.textContent = '+ $'+Number(obj.valorimpuestototal).toLocaleString();\r\n      document.querySelector('#otrosGastosBancarios')!.textContent = '+ $'+Number(obj.gastosbanco).toLocaleString();\r\n      document.querySelector('#cantidadFacturasFE')!.textContent = obj.facturaselectronicas;\r\n      document.querySelector('#cantidadFacturasPOS')!.textContent = obj.facturaspos;\r\n    }\r\n\r\n    function printsobrantesfaltantes(array: {id_mediopago:string, idcierrecajaid:string, nombremediopago:string, valordeclarado:number, valorsistema:number}[]){\r\n      const sobranteFaltante = document.querySelector('#sobranteFaltante tbody') as HTMLTableElement;\r\n      while(sobranteFaltante.firstChild)sobranteFaltante.removeChild(sobranteFaltante.firstChild);\r\n      array.forEach(row=>{\r\n        const tr = document.createElement('tr');\r\n        if(row.nombremediopago=='Efectivo')tr.classList.add('!border-2', '!border-indigo-600');\r\n        tr.innerHTML = `<td class=\"\">${row.nombremediopago}</td> \r\n                        <td class=\"colsistem\">${row.valorsistema.toLocaleString()}</td>\r\n                        <td class=\"coldeclarado\" data-mediopagoid=\"${row.id_mediopago}\">${row.valordeclarado.toLocaleString()}</td>\r\n                        <td class=\"coldif\">${(row.valordeclarado - row.valorsistema).toLocaleString()}</td>\r\n                      `;\r\n        sobranteFaltante.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function printventasxusuarios(array: {Nombre:string, N_ventas:string, ventas:string}[]){\r\n      const ventasxusuarios = document.querySelector('#ventasXUsuario tbody') as HTMLTableElement;\r\n      while(ventasxusuarios.firstChild)ventasxusuarios.removeChild(ventasxusuarios.firstChild);\r\n      array.forEach(row=>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${row.Nombre}</td>\r\n                        <td class=\"\">${row.N_ventas}</td>\r\n                        <td class=\"\"><strong>$ </strong>${Number(row.ventas).toLocaleString()}</td>\r\n                      `;\r\n        ventasxusuarios.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function printventas(array: {id:string, idcliente:string, idvendedor:string, idcaja:string, idconsecutivo:string, iddireccion:string, idtarifazona:string, idcierrecaja:string, cliente:string, vendedor:string, caja:string, tipofacturador:string, mediosdepago:{id:string, id_factura:string, mediopago:string, valor:string}[], direccion:string, tarifazona:string, totalunidades:string, recibido:string, transaccion:string, tipoventa:string, cotizacion:string, estado:string, cambioaventa:string, subtotal:string, base:string, valorimpuestototal:string, dctox100:string, descuento:string, total:string, observacion:string, departamento:string, ciudad:string, entrega:string, valortarifa:string, fechacreacion:string, fechapago:string}[]){\r\n      const tablaVentas = document.querySelector('#tablaVentas tbody') as HTMLTableElement;\r\n      while(tablaVentas.firstChild)tablaVentas.removeChild(tablaVentas.firstChild);\r\n      array.forEach((row, i)=>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${i}</td>        \r\n                        <td class=\"\">${row.fechapago}</td> \r\n                        <td class=\"\">${row.cliente}</td> \r\n                        <td class=\"\">${row.id}</td>\r\n                        <td>\r\n                            <div data-estado=\"${row.estado}\" data-totalpagado=\"${row.total}\" id=\"${row.id}\" class=\"mediosdepago max-w-full flex flex-wrap gap-2\">\r\n                                ${row.mediosdepago.map(mp=>`<button class=\"btn-xs btn-light\">${mp.mediopago}</button>`).join(' ')}\r\n                            </div>\r\n                        </td>\r\n                        <td class=\"${row.estado=='Paga'?'btn-xs btn-lima':'btn-xs btn-blueintense'}\">${row.estado}</td>\r\n                        <td class=\"\">$ ${Number(row.subtotal).toLocaleString()}</td>\r\n                        <td class=\"\">$ ${Number(row.total).toLocaleString()}</td>\r\n                        <td class=\"accionestd\"><div class=\"acciones-btns\" id=\"${row.id}\">\r\n                                <a class=\"btn-xs btn-turquoise\" href=\"/admin/caja/ordenresumen?id=${row.id}\">Ver</a> <button class=\"btn-xs btn-light\"><i class=\"fa-solid fa-print\"></i></button>\r\n                            </div>\r\n                        </td>\r\n                      `;\r\n        tablaVentas.appendChild(tr);\r\n      });\r\n    }\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === modalArqueocaja || event.target === Modalcerrarcaja || event.target === modalCambiarCaja || (event.target as HTMLInputElement).value === 'Cancelar' || (event.target as HTMLElement).closest('.salircerrarcaja') || (event.target as HTMLElement).closest('.finCerrarcaja')) {\r\n          modalArqueocaja.close();\r\n          Modalcerrarcaja.close();\r\n          modalCambiarCaja.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n          if((event.target as HTMLElement).closest('.finCerrarcaja')){  //Cuando se hace el cierre de caja\r\n            confirmarcierre();\r\n          }\r\n      }\r\n    }\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.detallecierrecaja')){\r\n    const btnImprimirDetalleCaja = document.querySelector('#btnImprimirDetalleCaja') as HTMLButtonElement;\r\n    const btnVerCierreWeb = document.querySelector('#btnVerCierreWeb') as HTMLButtonElement;\r\n\r\n    //capturar el id del cierre de caja por la url\r\n    const parametrosURL = new URLSearchParams(window.location.search);\r\n    const id:string = parametrosURL.get('id')??'';\r\n    ///////// imprimir detalle cierre\r\n    btnImprimirDetalleCaja?.addEventListener('click', ()=>{\r\n      if(id!=''){\r\n          const ventana = window.open('/printdetallecierre?id='+id, '_blank');\r\n          if(ventana){\r\n              ventana.onload = ()=>{\r\n                  ventana?.focus();\r\n                  ventana?.print();\r\n                  setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n              };\r\n          }\r\n      }else{\r\n        //alerta\r\n      }\r\n    });\r\n\r\n    if(id==''||id==null||isNaN(Number(id)))return;\r\n\r\n    ///////// ver detalle cierre en web\r\n    btnVerCierreWeb?.addEventListener('click', ()=>{\r\n        const ventana = window.open('/printdetallecierre?id='+id, '_blank');\r\n        if(ventana)ventana.onload = ()=>ventana?.focus();\r\n    });\r\n\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.fechazetadiario')){\r\n\r\n    const btnsmultiselect = document.querySelectorAll<HTMLElement>('.btnmultiselect');\r\n    const selectedcajas = document.querySelectorAll<HTMLLIElement>('.caja');\r\n    const consultarZDiario = document.querySelector('#consultarZDiario') as HTMLButtonElement;\r\n    const tbodyMediosPago = document.querySelector('#tablaMediosPago tbody') as HTMLTableElement;\r\n    const base = document.querySelector('#base') as HTMLElement;\r\n    const valorImpuestoTotal = document.querySelector('#valorImpuestoTotal') as HTMLElement;\r\n    const ingresoVentas = document.querySelector('#ingresoVentas') as HTMLElement;\r\n    const totalDescuentos = document.querySelector('#totalDescuentos') as HTMLElement;\r\n    const realVentas = document.querySelector('#realVentas') as HTMLElement;\r\n    const cantidadElectronicas = document.querySelector('#cantidadElectronicas') as HTMLElement;\r\n    const cantidadPOS = document.querySelector('#cantidadPOS') as HTMLElement;\r\n    const valorElectronicas = document.querySelector('#valorElectronicas') as HTMLElement;\r\n    const valorPOS = document.querySelector('#valorPOS') as HTMLElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\";\r\n\r\n    //evento a los select drop dawn para abrir y cerrar\r\n    btnsmultiselect.forEach((btnmultiselect, index) =>{\r\n      btnmultiselect.addEventListener('click', (e:Event)=>{\r\n        cerrarlosmultiselect(index);\r\n        btnmultiselect.classList.toggle('open');\r\n      });\r\n    });\r\n    function cerrarlosmultiselect(index:number){\r\n      btnsmultiselect.forEach((element, i) =>{\r\n        if(i != index || !element.classList.contains('open'))element.classList.remove('open');\r\n      });\r\n    }\r\n    document.querySelector('.fechazetadiario')?.addEventListener('click', (e:Event)=>{\r\n      if(!(e.target as HTMLElement).closest('.btnmultiselect')&&!(e.target as HTMLElement).closest('.list-items')){\r\n        const btnmultiselect = document.querySelector('.open');\r\n        if(btnmultiselect)btnmultiselect.classList.toggle('open');\r\n      }\r\n    });\r\n    // mostrar el nombre de las cajas,segun se selecciona\r\n    selectedcajas.forEach(c=>{c.addEventListener('click', cajas_seleccionadas);});\r\n\r\n    function cajas_seleccionadas(){\r\n      const inputscaja = document.querySelectorAll<HTMLInputElement>('input.caja[type=\"checkbox\"]:checked');\r\n      const cajastext = document.querySelector('#cajastext') as HTMLElement;\r\n      cajastext.textContent = \". \";\r\n      inputscaja.forEach((inputcaja, i) =>{\r\n        if(i<inputscaja.length-1){\r\n          cajastext.textContent += inputcaja.nextElementSibling?.textContent!+' - ';\r\n        }else{\r\n          cajastext.textContent += inputcaja.nextElementSibling?.textContent!;\r\n        }\r\n      });\r\n    }\r\n\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        (document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        (document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    consultarZDiario.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      const cajas = document.querySelectorAll<HTMLInputElement>('input.caja[type=\"checkbox\"]:checked');\r\n      const facturadores = document.querySelectorAll<HTMLInputElement>('input.facturador[type=\"checkbox\"]:checked');\r\n      \r\n      const valuecajas:string[] = Array.from(cajas).map(c=>c.value);\r\n      const valuefacturadores:string[] = Array.from(facturadores).map(f=>f.value);\r\n\r\n      (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n      (async ()=>{\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', fechainicio);\r\n        datos.append('fechafin', fechafin);\r\n        datos.append('cajas', JSON.stringify(valuecajas));\r\n        datos.append('facturadores', JSON.stringify(valuefacturadores));\r\n        try {\r\n            const url = \"/admin/api/consultafechazetadiario\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            console.log(resultado);\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n           reiniciarTablas();\r\n           imprimirtablaMediosPago(resultado.datosmediospago);\r\n           imprimirIngresos(resultado.datosventa);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n    });\r\n\r\n\r\n    function imprimirtablaMediosPago(datosmediospago:{id:string, nombre:string, valor:string}[]){\r\n      datosmediospago.forEach(mp =>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${mp.nombre}</td> \r\n                        <td class=\"\">$${Number(mp.valor).toLocaleString()}</td>`;\r\n        tbodyMediosPago.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function imprimirIngresos(datosventa:{subtotalventa:string, base:string, valorimpuestototal:string, totalventa:string, ELECTRONICAS:string, POS:string, total_ELECTRONICAS:string, total_POS:string}){\r\n      base.textContent = '$'+Number(datosventa.base).toLocaleString();\r\n      valorImpuestoTotal.textContent = '$'+Number(datosventa.valorimpuestototal).toLocaleString();\r\n      ingresoVentas.textContent = '$'+Number(datosventa.subtotalventa).toLocaleString();\r\n      totalDescuentos.textContent = '$'+(Number(datosventa.subtotalventa)-Number(datosventa.totalventa)).toLocaleString();\r\n      realVentas.textContent = '$'+Number(datosventa.totalventa).toLocaleString();\r\n      cantidadElectronicas.textContent = datosventa.ELECTRONICAS;\r\n      cantidadPOS.textContent = datosventa.POS;\r\n      valorElectronicas.textContent = '$'+Number(datosventa.total_ELECTRONICAS).toLocaleString();\r\n      valorPOS.textContent = '$'+Number(datosventa.total_POS).toLocaleString();\r\n    }\r\n\r\n    function reiniciarTablas(){\r\n      while(tbodyMediosPago.firstChild)tbodyMediosPago.removeChild(tbodyMediosPago.firstChild);\r\n      ingresoVentas.textContent = '';\r\n      totalDescuentos.textContent = \"\";\r\n      realVentas.textContent = \"\";\r\n      cantidadElectronicas.textContent = '';\r\n      cantidadPOS.textContent = '';\r\n      valorElectronicas.textContent = '';\r\n      valorPOS.textContent = '';\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n    if(document.querySelector('.ordenresumen')){\r\n      const POS = (window as any).POS;\r\n      const miDialogoFacturar:any = document.querySelector(\"#miDialogoFacturar\");\r\n      const miDialogoEliminarOrden = document.querySelector('#miDialogoEliminarOrden') as any;\r\n      const btnfacturar = document.querySelector<HTMLButtonElement>(\"#btnfacturar\");\r\n      const btneliminarorden = document.querySelector('#btneliminarorden') as HTMLButtonElement;\r\n      const btnCaja = document.querySelector('#caja') as HTMLSelectElement;\r\n      const btnTipoFacturador = document.querySelector('#facturador') as HTMLSelectElement;\r\n      const mediospago = document.querySelectorAll('.mediopago');\r\n      const btnsdevolverinv = document.querySelectorAll<HTMLInputElement>('input[name=\"devolverinventario\"]'); //radio buttom\r\n      const inputsInv = document.querySelectorAll<HTMLInputElement>('.inputInv');\r\n      const printcarta = document.querySelector('#printcarta');\r\n      const printcotizacion = document.querySelector('#printcotizacion');\r\n      const numOrden = document.querySelector('#numOrden');\r\n      const referenciaFactura = document.querySelector('#referenciaFactura');\r\n      const enviarEmail = document.querySelector('#enviarEmail') as HTMLButtonElement;\r\n      const miDialogoEnviarEmailCliente = document.querySelector('#miDialogoEnviarEmailCliente') as any;\r\n      const inputEliminarClave = document.querySelector('#inputEliminarClave') as HTMLInputElement;\r\n\r\n      const valorTotal = {subtotal: 0, impuesto: 0, dctox100: 0, descuento: 0, idtarifa: 0, valortarifa: 0, total: 0}; //datos global de la venta\r\n      const mapMediospago = new Map();\r\n\r\n      interface clavesApi {\r\n        clave:string,\r\n        valor_default:string|null,\r\n        valor_final:string|null,\r\n        valor_local:string|null\r\n      };\r\n\r\n      let claveEliminarOrden:clavesApi[];\r\n\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json(); \r\n            claveEliminarOrden = resultado;\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n  \r\n      valorTotal.subtotal = Number(document.querySelector('#subTotal')?.textContent);\r\n      valorTotal.total = Number(document.querySelector('#total')?.textContent?.replace(/[^\\d]/g, ''));\r\n      \r\n      selectFacturadorSegunCaja(btnCaja);\r\n    \r\n      btnCaja.addEventListener('change', (e:Event)=>selectFacturadorSegunCaja(e.target as HTMLSelectElement));\r\n    \r\n      function selectFacturadorSegunCaja(z:HTMLSelectElement){\r\n        $('#facturador').val(z.options[z.selectedIndex].dataset.idfacturador??'1');\r\n      }\r\n\r\n      printcarta?.addEventListener('click', ()=>{\r\n        //leer parametros de url\r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n        const ventana = window.open('/printfacturacarta?id='+id, '_blank');\r\n        if(ventana){\r\n          ventana.onload = ()=>{\r\n            ventana?.focus();\r\n            ventana?.print();\r\n            setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n          };\r\n        }\r\n      });\r\n\r\n      printcotizacion?.addEventListener('click', ()=>{\r\n        //leer parametros de url\r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n        const ventana = window.open('/printcotizacion?id='+id, '_blank');\r\n        if(ventana){\r\n          ventana.onload = ()=>{\r\n            ventana?.focus();\r\n            ventana?.print();\r\n            setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n          };\r\n        }\r\n      });\r\n\r\n      btnfacturar?.addEventListener('click', ()=>{\r\n        /*if(modalidadEntrega.textContent === \": Domicilio\" && (selectCliente.value =='1' || selectCliente.value =='2' || !dirEntrega.value)){\r\n          msjAlert('error', 'Cliente o direccion no seleccionado', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n          return;\r\n        }*/\r\n        /*if(carrito.length){*/\r\n          subirModalPagar();\r\n          miDialogoFacturar.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        //}\r\n      });\r\n      \r\n\r\n      btneliminarorden?.addEventListener('click', ()=>{\r\n          miDialogoEliminarOrden.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n\r\n      enviarEmail?.addEventListener('click', ()=>{\r\n        miDialogoEnviarEmailCliente.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n\r\n      document.querySelector('#formEnviarEmailCliente')?.addEventListener('submit', (e:Event)=>{\r\n        e.preventDefault();\r\n        const idorden = (document.querySelector('#idorden') as HTMLElement).dataset.idorden;\r\n        if(idorden!=null && Number(idorden)>0){\r\n          const datos = new FormData();\r\n          datos.append('id', idorden);\r\n          datos.append('email', (document.querySelector('#inputEmail') as HTMLInputElement).value);\r\n          miDialogoEnviarEmailCliente.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          (async ()=>{\r\n            try {\r\n              const url = \"/admin/api/sendOrdenEmailToCustemer\";  //va al controlador cajacontrolador para enviar detalle de orden por email.\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos});\r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito!=undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n          })();\r\n        }\r\n      });\r\n\r\n      ///////////////////// Logica botones devolver inventario ////////////////////////\r\n      btnsdevolverinv.forEach(inv=>{ //evento a los radiobutton\r\n        inv.addEventListener('change', (e:Event)=>{\r\n          document.querySelector('#productsInv')?.classList.toggle('hidden');\r\n          if((e.target as HTMLInputElement).value === \"1\"){\r\n            document.querySelectorAll('.inputInv').forEach(x=>x.setAttribute('required', ''));\r\n          }else{\r\n            document.querySelectorAll('.inputInv').forEach(x=>x.removeAttribute('required'));\r\n          }\r\n        });\r\n      });\r\n\r\n      inputsInv.forEach(inputinv =>{\r\n        inputinv.addEventListener('input', e=>{\r\n          const qty = (e.target as HTMLInputElement);\r\n          if(qty.value != qty.parentElement?.dataset.qty){\r\n            qty.classList.add('border-2', 'border-rose-600');\r\n            if(!document.querySelector('.alerta'))\r\n              msjAlert('error', 'Cantidad diferente a devolver a inventario', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n          }else{\r\n            qty.classList.remove('border-2', 'border-rose-600');\r\n            document.querySelector('.alerta')?.remove();\r\n          }\r\n        });\r\n      });\r\n\r\n      /////////////////////  logica del modal de pago  //////////////////////////\r\n      function subirModalPagar(){\r\n        document.querySelector('#totalPagar')!.textContent = `${valorTotal.total.toLocaleString()}`;\r\n        //como se puede cerrar el modal y aumentar los productos, hay calcular los inputs\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{\r\n          if(index>0)totalotrosmedios += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        });\r\n\r\n        if(valorTotal.total<totalotrosmedios){\r\n          totalotrosmedios = 0;\r\n          mapMediospago.clear();\r\n          $('.mediopago').val(0);\r\n        }\r\n        (document.querySelector('.Efectivo')! as HTMLInputElement).value =  `${(valorTotal.total-totalotrosmedios).toLocaleString()}`;\r\n        mapMediospago.set('1', valorTotal.total-totalotrosmedios);\r\n        if(valorTotal.total-totalotrosmedios == 0 && mapMediospago.has('1'))mapMediospago.delete('1');\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n      }\r\n  \r\n      //eventos a los inputs medios de pago\r\n      mediospago.forEach(m=>{m.addEventListener('input', (e)=>{ calcularmediospago(e);});}); \r\n\r\n      function calcularmediospago(e:Event){\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{ //sumar todos los medios de pago menos el efectivo\r\n          if(index>0)totalotrosmedios += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        });\r\n        if(totalotrosmedios<=valorTotal.total){\r\n          mapMediospago.set('1', valorTotal.total-totalotrosmedios);\r\n          if(valorTotal.total-totalotrosmedios == 0 && mapMediospago.has('1'))mapMediospago.delete('1');\r\n          mapMediospago.set((e.target as HTMLInputElement).id, parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, '')));\r\n          if((e.target as HTMLInputElement).value == '0' && mapMediospago.has((e.target as HTMLInputElement).id))mapMediospago.delete((e.target as HTMLInputElement).id);\r\n        }else{ //si la suma de los medios de pago superan el valor total, toma el ultimo input digitado y lo reestablece a su ultimo valor\r\n          if(mapMediospago.has((e.target as HTMLInputElement).id)){\r\n            (e.target as HTMLInputElement).value = mapMediospago.get((e.target as HTMLInputElement).id).toLocaleString();\r\n          }else{\r\n            (e.target as HTMLInputElement).value = '0';\r\n          }\r\n        }\r\n        (mediospago[0] as HTMLInputElement).value = (mapMediospago.get('1')??0).toLocaleString();\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n      }\r\n\r\n      /////////////////////  evento al input recibido  //////////////////////////\r\n      document.querySelector<HTMLInputElement>('#recibio')?.addEventListener('input', (e)=>{\r\n        calcularCambio((e.target as HTMLInputElement).value);\r\n      });\r\n      function calcularCambio(recibido:string):void{\r\n        recibido = recibido.replace(/[,.]/g, '');\r\n        if(Number(recibido)>mapMediospago.get('1')){\r\n          (document.querySelector('#cambio') as HTMLElement).textContent = (Number(recibido)-mapMediospago.get('1')).toLocaleString()+'';\r\n          return;\r\n        }\r\n        (document.querySelector('#cambio') as HTMLElement).textContent = '0';\r\n      }\r\n\r\n\r\n      ////////////////// evento al bton pagar del modal facturar //////////////////////\r\n      document.querySelector('#formfacturarCotizacion')?.addEventListener('submit', e=>{\r\n        e.preventDefault();\r\n        procesarpedido('Guardado');\r\n      });\r\n\r\n      async function procesarpedido(estado:string){ //////PROCESAR PAGO DE COTIZACION SiN CAMBIAR DATOS DE LOS PRODUCTOS//////\r\n        const imprimir = document.querySelector('input[name=\"imprimir\"]:checked') as HTMLInputElement;\r\n        const datos = new FormData();\r\n        datos.append('id', (document.querySelector('#idorden') as HTMLElement).dataset.idorden!);\r\n        //datos.append('idcliente', (document.querySelector('#selectCliente') as HTMLSelectElement).value);\r\n        //datos.append('idvendedor', (document.querySelector('#vendedor') as HTMLInputElement).dataset.idvendedor!);\r\n        datos.append('idcaja', btnCaja.value);\r\n        datos.append('idconsecutivo', btnTipoFacturador.value);\r\n        //datos.append('iddireccion', dirEntrega.value);\r\n        //datos.append('idtarifazona', valorTotal.idtarifa+'');\r\n        //datos.append('cliente', selectCliente.options[selectCliente.selectedIndex].textContent!);\r\n        //datos.append('vendedor', (document.querySelector('#vendedor') as HTMLInputElement).value);\r\n        datos.append('caja', (document.querySelector('#caja option:checked') as HTMLSelectElement).textContent!);\r\n        datos.append('tipofacturador', btnTipoFacturador.options[btnTipoFacturador.selectedIndex].textContent!);\r\n        //datos.append('direccion', dirEntrega.options[dirEntrega.selectedIndex].text);\r\n        //datos.append('tarifazona', nombretarifa||'');\r\n        //datos.append('carrito', JSON.stringify(carrito));\r\n        //datos.append('totalunidades', totalunidades.textContent!);\r\n        //datos.append('mediosPago', JSON.stringify(Object.fromEntries(mapMediospago)));\r\n        datos.append('mediosPago', JSON.stringify(Array.from(mapMediospago, ([idmediopago, valor])=>({idmediopago, id_factura:0, valor}))));\r\n        datos.append('recibido', document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n        datos.append('transaccion', '');\r\n        datos.append('estado', estado);\r\n        datos.append('cambioaventa', '1');  //cambioaventa por defecto es 0\r\n        //datos.append('subtotal', valorTotal.subtotal+'');\r\n        //datos.append('impuesto', valorTotal.impuesto+'');\r\n        //datos.append('dctox100',valorTotal.dctox100+'');\r\n        //datos.append('descuento',valorTotal.descuento+'');\r\n        //datos.append('total', valorTotal.total.toString());\r\n        datos.append('observacion', document.querySelector<HTMLTextAreaElement>('#observacion')!.value);\r\n        //datos.append('departamento', '');\r\n        //datos.append('ciudad', (document.querySelector('#ciudadEntrega') as HTMLInputElement).value);\r\n        //datos.append('entrega', modalidadEntrega.textContent!.replace(': ', ''));\r\n        //datos.append('valortarifa', valorTotal.valortarifa+'');\r\n        //datos.append('datosAdquiriente', JSON.stringify(POS.gestionarAdquiriente.datosAdquiriente));\r\n        //datos.append('opc1', '');\r\n        //datos.append('opc2', '');\r\n        try {\r\n            const url = \"/admin/api/facturarCotizacion\";  //va al controlador ventascontrolador\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            console.log(resultado);\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              /////// reinciar modulo de ventas\r\n              ordenpagada();\r\n              miDialogoFacturar.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              if(resultado.idfactura && imprimir.value === '1')printTicketPOS(resultado.idfactura);\r\n              if(btnTipoFacturador.options[btnTipoFacturador.selectedIndex].dataset.idtipofacturador == '1'){ \r\n                const resDian = await POS.sendInvoiceAPI.sendInvoice(resultado.idfactura); //llama a la funcion que esta en ts/ventas/ventas.sendinvoice.ts\r\n                console.log(resDian);\r\n              }\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      }\r\n  \r\n      function printTicketPOS(idfactura:string){\r\n      setTimeout(() => {\r\n        window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");\r\n      }, 1200);\r\n    }\r\n\r\n      function ordenpagada(){\r\n        if(btnfacturar)btnfacturar.style.display = \"none\";\r\n        (document.querySelector('#abrirOrden') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#estadoOrden') as HTMLElement).textContent = \"Paga\";\r\n      }\r\n  \r\n      function cerrarDialogoExterno(event:Event) {\r\n        const f = event.target;\r\n        if (event.target === miDialogoFacturar || event.target === miDialogoEliminarOrden || event.target === miDialogoEnviarEmailCliente || (f as HTMLInputElement).value === 'cancelar' || (f as HTMLInputElement).value === 'Salir' || (f as HTMLInputElement).closest('.noeliminar')) {\r\n            miDialogoFacturar.close();\r\n            miDialogoEliminarOrden.close();\r\n            miDialogoEnviarEmailCliente.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n\r\n      //evento al boton confirmar para eliminar orden\r\n      document.querySelector('.sieliminar')?.addEventListener('click', (event:Event)=>{\r\n        const f = event.target;\r\n        if((f as HTMLInputElement).closest('.sieliminar'))eliminarorden();\r\n      });\r\n\r\n\r\n      function eliminarorden():void{\r\n        ///////*** crear arreglo de obj de los productos y sus cantidades ***///////\r\n        type producto = {id:string, idproducto:string, tipoproducto:string, tipoproduccion:string, rendimientoestandar:string, cantidad: string };\r\n        var products:producto[] = [];\r\n\r\n        const v:number = validarPasswordDcto();\r\n        if(!v)return;\r\n\r\n        inputsInv.forEach(inputinv =>{\r\n          const v = inputinv as HTMLInputElement;\r\n          products = [...products, {id: v.id, idproducto: v.id, tipoproducto: v.dataset.tipoproducto!, tipoproduccion: v.dataset.tipoproduccion!, rendimientoestandar: v.dataset.rendimientoestandar!, cantidad: v.value}];\r\n        });\r\n\r\n        (async ()=>{\r\n          const datos = new FormData();\r\n          datos.append('id', (document.querySelector('#idorden') as HTMLElement).dataset.idorden!); //id de la factura\r\n          datos.append('inv', JSON.stringify(products));\r\n          datos.append('devolverinv', (document.querySelector('input[name=\"devolverinventario\"]:checked') as HTMLInputElement).value);\r\n          //datos.append('domicilio', 0);\r\n          try {\r\n              const url = \"/admin/api/eliminarOrden\";  //api llamada en cajacontrolador.php\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                miDialogoEliminarOrden.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                btneliminarorden.style.display = \"none\";\r\n                enviarEmail.style.display = \"none\";\r\n                (document.querySelector('#estadoOrden') as HTMLElement).textContent = \"Eliminada\";\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();\r\n      }\r\n\r\n\r\n      function validarPasswordDcto():number{\r\n        const clave = claveEliminarOrden.find(c => c.clave=='clave_para_eliminar_factura');\r\n        if(clave?.valor_final!==null && inputEliminarClave.value !== clave?.valor_final){\r\n          msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n          return 0;\r\n        }\r\n        return 1;\r\n      }\r\n\r\n    }\r\n  \r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.pedidosguardados')){\r\n\r\n    let indiceFila=0, control=0, tablaPedidosGuardados:HTMLElement;\r\n/*\r\n    type cajasapi = {\r\n        id:string,\r\n        idtipoconsecutivo: string,\r\n        nombre: string,\r\n        negocio: string\r\n      };\r\n  \r\n      let cajas:cajasapi[]=[], unacaja:cajasapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allcajas\"; //llamado a la API REST y se trae todos los productos\r\n            const respuesta = await fetch(url); \r\n            cajas = await respuesta.json(); \r\n            console.log(cajas);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaPedidosGuardados = ($('#tablaPedidosGuardados') as any).DataTable(configdatatables);\r\n\r\n    document.querySelector('#tablaPedidosGuardados')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"eliminarPedidoGuardado\")||target.parentElement?.classList.contains(\"eliminarPedidoGuardado\"))eliminarPedidoGuardado(e);\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar cotizacion por completo del sistema  //////////////////////\r\n    function eliminarPedidoGuardado(e:Event){\r\n      let idpedidoguardado = (e.target as HTMLElement).parentElement!.id, info = (tablaPedidosGuardados as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idpedidoguardado = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaPedidosGuardados as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: `Desea eliminar la orden guardado #${idpedidoguardado}?`,\r\n          text: \"La orden/cotizacion guardado sera eliminado definitivamente del sistema.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idpedidoguardado);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarPedidoGuardado\"; // llama controlador cajacontrolador.php\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaPedidosGuardados as any).row(indiceFila).remove().draw(); \r\n                        (tablaPedidosGuardados as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n    \r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCaja') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(function(){\r\n  if(document.querySelector('.empleados')){\r\n    const crearempleado = document.querySelector('#crearempleado') as HTMLElement;\r\n    const dialogoEmpleado:any = document.getElementById(\"miDialogoEmpleado\");\r\n    const dialogoContraseña = document.getElementById(\"miDialogoContraseña\");\r\n    const btnupImage = document.querySelector('#upImage') as HTMLInputElement;\r\n    const btncustomUpImage = document.querySelector('#customUpImage') as HTMLButtonElement;\r\n    const imginputfile = document.querySelector('#imginputfile') as HTMLImageElement;  //img\r\n\r\n    const inputNombre = document.querySelector('#nombreempleado') as HTMLInputElement;\r\n    const inputApellido = document.querySelector('#apellidoempleado') as HTMLInputElement;\r\n    const inputnickname = document.querySelector('#nicknameempleado') as HTMLInputElement;\r\n    //const inputcedula = document.querySelector('#cedulaempleado') as HTMLInputElement;\r\n    const inputpassword = document.querySelector('#passwordempleado') as HTMLInputElement;\r\n    const inputpassword2 = document.querySelector('#passwordempleado2 ') as HTMLInputElement;\r\n    const inputMovil = document.querySelector('#movilempleado ') as HTMLInputElement;\r\n    //const inputEmail = document.querySelector('#emailempleado') as HTMLInputElement;\r\n    //const inputDepartamento = document.querySelector('#departamentoempleado') as HTMLInputElement;\r\n    //const inputCiudad = document.querySelector('#ciudadempleado') as HTMLInputElement;\r\n    //const inputDireccion = document.querySelector('#direccionempleado') as HTMLInputElement;\r\n    const inputPerfil = document.querySelector('#perfilempleado') as HTMLInputElement;\r\n\r\n    let indiceFila=0, control=0, tablaempleados:HTMLElement;\r\n    let empleadosapi: {\r\n      id:string, \r\n      nombre: string,\r\n      apellido: string,\r\n      nickname: string,\r\n      cedula: string,\r\n      movil: string,\r\n      email: string,\r\n      departamento: string,\r\n      ciudad: string,\r\n      direccion: string,\r\n      perfil: string,\r\n      img:string,\r\n      idusuariospermisos:{id:string, usuarioid:string, permisoid:string}[]\r\n      permisos:{id:string, nombre:string}[]\r\n    }[] =[];\r\n      \r\n    let unempleado:{\r\n      id:string,\r\n      nombre: string,\r\n      apellido: string,\r\n      nickname: string,\r\n      cedula: string,\r\n      movil: string,\r\n      email: string,\r\n      departamento: string,\r\n      ciudad: string,\r\n      direccion: string,\r\n      perfil: string, \r\n      img:string,\r\n      idusuariospermisos:{id:string, usuarioid:string, permisoid:string}[]\r\n      permisos:{id:string, nombre:string}[]\r\n    }|undefined;\r\n\r\n    /////////////////  traer todos los empleados con sus skills  ///////////////////\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getAllemployee\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          empleadosapi = await respuesta.json(); \r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n    inputPerfil.addEventListener('change', (e)=>{\r\n      if((e.target as HTMLSelectElement).value == '2'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n      if((e.target as HTMLSelectElement).value == '3'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"block\";\r\n      }\r\n      if((e.target as HTMLSelectElement).value == '4'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"block\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n    });\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaempleados = ($('#tablaempleados') as any).DataTable(configdatatables);\r\n\r\n    //////////////////// ventana modal al crear empleado  //////////////////////\r\n    crearempleado.addEventListener('click', (e)=>{\r\n      control = 0;\r\n      limpiarformdialog();\r\n      \r\n      (document.querySelector('#campopass1') as HTMLElement).style.display = \"\";\r\n      (document.querySelector('#campopass2') as HTMLElement).style.display = \"\";\r\n      (document.querySelector('#passwordempleado') as HTMLInputElement).setAttribute('required', 'true');\r\n      (document.querySelector('#passwordempleado2') as HTMLInputElement).setAttribute('required', 'true');\r\n\r\n      document.querySelector('#modalEmpleado')!.textContent = \"Crear empleado\";\r\n      (document.querySelector('#btnEditarCrearEmpleado') as HTMLInputElement).value = \"Crear\";\r\n      dialogoEmpleado.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n     //////////////////// Cargar imagen como preview  //////////////////////\r\n    btncustomUpImage.addEventListener('click', ()=>btnupImage.click());\r\n    btnupImage.addEventListener('change', function(){\r\n      const file = this.files?.[0];\r\n      if(file){\r\n        const reader = new FileReader();\r\n        reader.onload = function(){\r\n          const resrult:(string | ArrayBuffer | null) = reader.result;\r\n          if(typeof resrult == \"string\")imginputfile.src = resrult;\r\n        } \r\n        reader.readAsDataURL(file);\r\n      }\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaempleados')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarEmpleado\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarEmpleado\"))editarEmpleado(e);\r\n      if((e.target as HTMLElement)?.classList.contains(\"updatePassword\")||(e.target as HTMLElement).parentElement?.classList.contains(\"updatePassword\"))updatePassword(e);\r\n      if(target?.classList.contains(\"eliminarEmpleado\")||target.parentElement?.classList.contains(\"eliminarEmpleado\"))eliminarEmpleado(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar empleado  //////////////////////\r\n    function editarEmpleado(e:Event){\r\n      let idempleado = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idempleado = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n\r\n      (document.querySelector('#campopass1') as HTMLElement).style.display = \"none\";\r\n      (document.querySelector('#campopass2') as HTMLElement).style.display = \"none\";\r\n      (document.querySelector('#passwordempleado') as HTMLInputElement).removeAttribute('required');\r\n      (document.querySelector('#passwordempleado2') as HTMLInputElement).removeAttribute('required');\r\n\r\n      document.querySelector('#modalEmpleado')!.textContent = \"Actualizar Empleado\";\r\n      (document.querySelector('#btnEditarCrearEmpleado') as HTMLInputElement)!.value = \"Actualizar\";\r\n      unempleado = empleadosapi.find(x => x.id==idempleado); //me trae al empleado seleccionado\r\n      imginputfile.src = \"/build/img/\"+unempleado?.img;\r\n      inputNombre.value = unempleado?.nombre??'';\r\n      inputApellido.value = unempleado?.apellido??'';\r\n      inputnickname.value = unempleado?.nickname??'';\r\n      //inputcedula.value = unempleado?.cedula??'';\r\n      inputMovil.value = unempleado?.movil??'';\r\n      //inputEmail.value = unempleado?.email??'';\r\n      //inputDepartamento.value = unempleado?.departamento??'';\r\n      //inputCiudad.value = unempleado?.ciudad??'';\r\n      //inputDireccion.value = unempleado?.direccion??'';\r\n      $('#perfilempleado').val(unempleado?.perfil??'');\r\n      if(unempleado?.perfil == '2'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n      if(unempleado?.perfil == '3'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"block\";\r\n      }\r\n      if(unempleado?.perfil == '4'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"block\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n      printpermisos(unempleado?.permisos??[]);\r\n      indiceFila = (tablaempleados as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      dialogoEmpleado.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function printpermisos(leave:{id:string, nombre:string}[]){\r\n      document.querySelectorAll<HTMLInputElement>('#contentpermisos input[type=\"checkbox\"]').forEach(checkbox=>{checkbox.checked=false}); //limpia los checkbox\r\n      leave.forEach(s =>{\r\n        const inputpermiso = document.querySelector(`input[value=\"${s.id}\"]`) as HTMLInputElement;\r\n        inputpermiso.checked = true;\r\n      });\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar empleado  //////////////////////\r\n    document.querySelector('#formCrearUpdateEmpleado')?.addEventListener('submit', e=>{\r\n      if(control){\r\n        e.preventDefault();\r\n        var imgFile:(string|File), info = (tablaempleados as any).page.info();\r\n        imgFile=unempleado!.img;\r\n        if(!imginputfile.src.includes(unempleado!.img)){ //cambio de imagen\r\n          imgFile = ((e.target as HTMLFormElement).elements.namedItem(\"upImage\") as HTMLInputElement).files?.[0]!; //obtengo el archivo\r\n          if(imgFile){\r\n            if(imgFile.type!==\"image/png\"&&imgFile.type!==\"image/jpeg\"){\r\n              msjAlert('error', 'No es un formato valido para la foto', (document.querySelector('#divmsjalertaempleado1') as HTMLElement));\r\n              return;\r\n            }\r\n            if(imgFile.size>550000){ //si es mayor a 550KB\r\n              msjAlert('error', 'La imagen no debe superar los 500KB', document.querySelector('#divmsjalertaempleado1')!);\r\n              return;\r\n            }\r\n          }\r\n        }\r\n\r\n        var arraypermisos:{id:string, nombre:string}[] = [];\r\n        document.querySelectorAll<HTMLInputElement>('#contentpermisos input[type=\"checkbox\"]').forEach(x=>{\r\n          if(x.checked)arraypermisos = [...arraypermisos, {id:x.value, nombre: x.nextElementSibling?.textContent??'permiso'}];\r\n        });\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unempleado!.id);\r\n          datos.append('img', imgFile); //en el backend no se lee con $_POST, se lee con $_FILES\r\n          datos.append('nombre', inputNombre.value);\r\n          datos.append('apellido', inputApellido.value);\r\n          datos.append('nickname', inputnickname.value);\r\n          //datos.append('cedula', inputcedula.value);\r\n          datos.append('password', inputpassword.value);\r\n          datos.append('password2', inputpassword2.value);\r\n          datos.append('movil', inputMovil.value);\r\n          //datos.append('email', inputEmail.value);\r\n          //datos.append('departamento', inputDepartamento.value);\r\n          //datos.append('ciudad', inputCiudad.value);\r\n          //datos.append('direccion', inputDireccion.value);\r\n          datos.append('perfil', inputPerfil.value);\r\n          datos.append('idpermisos', JSON.stringify(arraypermisos.map(v=>v.id)));\r\n          try {\r\n              const url = \"/admin/api/actualizarEmpleado\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                ///////// cambiar la fila completa, su contenido //////////\r\n                const datosActuales = (tablaempleados as any).row(indiceFila+=info.start).data();\r\n                /*NOMBRE*/datosActuales[1] = inputNombre.value +' '+inputApellido.value;\r\n                /*img*/datosActuales[2] = `<div class=\"text-center\"><img style=\"width: 40px;\" src=\"/build/img/${resultado.rutaimg}\" alt=\"\"></div>`;\r\n                /*USER*/datosActuales[3] = inputnickname.value;\r\n                /*PERFIL*/datosActuales[6] = inputPerfil.value==='1'?'root':inputPerfil.value=='2'?'Superior':inputPerfil.value == '3'?'Admin':'Asesor';\r\n                //actualizar arreglo de permisos\r\n                empleadosapi.forEach(a=>{\r\n                  if(a.id == unempleado?.id){\r\n                    a.permisos = arraypermisos;\r\n                    a.img = resultado.rutaimg;\r\n                  }\r\n                });\r\n                (tablaempleados as any).row(indiceFila).data(datosActuales).draw();\r\n                (tablaempleados as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n              dialogoEmpleado.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n      } //fin if(control)\r\n    });\r\n\r\n\r\n    ////////////////////  Actualizar contraseña del empleado  //////////////////////\r\n    function updatePassword(e:Event){\r\n      let idempleado = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement).tagName === 'I')idempleado = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      unempleado = empleadosapi.find(x => x.id==idempleado);\r\n      (document.querySelector('#nombreEmpleadoPass') as HTMLElement).textContent = unempleado?.nombre+\" \"+(unempleado?.apellido??'');\r\n      (dialogoContraseña as any)?.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    document.querySelector('#formContraseña')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      (async ()=>{\r\n        const datos = new FormData();\r\n        datos.append('id', unempleado!.id);\r\n        datos.append('password', (document.querySelector('#changePassword') as HTMLInputElement).value);\r\n        try {\r\n            const url = \"/admin/api/updatepassword\";\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.exito[0]);\r\n            }\r\n            (dialogoContraseña as any)?.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar el empleado  //////////////////////\r\n    function eliminarEmpleado(e:Event){\r\n      let idempleado = (e.target as HTMLElement).parentElement!.id, info = (tablaempleados as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idempleado = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaempleados as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el empleado?',\r\n          text: \"El empleado sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idempleado);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarEmpleado\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaempleados as any).row(indiceFila).remove().draw(); \r\n                        (tablaempleados as any).page(info.page).draw('page');\r\n                        empleadosapi = empleadosapi.filter(x=>x.id!=idempleado);\r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === dialogoEmpleado || event.target === dialogoContraseña || (event.target as HTMLInputElement).value === 'Cancelar') {\r\n          dialogoEmpleado.close();\r\n          (dialogoContraseña as any)?.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      imginputfile.src = ' ';\r\n      (document.querySelector('#formCrearUpdateEmpleado') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.gestionbancos')){\r\n    const crearBanco = document.querySelector('#crearBanco') as HTMLButtonElement;\r\n    const miDialogoBanco = document.querySelector('#miDialogoBanco') as any;\r\n\r\n    let indiceFila=0, control=0, tablaBancos:HTMLElement;\r\n\r\n    type bancosapi = {\r\n        id:string,\r\n        nombre: string,\r\n        numerocuenta: string,\r\n        saldo: string,\r\n        estado: string,\r\n        created_at: string\r\n      };\r\n  \r\n      let bancos:bancosapi[]=[], unbanco:bancosapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allbancos\"; //llamado a la API REST y se trae todos los bancos\r\n            const respuesta = await fetch(url); \r\n            bancos = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaBancos = ($('#tablaBancos') as any).DataTable(configdatatables);\r\n\r\n    crearBanco.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalBanco')!.textContent = \"Crear banco\";\r\n        (document.querySelector('#btnEditarCrearBanco') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoBanco.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaBancos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarBanco\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarBanco\"))editarBanco(e);\r\n      if(target?.classList.contains(\"eliminarBanco\")||target.parentElement?.classList.contains(\"eliminarBanco\"))eliminarBanco(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar banco  //////////////////////\r\n    function editarBanco(e:Event){\r\n      let idbanco = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idbanco = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalBanco')!.textContent = \"Actualizar banco\";\r\n      (document.querySelector('#btnEditarCrearBanco') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unbanco = bancos.find(x => x.id==idbanco); //me trae a la banco seleccionada\r\n      (document.querySelector('#nombreBanco')as HTMLInputElement).value = unbanco?.nombre!;\r\n      (document.querySelector('#numeroCuenta')as HTMLInputElement).value = unbanco?.numerocuenta!;\r\n      \r\n      indiceFila = (tablaBancos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoBanco.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar banco  //////////////////////\r\n    document.querySelector('#formCrearUpdateBanco')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearBanco\";\r\n      if(control)urlApi = \"actualizarBanco\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaBancos as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unbanco?.id?unbanco?.id:'');\r\n          datos.append('nombre', $('#nombreBanco').val()as string);\r\n          datos.append('numerocuenta', $('#numeroCuenta').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoBanco.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de la banco ///\r\n                  bancos = [...bancos, resultado.banco];\r\n                  (tablaBancos as any).row.add([\r\n                      (tablaBancos as any).rows().count() + 1,\r\n                      resultado.banco.nombre,\r\n                      resultado.banco.numerocuenta,\r\n                      resultado.banco.created_at,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.banco.id}\" data-banco=\"${resultado.banco.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarBanco\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarBanco\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de bancos ///\r\n                  bancos.forEach(a=>{if(a.id == unbanco?.id)a = Object.assign(a, resultado.banco[0]);});\r\n                  const datosActuales = (tablaBancos as any).row(indiceFila+=info.start).data();\r\n                  /*BANCO*/      datosActuales[1] = resultado.banco[0].nombre;\r\n                  /*NUM CUENTA*/ datosActuales[2] = resultado.banco[0].numerocuenta;\r\n                  (tablaBancos as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaBancos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar banco  //////////////////////\r\n    function eliminarBanco(e:Event){\r\n      let idbanco = (e.target as HTMLElement).parentElement!.id, info = (tablaBancos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idbanco = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaBancos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el banco?',\r\n          text: \"El banco sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idbanco);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarBanco\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaBancos as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaBancos as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoBanco || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoBanco.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrarbanco')){  //Cuando se hace el cierre de banco\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateBanco') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.gestioncajas')){\r\n    const crearCaja = document.querySelector('#crearCaja') as HTMLButtonElement;\r\n    const miDialogoCaja = document.querySelector('#miDialogoCaja') as any;\r\n\r\n    let indiceFila=0, control=0, tablaCajas:HTMLElement;\r\n\r\n    type cajasapi = {\r\n        id:string,\r\n        idtipoconsecutivo: string,\r\n        nombre: string,\r\n        negocio: string\r\n      };\r\n  \r\n      let cajas:cajasapi[]=[], unacaja:cajasapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allcajas\"; //llamado a la API REST y se trae todos las cajas\r\n            const respuesta = await fetch(url); \r\n            cajas = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaCajas = ($('#tablaCajas') as any).DataTable(configdatatables);\r\n\r\n    crearCaja.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalCaja')!.textContent = \"Crear caja\";\r\n        (document.querySelector('#btnEditarCrearCaja') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoCaja.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaCajas')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarCaja\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarCaja\"))editarCaja(e);\r\n      if(target?.classList.contains(\"eliminarCaja\")||target.parentElement?.classList.contains(\"eliminarCaja\"))eliminarCaja(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar caja  //////////////////////\r\n    function editarCaja(e:Event){\r\n      let idcaja = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idcaja = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalCaja')!.textContent = \"Actualizar caja\";\r\n      (document.querySelector('#btnEditarCrearCaja') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unacaja = cajas.find(x => x.id==idcaja); //me trae a la caja seleccionada\r\n      (document.querySelector('#nombrecaja')as HTMLInputElement).value = unacaja?.nombre!;\r\n      $('#idtipoconsecutivo').val(unacaja?.idtipoconsecutivo??'');\r\n      $('#negociogestioncaja').val(1);\r\n      \r\n      indiceFila = (tablaCajas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoCaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar caja  //////////////////////\r\n    document.querySelector('#formCrearUpdateCaja')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearCaja\";\r\n      if(control)urlApi = \"actualizarCaja\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaCajas as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unacaja?.id?unacaja?.id:'');\r\n          datos.append('idtipoconsecutivo', $('#idtipoconsecutivo').val()as string);\r\n          datos.append('nombre', $('#nombrecaja').val()as string);\r\n          datos.append('negocio', $('#negociogestioncaja').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoCaja.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de la caja ///\r\n                  cajas = [...cajas, resultado.caja];\r\n                  (tablaCajas as any).row.add([\r\n                      (tablaCajas as any).rows().count() + 1,\r\n                      resultado.caja.nombre,\r\n                      resultado.caja.nombreconsecutivo.nombre,\r\n                      resultado.caja.negocio,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.caja.id}\" data-caja=\"${resultado.caja.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarCaja\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarCaja\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de cajas ///\r\n                  cajas.forEach(a=>{if(a.id == unacaja?.id)a = Object.assign(a, resultado.caja[0]);});\r\n                  const datosActuales = (tablaCajas as any).row(indiceFila+=info.start).data();\r\n                  /*CAJA*/      datosActuales[1] = resultado.caja[0].nombre;\r\n                  /*FACT AUTO*/ datosActuales[2] = $('#idtipoconsecutivo option:selected').text();\r\n                  /*NEGOCIO*/   datosActuales[3] = $('#negociogestioncaja option:selected').text();\r\n                  (tablaCajas as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaCajas as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar caja  //////////////////////\r\n    function eliminarCaja(e:Event){\r\n      let idcaja = (e.target as HTMLElement).parentElement!.id, info = (tablaCajas as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idcaja = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaCajas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar la caja?',\r\n          text: \"La caja sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idcaja);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarCaja\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaCajas as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaCajas as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoCaja || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoCaja.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrarcaja')){  //Cuando se hace el cierre de caja\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCaja') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.gestionfacturadores')){\r\n    const POS = (window as any).POS;\r\n    const crearFacturador = document.querySelector('#crearFacturador') as HTMLButtonElement;\r\n    const miDialogoFacturador = document.querySelector('#miDialogoFacturador') as any;\r\n\r\n    let indiceFila=0, control=0, tablaFacturadores:HTMLElement;\r\n\r\n    type facturadoresapi = {\r\n        id:string,\r\n        id_sucursalid: string,\r\n        idtipofacturador: string,\r\n        idnegocio: string,\r\n        nombre: string\r\n        rangoinicial:string,\r\n        rangofinal: string,\r\n        siguientevalor: string,\r\n        fechainicio: string\r\n        fechafin:string,\r\n        resolucion: string,\r\n        consecutivoremplazo: string,\r\n        prefijo: string,\r\n        mostrarresolucion:string,\r\n        mostrarimpuestodiscriminado: string,\r\n        tokenfacturaelectronica: string,\r\n        electronica: string,\r\n        estado: string\r\n      };\r\n  \r\n      let facturadores:facturadoresapi[]=[], unfacturador:facturadoresapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allfacturadores\"; //llamado a la API REST y se trae todos los consecutivos\r\n            const respuesta = await fetch(url); \r\n            facturadores = await respuesta.json();\r\n            POS.facturadores = facturadores;  //se expone globalmente para procesar en gestiondian.ts\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaFacturadores = ($('#tablaFacturadores') as any).DataTable(configdatatables);\r\n\r\n    crearFacturador.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalFacturador')!.textContent = \"Crear facturador\";\r\n        (document.querySelector('#btnEditarCrearFacturador') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoFacturador.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaFacturadores')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarFacturador\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarFacturador\"))editarFacturador(e);\r\n      if(target?.classList.contains(\"eliminarFacturador\")||target.parentElement?.classList.contains(\"eliminarFacturador\"))eliminarFacturador(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar facturador  //////////////////////\r\n    function editarFacturador(e:Event){\r\n      let idfacturador = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idfacturador = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalFacturador')!.textContent = \"Actualizar facturador\";\r\n      (document.querySelector('#btnEditarCrearFacturador') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unfacturador = facturadores.find(x => x.id==idfacturador); //me trae el facturador seleccionado\r\n      (document.querySelector('#nombrefacturador')as HTMLInputElement).value = unfacturador?.nombre!;\r\n      $('#idtipofacturador').val(unfacturador?.idtipofacturador??'');\r\n      $('#rangoinicial').val(unfacturador?.rangoinicial??'');\r\n      $('#rangofinal').val(unfacturador?.rangofinal??'');\r\n      $('#siguientevalor').val(unfacturador?.siguientevalor??'');\r\n      $('#fechainicio').val(unfacturador?.fechainicio??'');\r\n      $('#fechafin').val(unfacturador?.fechafin??'');\r\n      $('#resolucion').val(unfacturador?.resolucion??'');\r\n      $('#prefijo').val(unfacturador?.prefijo??'');\r\n      $('#negociofacturador').val(1);\r\n      \r\n      indiceFila = (tablaFacturadores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoFacturador.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar facturador  //////////////////////\r\n    document.querySelector('#formCrearUpdateFacturador')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearFacturador\";\r\n      if(control)urlApi = \"actualizarFacturador\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaFacturadores as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unfacturador?.id?unfacturador?.id:'');\r\n          datos.append('idtipofacturador', $('#idtipofacturador').val()as string);\r\n          datos.append('idnegocio', $('#negociofacturador').val()as string);\r\n          datos.append('nombre', $('#nombrefacturador').val()as string);\r\n          datos.append('rangoinicial', $('#rangoinicial').val()as string);\r\n          datos.append('rangofinal', $('#rangofinal').val()as string);\r\n          datos.append('siguientevalor', $('#siguientevalor').val()as string);\r\n          datos.append('fechainicio', $('#fechainicio').val()as string);\r\n          datos.append('fechafin', $('#fechafin').val()as string);\r\n          datos.append('resolucion', $('#resolucion').val()as string);\r\n          //datos.append('consecutivoremplazo', $('#negociofacturador').val()as string);\r\n          datos.append('prefijo', $('#prefijo').val()as string);\r\n          /*datos.append('mostrarresolucion', $('#negociofacturador').val()as string);\r\n          datos.append('mostrarimpuestodiscriminado', $('#nombrefacturador').val()as string);\r\n          datos.append('tokenfacturaelectronica', $('#negociofacturador').val()as string);\r\n          datos.append('electronica', $('#negociofacturador').val()as string);\r\n          datos.append('estado', $('#nombrefacturador').val()as string);*/\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoFacturador.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle del facturador///\r\n                  facturadores = [...facturadores, resultado.facturador];\r\n                  (tablaFacturadores as any).row.add([\r\n                      (tablaFacturadores as any).rows().count() + 1,\r\n                      resultado.facturador.nombre,\r\n                      resultado.facturador.nombretipofacturador.nombre,\r\n                      resultado.facturador.rangoinicial,\r\n                      resultado.facturador.siguientevalor,\r\n                      resultado.facturador.fechafin,\r\n                      resultado.facturador.estado==1?'Activo':'Inactivo',\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.facturador.id}\" data-facturador=\"${resultado.facturador.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarFacturador\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarFacturador\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                  crearConsecutivoGestionCaja(resultado.facturador.id, resultado.facturador.nombre);\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de facturadores ///\r\n                  facturadores.forEach(a=>{if(a.id == unfacturador?.id)a = Object.assign(a, resultado.facturador[0]);});\r\n                  const datosActuales = (tablaFacturadores as any).row(indiceFila+=info.start).data();\r\n                  /*xx*/datosActuales[1] = resultado.facturador[0].nombre;\r\n                  /*x*/ datosActuales[2] = resultado.facturador[0].nombretipofacturador;\r\n                  /*x*/ datosActuales[3] = resultado.facturador[0].rangoinicial;\r\n                        datosActuales[4] = resultado.facturador[0].siguientevalor;\r\n                        datosActuales[5] = resultado.facturador[0].fechafin;\r\n                        datosActuales[6] = resultado.facturador[0].estado==1?'Activo':'Inactivo';\r\n                  (tablaFacturadores as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaFacturadores as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                  actualizarConsecutivoGestionCaja(unfacturador!.id, resultado.facturador[0].nombre);\r\n                }\r\n              }else{\r\n                miDialogoFacturador.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar facturador  //////////////////////\r\n    function eliminarFacturador(e:Event){\r\n      let idfacturador = (e.target as HTMLElement).parentElement!.id, info = (tablaFacturadores as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idfacturador = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaFacturadores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el facturador?',\r\n          text: \"El facturador sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idfacturador);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarFacturador\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaFacturadores as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaFacturadores as any).page(info.page).draw('page');\r\n                        eliminardegestioncaja(idfacturador);\r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function crearConsecutivoGestionCaja(idfacturador:string, nombre:string){\r\n      const selectConsecutivoCaja = document.querySelector('#idtipoconsecutivo') as HTMLSelectElement;\r\n      const option = document.createElement('option');\r\n      option.value = idfacturador;\r\n      option.textContent = nombre;\r\n      selectConsecutivoCaja.appendChild(option);\r\n    }\r\n\r\n    function actualizarConsecutivoGestionCaja(idfacturador:string, nombre:string){\r\n      const selectConsecutivoCaja = document.querySelector('#idtipoconsecutivo') as HTMLSelectElement;\r\n      const opcionconsecutivo = selectConsecutivoCaja.querySelector(`option[value=\"${idfacturador}\"]`) as HTMLOptionElement;\r\n      opcionconsecutivo.textContent = nombre;\r\n    }\r\n\r\n    function eliminardegestioncaja(idfacturador:string){\r\n      const selectConsecutivoCaja = document.querySelector('#idtipoconsecutivo') as HTMLSelectElement;\r\n      const opcionconsecutivo = selectConsecutivoCaja.querySelector(`option[value=\"${idfacturador}\"]`);\r\n      opcionconsecutivo?.remove();\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoFacturador || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoFacturador.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateFacturador') as HTMLFormElement)?.reset();\r\n    }\r\n  }\r\n  \r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.mediosPagos')){\r\n    const crearMedioPago = document.querySelector('#crearMedioPago') as HTMLButtonElement;\r\n    const miDialogoMedioPago = document.querySelector('#miDialogoMedioPago') as any;\r\n\r\n    let indiceFila=0, control=0, tablamediosPagos:HTMLElement;\r\n\r\n    type mediospagoapi = {\r\n        id:string,\r\n        mediopago: string,\r\n        estado: string,\r\n        nick: string\r\n      };\r\n  \r\n      let mediospagos:mediospagoapi[]=[], unmediopago:mediospagoapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allmediospago\"; //llamado a la API REST y se trae todos las medios de pago\r\n            const respuesta = await fetch(url); \r\n            mediospagos = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablamediosPagos = ($('#tablamediosPagos') as any).DataTable(configdatatables);\r\n\r\n    crearMedioPago.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalMedioPago')!.textContent = \"Crear medio de pago\";\r\n        (document.querySelector('#btnEditarCrearMedioPago') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoMedioPago.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablamediosPagos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"statemediopago\"))changeState(e);\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarMedioPago\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarMedioPago\"))editarMedioPago(e);\r\n      if(target?.classList.contains(\"eliminarMedioPago\")||target.parentElement?.classList.contains(\"eliminarMedioPago\"))eliminarMedioPago(e);\r\n    });\r\n\r\n\r\n    ///////////////  Cambiar estado del medio de pago  ////////////////\r\n    function changeState(e:Event){\r\n      const button=(e.target as HTMLButtonElement), info = (tablamediosPagos as any).page.info();\r\n      indiceFila =  (tablamediosPagos as any).row(button.closest('tr')).index();\r\n      (async ()=>{ \r\n        const datos = new FormData();\r\n        datos.append('id', button.id);\r\n        datos.append('estado', button.dataset.state=='0'?'1':'0');\r\n        try {\r\n            const url = \"/admin/api/updateStateMedioPago\";\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();  \r\n            if(resultado.exito !== undefined){\r\n              const s1 = `<button id=\"${button.id}\" data-state=\"${button.dataset.state=='0'?'1':'0'}\" class=\"statemediopago btn-xs ${button.dataset.state=='0'?'btn-lima':'btn-red'}\">${button.dataset.state=='0'?'Activo':'Inactivo'}</button>`;\r\n              (tablamediosPagos as any).cell((tablamediosPagos as any).row(indiceFila+=info.start), 2).data(s1).draw(); //se modifica solo la columna con la fila correspondiente, y destruye la que habai antes\r\n              (tablamediosPagos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n            }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();//cierre de async()\r\n    }\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar medio de pago  //////////////////////\r\n    function editarMedioPago(e:Event){\r\n      let idmediopago = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idmediopago = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalMedioPago')!.textContent = \"Actualizar medio de pago\";\r\n      (document.querySelector('#btnEditarCrearMedioPago') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unmediopago = mediospagos.find(x => x.id==idmediopago); //me trae el emdio de pago seleccionado\r\n      (document.querySelector('#nombreMedioPago')as HTMLInputElement).value = unmediopago?.mediopago!;\r\n      \r\n      indiceFila = (tablamediosPagos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoMedioPago.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar medio de pago  //////////////////////\r\n    document.querySelector('#formCrearUpdateMedioPago')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearMedioPago\";\r\n      if(control)urlApi = \"actualizarMedioPago\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablamediosPagos as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unmediopago?.id?unmediopago?.id:'');\r\n          datos.append('mediopago', $('#nombreMedioPago').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoMedioPago.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de los medios de pagos ///\r\n                  mediospagos = [...mediospagos, resultado.mediopago];\r\n                  (tablamediosPagos as any).row.add([\r\n                      (tablamediosPagos as any).rows().count() + 1,\r\n                      resultado.mediopago.mediopago,\r\n                      resultado.mediopago.estado == '1'?'Activo':'Inactivo',\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.mediopago.id}\" data-mediopago=\"${resultado.mediopago.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarMedioPago\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarMedioPago\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de medios de pagos ///\r\n                  mediospagos.forEach(a=>{if(a.id == unmediopago?.id)a = Object.assign(a, resultado.mediopago[0]);});\r\n                  const datosActuales = (tablamediosPagos as any).row(indiceFila+=info.start).data();\r\n                  /*MEDIO DE PAGO*/ datosActuales[1] = resultado.mediopago.mediopago;\r\n                  /*ESTADO*/        datosActuales[2] = resultado.mediopago.estado == '1'?'Activo':'Inactivo';\r\n                  (tablamediosPagos as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablamediosPagos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar medio de pago  //////////////////////\r\n    function eliminarMedioPago(e:Event){\r\n      let idmediopago = (e.target as HTMLElement).parentElement!.id, info = (tablamediosPagos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idmediopago = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablamediosPagos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el medio de pago?',\r\n          text: \"El medio de pago sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idmediopago);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarMedioPago\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablamediosPagos as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablamediosPagos as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoMedioPago || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoMedioPago.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrarcaja')){  //Cuando se hace el cierre de caja\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCaja') as HTMLFormElement)?.reset();\r\n    }\r\n  }\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.tarifas')){\r\n    const crearTarifa = document.querySelector('#crearTarifa') as HTMLButtonElement;\r\n    const miDialogoTarifa = document.querySelector('#miDialogoTarifa') as any;\r\n\r\n    let indiceFila=0, control=0, tablaTarifas:HTMLElement;\r\n\r\n    type tarifasapi = {\r\n        id:string,\r\n        nombre: string,\r\n        valor: string,\r\n      };\r\n  \r\n      let tarifas:tarifasapi[]=[], unatarifa:tarifasapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/alltarifas\"; //llamado a la API REST y se trae todos las tarifas\r\n            const respuesta = await fetch(url); \r\n            tarifas = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaTarifas = ($('#tablaTarifas') as any).DataTable(configdatatables);\r\n\r\n    crearTarifa.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalTarifa')!.textContent = \"Crear tarifa\";\r\n        (document.querySelector('#btnEditarCrearTarifa') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoTarifa.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaTarifas')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarTarifa\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarTarifa\"))editarTarifa(e);\r\n      if(target?.classList.contains(\"eliminarTarifa\")||target.parentElement?.classList.contains(\"eliminarTarifa\"))eliminarTarifa(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar tarifa  //////////////////////\r\n    function editarTarifa(e:Event){\r\n      let idtarifa = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idtarifa = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalTarifa')!.textContent = \"Actualizar tarifa\";\r\n      (document.querySelector('#btnEditarCrearTarifa') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unatarifa = tarifas.find(x => x.id==idtarifa); //me trae a la tarifa seleccionada\r\n      (document.querySelector('#nombreTarifa')as HTMLInputElement).value = unatarifa?.nombre!;\r\n      (document.querySelector('#valorTarifa')as HTMLInputElement).value = unatarifa?.valor!;\r\n      \r\n      indiceFila = (tablaTarifas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoTarifa.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar tarifa  //////////////////////\r\n    document.querySelector('#formCrearUpdateTarifa')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearTarifa\";\r\n      if(control)urlApi = \"actualizarTarifa\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaTarifas as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unatarifa?.id?unatarifa?.id:'');\r\n          datos.append('nombre', $('#nombreTarifa').val()as string);\r\n          datos.append('valor', $('#valorTarifa').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoTarifa.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de la tarifa ///\r\n                  tarifas = [...tarifas, resultado.tarifa];\r\n                  (tablaTarifas as any).row.add([\r\n                      (tablaTarifas as any).rows().count() + 1,\r\n                      resultado.tarifa.nombre,\r\n                      resultado.tarifa.valor,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.tarifa.id}\" data-tarifa=\"${resultado.tarifa.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarTarifa\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarTarifa\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de tarifas ///\r\n                  tarifas.forEach(a=>{if(a.id == unatarifa?.id)a = Object.assign(a, resultado.tarifa[0]);});\r\n                  const datosActuales = (tablaTarifas as any).row(indiceFila+=info.start).data();\r\n                  /*TARIFA*/ datosActuales[1] = resultado.tarifa[0].nombre;\r\n                  /*VALOR*/  datosActuales[2] = '$'+Number(resultado.tarifa[0].valor).toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n                  (tablaTarifas as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaTarifas as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar tarifa  //////////////////////\r\n    function eliminarTarifa(e:Event){\r\n      let idtarifa = (e.target as HTMLElement).parentElement!.id, info = (tablaTarifas as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idtarifa = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaTarifas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar la tarifa?',\r\n          text: \"La tarifa sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idtarifa);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarTarifa\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaTarifas as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaTarifas as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoTarifa || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoTarifa.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrartarifa')){  //Cuando se hace el cierre de tarifa\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateTarifa') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.editartrasladoinv')){\r\n        // EDITAR LOS PRODUCTOS A TRASLADOR A OTRA SEDE\r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const btnUpdateTrasladoInv = document.querySelector('#btnUpdateTrasladoInv') as HTMLButtonElement;\r\n        let carrito:{id: string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, iditem:string, nombreitem:string, tipo:string, unidadmedida:string, cantidad: number, factor: number}[]=[];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json(); \r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n        \r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n        if(id!=null && /^\\d+$/.test(id) && Number(id) >= 1){\r\n            (async ()=>{\r\n                try {\r\n                    const url = \"/admin/api/idOrdenTrasladoSolicitudInv?id=\"+id; //llamado a la API REST y trae el detalle de la orden trasladar/solicitud desde trasladarinvcontrolador.php\r\n                    const respuesta = await fetch(url); \r\n                    const resultado = await respuesta.json();\r\n                    const detalleOrden = resultado.orden[0];\r\n                    const itemsorden:{id:string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, nombre:string, cantidad:number}[] = detalleOrden.detalletrasladoinv;\r\n                    carrito = itemsorden.map(item =>{\r\n                        const esProducto = item.fkproducto && !item.idsubproducto_id;\r\n                        return {\r\n                            id: item.id,\r\n                            id_trasladoinv: item.id_trasladoinv,\r\n                            fkproducto: item.fkproducto,\r\n                            idsubproducto_id: item.idsubproducto_id,\r\n                            iditem: esProducto?item.fkproducto:item.idsubproducto_id, \r\n                            nombreitem: item.nombre, \r\n                            tipo: esProducto?'0':'1', \r\n                            unidadmedida:'', \r\n                            cantidad: item.cantidad, \r\n                            factor: 1\r\n                        }\r\n                    });\r\n                    //printDetalleOrden(detalleOrden);\r\n                    carrito.forEach(c =>printItemTable(c.iditem, c.tipo, c.unidadmedida, c.cantidad, c.nombreitem));   \r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n        \r\n        \r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });  \r\n        }\r\n\r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos)(document.querySelector('#unidadmedida') as HTMLInputElement).value = datos.unidadmedida;\r\n        });\r\n\r\n        btnAddItem.addEventListener('click', (e)=>{\r\n            let cantidad = parseFloat((document.querySelector('#cantidad') as HTMLInputElement).value);\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            console.log(datos);\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.iditem==datos.id&&x.tipo==datos.tipo);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!; \r\n                    const item:{id:string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, iditem: string, nombreitem: string, tipo: string, unidadmedida: string, cantidad: number, factor: number} = {\r\n                        id: '',\r\n                        id_trasladoinv: id!,\r\n                        fkproducto: itemselected.tipo=='0'?itemselected.id:'NULL', \r\n                        idsubproducto_id: itemselected.tipo=='1'?itemselected.id:'NULL',\r\n                        iditem: itemselected?.id!,\r\n                        nombreitem: itemselected.text,\r\n                        tipo: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n                        unidadmedida: itemselected.unidadmedida,\r\n                        cantidad: cantidad,\r\n                        factor: 1,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(itemselected.id, itemselected.tipo, itemselected.unidadmedida, cantidad, itemselected.text);\r\n                }else{\r\n                    carrito[index].cantidad = cantidad;\r\n                    const tr = document.querySelector(`[data-id=\"${carrito[index].iditem}\"][data-tipo=\"${carrito[index].tipo}\"]`)!;\r\n                    tr.children[1].textContent = carrito[index].cantidad+'';\r\n                }\r\n            }\r\n        });\r\n\r\n        function printItemTable(id:string, tipo:string, unidadmedida:string, cantidad:number, nombre:string){\r\n            let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            /*if(tipo=='1'){   //si es un subproducto\r\n                options = \"\";\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == id); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            if(tipo=='0'){\r\n                options = \"\";\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }*/\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.dataset.tipo = `${tipo}`;\r\n            tr.insertAdjacentHTML('afterbegin', \r\n                `<td class=\"p-4\">${nombre}</td>\r\n                <td class=\"p-4\">${cantidad}</td>\r\n                <td class=\"p-4 flex items-center justify-center gap-2\">\r\n                    <button class=\"flex items-center gap-1 px-3 py-1 text-base text-indigo-600 border border-indigo-200 rounded-lg hover:bg-indigo-50\">\r\n                        👁 Ver\r\n                    </button>\r\n                    <button class=\"w-11 h-11 flex items-center justify-center text-green-600 border border-green-200 rounded-full hover:bg-green-50 text-xl\">✅</button>\r\n                    <button class=\"eliminarItem w-11 h-11 flex items-center justify-center text-rose-600 border border-rose-200 rounded-full hover:bg-rose-50 text-xl\">❌</button>\r\n                </td>`);\r\n            tablaItems?.appendChild(tr);\r\n        }\r\n\r\n\r\n        /*function printDetalleOrden(detalleOrden:{id:string, sucursal_origen:string, sucursal_destino:string, tipo:string, fkusuario:string, nombreusuario:string, estado:string}){\r\n            console.log(detalleOrden);\r\n\r\n        }*/\r\n\r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaItems?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n        \r\n            if((e.target as HTMLElement).classList.contains('eliminarItem')){ //se trae todoscon true menos el que coincida con iditem y tipoitem\r\n                carrito = carrito.filter(x=> {\r\n                    if(x.iditem==iditem){\r\n                        if(x.tipo==tipoitem){\r\n                            return false;\r\n                        }else{\r\n                            return true;\r\n                        }\r\n                    }else{\r\n                        return true;\r\n                    }\r\n                });\r\n                tablaItems?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"]`)?.remove();\r\n            }\r\n            //itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n\r\n        btnUpdateTrasladoInv.addEventListener('click', ()=>{\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Esta seguro de actualizar la orden de transferencia?',\r\n                text: \"Se procesara la orden con todos los productos para la sede destino\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('id_trasladoinv', id!);\r\n                        datos.append('ids', JSON.stringify(carrito.map(x=>x.id)));\r\n                        datos.append('nuevosproductos', JSON.stringify(carrito));\r\n                        try {\r\n                            const url = \"/admin/api/editarOrdenTransferencia\";  //api llamada a trasladosinvcontrolador\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                                setTimeout(() => {\r\n                                    window.location.href = `/admin/almacen/trasladarinventario`;\r\n                                }, 1600);\r\n                                Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()\r\n                }\r\n            });\r\n        });\r\n\r\n    }\r\n})();","(()=>{\r\n\r\n    if(document.querySelector('.nuevotrasladoinv')){\r\n        // PROCESO SOLICITUD DE INVENTARIO A OTRAS SEDES\r\n        const btnAnterior = document.getElementById(\"btnAnteriorTrasladoInv\") as HTMLButtonElement;\r\n        const btnSiguiente = document.getElementById(\"btnSiguienteTrasladoInv\") as HTMLButtonElement;\r\n        const steps = document.querySelectorAll<HTMLDivElement>(\".step-circle\");\r\n        const stepSections = document.querySelectorAll<HTMLElement>(\".step-section\");\r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const resumenSedeDestino = document.querySelector('#resumenSedeDestino') as HTMLParagraphElement;\r\n        const resumenFecha = document.querySelector('#resumenFecha') as HTMLParagraphElement;\r\n        const resumenObservaciones = document.querySelector('#resumenObservaciones') as HTMLParagraphElement;\r\n        let carrito:{iditem:string, idpx:string, idsx:string, tipo: string, nombreitem:string, unidad:string, cantidad: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra: number, valorcompra: number}[]=[];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n        let currentStep = 1;\r\n        const totalSteps = 3;\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json(); \r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n\r\n        //establecer fecha por defecto\r\n        const inputFecha = document.getElementById('fecha') as HTMLInputElement;\r\n            const hoy = new Date();\r\n            const yyyy = hoy.getFullYear();\r\n            const mm = String(hoy.getMonth() + 1).padStart(2, '0'); // Mes con 2 dígitos\r\n            const dd = String(hoy.getDate()).padStart(2, '0');      // Día con 2 dígitos\r\n            inputFecha.value = `${yyyy}-${mm}-${dd}`;\r\n\r\n        function actualizarProgreso() {\r\n            // Actualizar barra de progreso\r\n            steps.forEach((step, index) => {\r\n                const stepNumber = index + 1;\r\n                if (stepNumber < currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-green-500 text-white font-semibold flex items-center justify-center\";\r\n                } else if (stepNumber === currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-indigo-600 text-white font-semibold flex items-center justify-center\";\r\n                } else {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full border-2 border-gray-300 text-gray-400 font-semibold flex items-center justify-center\";\r\n                }\r\n            });\r\n\r\n            // Mostrar solo la sección actual\r\n            stepSections.forEach((section, index) => {\r\n                if (index + 1 === currentStep) {\r\n                section.style.display = \"block\";\r\n                } else {\r\n                section.style.display = \"none\";\r\n                }\r\n            });\r\n\r\n            // Deshabilitar/activar botones si es necesario\r\n            btnAnterior.disabled = currentStep === 1;\r\n            //btnSiguiente.disabled = currentStep === totalSteps;\r\n        }\r\n\r\n        // Inicializar vista\r\n        actualizarProgreso();\r\n\r\n        // Eventos de navegación\r\n        btnSiguiente.addEventListener(\"click\", () => {\r\n            if (currentStep < totalSteps) {\r\n                currentStep++;\r\n                if(currentStep===3 && carrito.length===0){\r\n                    currentStep--;\r\n                    return;\r\n                }\r\n                if(currentStep===3 && carrito.length>0)resumen();\r\n                actualizarProgreso();\r\n            }else{\r\n                generarorden();\r\n            }\r\n            \r\n        });\r\n\r\n        btnAnterior.addEventListener(\"click\", () => {\r\n            if (currentStep > 1) {\r\n                currentStep--;\r\n                actualizarProgreso();\r\n            }\r\n        });\r\n\r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });\r\n           \r\n        }\r\n\r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos)(document.querySelector('#unidadmedida') as HTMLInputElement).value = datos.unidadmedida;\r\n        });\r\n\r\n        btnAddItem.addEventListener('click', (e)=>{\r\n            let cantidad = parseFloat((document.querySelector('#cantidad') as HTMLInputElement).value);\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            console.log(datos);\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.iditem==datos.id&&x.tipo==datos.tipo);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!; //products es el arreglo de todos los productos traido por api\r\n                    const item:{iditem: string, idpx: string, idsx: string, tipo: string, nombreitem: string, unidad: string, cantidad: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra:number, valorcompra: number} = {\r\n                        iditem: itemselected?.id!,\r\n                        idpx: itemselected.tipo=='0'?itemselected.id:'NULL',\r\n                        idsx: itemselected.tipo=='1'?itemselected.id:'NULL',\r\n                        tipo: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n                        nombreitem: itemselected.text,\r\n                        unidad: itemselected.unidadmedida,\r\n                        cantidad: cantidad,\r\n                        factor: 1,\r\n                        impuesto: 0,\r\n                        valorunidad: 0,\r\n                        subtotal: 0,\r\n                        precio_compra: 0,\r\n                        valorcompra: 0,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(datos.id, datos.tipo, datos.unidadmedida, cantidad);\r\n                }else{\r\n                    carrito[index].cantidad = cantidad;\r\n                    const tr = document.querySelector(`[data-id=\"${carrito[index].iditem}\"][data-tipo=\"${carrito[index].tipo}\"]`)!;\r\n                    tr.children[1].textContent = carrito[index].cantidad+'';\r\n                }\r\n            }\r\n        });\r\n\r\n        function printItemTable(id:string, tipo:string, unidadmedida:string, cantidad:number){\r\n            let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            const unItem = filteredData.find(x=>x.id==id&&x.tipo==tipo)!;\r\n            /*if(tipo=='1'){   //si es un subproducto\r\n                options = \"\";\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == id); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            if(tipo=='0'){\r\n                options = \"\";\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }*/\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.dataset.tipo = `${tipo}`;\r\n            tr.insertAdjacentHTML('afterbegin', \r\n                `<td class=\"p-4\">${unItem?.text}</td>\r\n                <td class=\"p-4\">${cantidad}</td>\r\n                <td class=\"p-4 flex items-center justify-center gap-2\">\r\n                    <button class=\"flex items-center gap-1 px-3 py-1 text-base text-indigo-600 border border-indigo-200 rounded-lg hover:bg-indigo-50\">\r\n                        👁 Ver\r\n                    </button>\r\n                    <button class=\"w-11 h-11 flex items-center justify-center text-green-600 border border-green-200 rounded-full hover:bg-green-50 text-xl\">✅</button>\r\n                    <button class=\"eliminarItem w-11 h-11 flex items-center justify-center text-rose-600 border border-rose-200 rounded-full hover:bg-rose-50 text-xl\">❌</button>\r\n                </td>`);\r\n            tablaItems?.appendChild(tr);\r\n        }\r\n\r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaItems?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n\r\n            const itemCarrito = carrito.find(x=>x.iditem==iditem&&x.tipo==tipoitem)!;\r\n            \r\n        \r\n            if((e.target as HTMLElement).classList.contains('eliminarItem')){\r\n                carrito = carrito.filter(x=> {\r\n                    if(x.iditem==iditem){\r\n                        if(x.tipo==tipoitem){\r\n                            return false;\r\n                        }else{\r\n                            return true;\r\n                        }\r\n                    }else{\r\n                        return true;\r\n                    }\r\n                });\r\n                tablaItems?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"]`)?.remove();\r\n                //resumen();\r\n            }\r\n\r\n            //itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n        function resumen(){\r\n            const tablaproductosresumen = document.querySelector('#tablaproductosresumen tbody');\r\n            while(tablaproductosresumen?.firstChild)tablaproductosresumen.removeChild(tablaproductosresumen.firstChild);\r\n            resumenSedeDestino.textContent = (document.querySelector('#sucursaldestino') as HTMLSelectElement).selectedOptions[0].text;\r\n            resumenFecha.textContent = inputFecha.value;\r\n            resumenObservaciones.textContent = (document.querySelector('#observaciones') as HTMLTextAreaElement).value;\r\n\r\n            carrito.forEach(z=>{\r\n                const tr = document.createElement('tr');\r\n                const tdnombre = document.createElement('td');\r\n                tdnombre.textContent = z.nombreitem;\r\n                tr?.appendChild(tdnombre);\r\n                const tdcantidad = document.createElement('td');\r\n                tdcantidad.textContent = z.cantidad+'';\r\n                tr?.appendChild(tdcantidad);\r\n                const tdund = document.createElement('td');\r\n                tdund.textContent = z.unidad;\r\n                tr?.appendChild(tdund);\r\n                tablaproductosresumen?.appendChild(tr);\r\n            });\r\n        }\r\n\r\n        function generarorden(){\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Esta seguro de generar orden de transferencia?',\r\n                text: \"Se procesara la orden con todos los productos en la sede destino\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    const idsucursalorigen = document.querySelector('#sucursalorigen') as HTMLSelectElement;\r\n                    const sucursaldestino = document.querySelector('#sucursaldestino') as HTMLSelectElement;\r\n                    (async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('idsucursalorigen', idsucursalorigen.value);\r\n                        datos.append('idsucursaldestino', sucursaldestino.value);\r\n                        datos.append('productos', JSON.stringify(carrito));\r\n                        try {\r\n                            const url = \"/admin/api/apinuevotrasladoinv\";  //api llamada a trasladosinvcontrolador\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                                setTimeout(() => {\r\n                                    window.location.href = `/admin/almacen/trasladarinventario`;\r\n                                }, 1100);\r\n                                Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()\r\n                }\r\n            });\r\n        }\r\n\r\n    }\r\n})();","(()=>{\r\n\r\n    if(document.querySelector('.solicitarinvnetario')){\r\n        // PROCESO SOLICITUD DE INVENTARIO A OTRAS SEDES\r\n        const btnAnterior = document.getElementById(\"btnAnteriorSolicitudInv\") as HTMLButtonElement;\r\n        const btnSiguiente = document.getElementById(\"btnSiguienteSolicitudInv\") as HTMLButtonElement;\r\n        const steps = document.querySelectorAll<HTMLDivElement>(\".step-circle\");\r\n        const stepSections = document.querySelectorAll<HTMLElement>(\".step-section\");\r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const resumenSedeDestino = document.querySelector('#resumenSedeDestino') as HTMLParagraphElement;\r\n        const resumenFecha = document.querySelector('#resumenFecha') as HTMLParagraphElement;\r\n        const resumenObservaciones = document.querySelector('#resumenObservaciones') as HTMLParagraphElement;\r\n        let carrito:{iditem:string, idpx:string, idsx:string, tipo: string, nombreitem:string, unidad:string, cantidad: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra: number, valorcompra: number}[]=[];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n        let currentStep = 1;\r\n        const totalSteps = 3;\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json(); \r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n\r\n        //establecer fecha por defecto\r\n        const inputFecha = document.getElementById('fecha') as HTMLInputElement;\r\n            const hoy = new Date();\r\n            const yyyy = hoy.getFullYear();\r\n            const mm = String(hoy.getMonth() + 1).padStart(2, '0'); // Mes con 2 dígitos\r\n            const dd = String(hoy.getDate()).padStart(2, '0');      // Día con 2 dígitos\r\n            inputFecha.value = `${yyyy}-${mm}-${dd}`;\r\n\r\n        function actualizarProgreso() {\r\n            // Actualizar barra de progreso\r\n            steps.forEach((step, index) => {\r\n                const stepNumber = index + 1;\r\n                if (stepNumber < currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-green-500 text-white font-semibold flex items-center justify-center\";\r\n                } else if (stepNumber === currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-indigo-600 text-white font-semibold flex items-center justify-center\";\r\n                } else {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full border-2 border-gray-300 text-gray-400 font-semibold flex items-center justify-center\";\r\n                }\r\n            });\r\n\r\n            // Mostrar solo la sección actual\r\n            stepSections.forEach((section, index) => {\r\n                if (index + 1 === currentStep) {\r\n                section.style.display = \"block\";\r\n                } else {\r\n                section.style.display = \"none\";\r\n                }\r\n            });\r\n\r\n            // Deshabilitar/activar botones si es necesario\r\n            btnAnterior.disabled = currentStep === 1;\r\n            //btnSiguiente.disabled = currentStep === totalSteps;\r\n        }\r\n\r\n        // Inicializar vista\r\n        actualizarProgreso();\r\n\r\n        // Eventos de navegación\r\n        btnSiguiente.addEventListener(\"click\", () => {\r\n            if (currentStep < totalSteps) {\r\n                currentStep++;\r\n                if(currentStep===3 && carrito.length===0){\r\n                    currentStep--;\r\n                    return;\r\n                }\r\n                if(currentStep===3 && carrito.length>0)resumen();\r\n                actualizarProgreso();\r\n            }else{\r\n                generarorden();\r\n            }\r\n            \r\n        });\r\n\r\n        btnAnterior.addEventListener(\"click\", () => {\r\n            if (currentStep > 1) {\r\n                currentStep--;\r\n                actualizarProgreso();\r\n            }\r\n        });\r\n\r\n\r\n        